export const SPOTS = [
  {name:"b. Patisserie",tier:"A",lat:21.2794,lng:-157.8307,category:"bakery",subcategory:"french-bakery",tagline:"San Francisco's award-winning French bakery lands in Honolulu — the kouign-amann and cruffins are worth every calorie.",area:"Waikiki (International Market Place)",price:"$$",mustOrder:["kouign-amann — the signature, caramelized butter pastry","cruffin — croissant-muffin hybrid with seasonal fillings","almond croissant — twice-baked perfection"],parking:"International Market Place validated parking on Kuhio Ave side",talkStory:"Belinda Leong's James Beard-nominated bakery expanded from San Francisco to Honolulu, located inside Kona Coffee Purveyors at International Market Place. The kouign-amann is the star — a Breton pastry of laminated dough and caramelized sugar that's become a dessert icon. The cruffins (croissant-muffin hybrids) rotate flavors and sell out fast. Everything is beautiful and precisely made. Prices match the quality — this is premium pastry, not a neighborhood donut shop. Open daily.",cashOnly:false,kamaaina:null},
  {name:"Champion Malasadas",tier:"A",lat:21.3937,lng:-157.744,category:"bakery",subcategory:"malasada-shop",tagline:"Kailua's neighborhood malasada spot — lighter and less greasy than the famous ones, with perfect sugar coating.",area:"Kailua",price:"$",mustOrder:["plain malasada","haupia filled","custard filled"],parking:"Free lot at shopping center",talkStory:"While Leonard's gets all the fame, Windward side locals swear by Champion Malasadas in Kailua. The malasadas here are lighter and less greasy, with a perfect sugar coating. The haupia-filled and custard-filled versions are excellent. Located in a small shopping center, it's a true neighborhood spot where you'll see locals grabbing a box on the way home. Freshest in the morning.",cashOnly:false,kamaaina:null},
  {name:"Dee Lite Bakery",tier:"A",lat:21.3335,lng:-157.8733,category:"bakery",subcategory:"local-bakery",tagline:"A Kalihi hole-in-the-wall turning out some of Honolulu's best pies, pastries, and cakes — the coconut cake is a local legend.",area:"Kalihi",price:"$",mustOrder:["coconut cake — the signature, towering and moist","apple pie — classic and flaky","fruit tart — seasonal and beautiful"],parking:"Small strip mall lot on Dillingham Blvd",talkStory:"A Kalihi bakery that's been quietly making some of the best cakes and pies in Honolulu for years. The coconut cake is legendary — layers of moist cake covered in fresh coconut. Locals order whole cakes for birthdays and holidays. It's not pretty from the outside and you'd drive right past it, but inside the display cases are filled with beautifully made pastries, pies, and cakes at prices that haven't caught up to Honolulu's rising costs. A true neighborhood gem.",cashOnly:false,kamaaina:null},
  {name:"Fendu Boulangerie",tier:"A",lat:21.2832,lng:-157.8148,category:"bakery",subcategory:"french-bakery",tagline:"Kaimuki's French-inspired bakery — croissants, kouign-amann, and naturally leavened breads that rival mainland artisan bakeries.",area:"Kaimuki",price:"$",mustOrder:["kouign-amann — buttery, caramelized, flaky","croissant — perfectly laminated","seasonal fruit danish — whatever's fresh"],parking:"Street parking on Waialae Ave",talkStory:"A proper French-inspired artisan bakery in Kaimuki, run by bakers who care deeply about technique. The kouign-amann is as good as what you'd find in San Francisco or New York — shattering layers of caramelized butter pastry. The croissants are textbook. Everything is made with natural levain and high-quality flour. Arrives early — popular items sell out by mid-morning. A welcome addition to Oahu's bakery scene, which was long dominated by local-style bakeries.",cashOnly:false,kamaaina:null},
  {name:"Kamehameha Bakery",tier:"A",lat:21.3323,lng:-157.8723,category:"bakery",subcategory:"local-bakery",tagline:"Kalihi's legendary bakery — the poi glazed donuts sell out before dawn and the butter rolls have been a local staple for decades.",area:"Kalihi",price:"$",mustOrder:["poi glazed donut — the icon, purple and perfect","butter rolls — soft, sweet, addictive","apple turnover — old-school flaky goodness"],parking:"Small lot on King St — arrive very early",talkStory:"Opens at midnight and the poi glazed donuts sell out by 5 AM — that should tell you everything. Kamehameha Bakery has been in Kalihi for decades, turning out poi donuts, butter rolls, and pastries that locals set alarms for. The poi donut is uniquely Hawaiian — made with taro, giving it a purple hue and a slightly chewy, earthy sweetness. If you're serious about experiencing local food culture, waking up at 4 AM for these donuts is a rite of passage.",cashOnly:true,kamaaina:null},
  {name:"Lee's Bakery",tier:"A",lat:21.3122,lng:-157.8649,category:"bakery",subcategory:"bakery",tagline:"Chinatown's Vietnamese bakery with the best banh mi on the island and fresh-baked French bread daily.",area:"Chinatown",price:"$",mustOrder:["Banh mi — classic Vietnamese sandwich on crispy French bread with pate and pickled veg","Pork hash — steamed dim sum-style dumpling, a local favorite","Coconut pandan cake — soft, fragrant, and not too sweet"],parking:"Street metered parking on River St. Chinatown garage nearby. Come early — they sell out.",talkStory:"A Chinatown institution run by the Lee family, this Vietnamese bakery has been anchoring its corner of River Street for decades. The banh mi is under $5 — crispy French bread baked fresh daily (you can smell it from the street), layered with pate, cold cuts, pickled daikon and carrot, jalapeno, and cilantro. The pork hash (steamed dim sum-style dumpling) is a sleeper hit locals grab by the dozen. Get there before noon because the bread and popular items sell out. Cash preferred, takeout counter only — eat on a Chinatown bench.",cashOnly:true,kamaaina:null},
  {name:"Leonard's Bakery",tier:"S",lat:21.2854,lng:-157.8185,category:"bakery",subcategory:"hawaiian",tagline:"Malasada institution since 1952 — get the custard-filled haupia and eat them in the parking lot.",area:"Kapahulu",price:"$",mustOrder:["haupia (coconut) malasada puff (the insider's pick over custard)","original plain"],parking:"Dedicated parking lot (~15–20 spots)",talkStory:"Founded in 1952 by Leonard Rego Jr., a second-generation Portuguese-Hawaiian whose family traced back to Madeira and the Azores sugar plantation immigrants. Malasadas were traditionally made on Shrove Tuesday (Fat Tuesday) to use up sugar and butter before Lent — Leonard turned the tradition into a year-round institution. The original plain malasada is perfect, but the haupia (coconut) puff is the insider pick. Bringing a box of Leonard's to a party, office, or someone's house is a power move in Honolulu — never refrigerate them.",cashOnly:false,kamaaina:null},
  {name:"Leonard's Malasada Mobile",tier:"B",lat:21.3132,lng:-157.8636,category:"bakery",subcategory:"bakery",tagline:"Can't make it to Kapahulu? The Malasada Mobile brings the magic to you — same recipe, same dangerous habit-forming quality.",area:"Roaming / Metro Honolulu",price:"$",mustOrder:["original malasadas","custard-filled malasadas"],parking:"Varies by location — usually parks near shopping centers or event venues with adjacent parking",talkStory:"An extension of the Leonard's Bakery legacy (est. 1952), the Malasada Mobile is a food truck that brings the same Portuguese doughnuts to events, festivals, and neighborhoods across Oahu. Same family recipes as the Kapahulu mothership — rolled in sugar, fried to order, impossibly light inside. The truck's schedule rotates, so check their Instagram @leonardsbakery for locations. Pro tip: they're best eaten within five minutes of frying while the outside is still crackling. Cash only at the truck.",cashOnly:true,kamaaina:null},
  {name:"Liliha Bakery",tier:"S",lat:21.3247,lng:-157.8519,category:"bakery",subcategory:"hawaiian",tagline:"Coco puffs since 1950 — the green chiffon cake and butter rolls are the real insider order.",area:"Liliha",price:"$",mustOrder:["coco puffs (non-negotiable)","butter rolls ($1)"],parking:"Dedicated lot at the original Kuakini St location; Nimitz Hwy location has larger lot",talkStory:"Founded in 1950 by Takeo and Sumie Takakuwa, a Japanese-American couple who built a neighborhood bakery that became a Honolulu institution. The Coco Puff — choux pastry filled with chocolate pudding and topped with Chantilly frosting — is arguably Hawaii's most iconic pastry. Locals just say 'I brought puffs' and everyone on Oahu knows exactly what that means. A box is the standard omiyage (gift) when visiting someone's home. Go before 7am weekdays for fresh batches and zero line — the butter rolls for a dollar are the quiet insider pick.",cashOnly:false,kamaaina:null},
  {name:"Nisshodo Candy Store",tier:"S",lat:21.326,lng:-157.865,category:"bakery",subcategory:"mochi-shop",tagline:"Handmade Japanese mochi and manju since the 1920s — hidden in an industrial warehouse, sold out by noon.",area:"Kalihi",price:"$",mustOrder:["chichi dango","mochi","manju"],parking:"Free lot on Dillingham Blvd",talkStory:"Hidden in an industrial warehouse on Dillingham Boulevard, Nisshodo has been making traditional Japanese mochi and manju by hand since the 1920s. The chichi dango (soft, chewy rice flour confection dusted in potato starch) is the signature — locals buy it by the box for family gatherings. Everything is made fresh daily in small batches. Arrive between 7-9am for the freshest selection; popular items sell out after noon. Closed Sundays.",cashOnly:true,kamaaina:null},
  {name:"Pipeline Bakeshop & Creamery",tier:"A",lat:21.28,lng:-157.781,category:"bakery",subcategory:"malasada-shop",tagline:"Kaimuki's cult-favorite bakery — the 'Malamode' (malasada + ice cream) and Cake Bombs are modern Hawaii classics.",area:"Kaimuki",price:"$",mustOrder:["Malamode (ube or haupia)","Cake Bombs","fresh malasadas"],parking:"Street parking on Waialae Ave",talkStory:"A Kaimuki bakery with a cult following for its freshly made malasadas and the signature Malamode — a malasada split open and filled with house-made ice cream in flavors like ube, haupia, and Kona coffee. The Cake Bombs (miniature layered cakes) are another local obsession. Arrive early because popular items sell out by midday. This is the modern evolution of Hawaii's malasada tradition.",cashOnly:false,kamaaina:null},
  {name:"Purvé Donut Stop",tier:"A",lat:21.2832,lng:-157.8167,category:"bakery",subcategory:"bakery",tagline:"Small-batch Hawaiian-flavored donuts that sell out by mid-morning — ube, lilikoi, haupia, and rotating seasonal specials.",area:"Kaimuki",price:"$",mustOrder:["ube donut — purple yam glaze, iconic","lilikoi donut — tart and sweet passionfruit","haupia donut — coconut cream filling"],parking:"Street parking on Waialae Ave; Kahala Mall parking nearby",talkStory:"Tiny Kaimuki donut shop on Waialae Ave with a 4.9 Google rating — one of the highest-rated food spots on Oahu. Everything is small-batch and made fresh daily with Hawaiian flavors. They sell out early, especially weekends — arrive by 7am to get the full selection. Leonard's has malasadas covered; Purvé is the donut move. Opens at 6am.",cashOnly:false,kamaaina:null},
  {name:"Royal Kitchen",tier:"A",lat:21.312,lng:-157.862,category:"bakery",subcategory:"chinese-bakery",tagline:"Chinatown's legendary baked manapua — the char siu pork buns have been a local staple since 1975.",area:"Chinatown / Downtown",price:"$",mustOrder:["baked char siu manapua — the signature, golden and sweet","pepeiao — a local-style sweet bread ear pastry","curry chicken manapua — savory alternative"],parking:"Chinatown Cultural Plaza parking; metered street parking",talkStory:"Inside the Chinatown Cultural Plaza since 1975, Royal Kitchen is synonymous with baked manapua in Honolulu. Their signature char siu bao has a distinctly Hawaiian twist — baked (not steamed like dim sum versions) with a sweet, golden crust and filled with diced char siu pork. Locals buy them by the dozen. The pepeiao is another old-school local treat you won't find on the mainland. Cash only, and they sell out of popular items early.",cashOnly:true,kamaaina:null},
  {name:"Ted's Bakery",tier:"A",lat:21.6485,lng:-158.0595,category:"bakery",subcategory:"bakery",tagline:"North Shore legend famous for haupia chocolate cream pie — the plate lunches fuel surfers year-round.",area:"North Shore (Sunset Beach)",price:"$",mustOrder:["Haupia chocolate cream pie — the iconic pie, chocolate and coconut pudding layers","Garlic shrimp plate — North Shore style, served with rice","Kalua pork plate lunch — smoky, tender, with mac salad and rice"],parking:"Small parking lot right in front on Kamehameha Hwy. Usually can find a spot except peak surf season weekends.",talkStory:"Ted Nakamura opened this North Shore bakery in 1987 near Sunset Beach, and his haupia chocolate cream pie became so iconic they now ship it to the mainland. Every surfer, every local, every Pipeline spectator ends up here. The plate lunches — garlic shrimp, kalua pork — are huge and cheap, perfect fuel after a dawn patrol session. Get the pie to go for the beach. They open early so it doubles as a solid breakfast stop before hitting the waves.",cashOnly:false,kamaaina:null},
  {name:"Via Gelato",tier:"B",lat:21.2725,lng:-157.809,category:"bakery",subcategory:"gelato",tagline:"Hawaii's best gelato — Italian technique with local flavors like haupia, ube, and lilikoi in a Kapahulu neighborhood shop.",area:"Kapahulu / Diamond Head",price:"$",mustOrder:["haupia gelato","ube gelato","lilikoi sorbetto"],parking:"Street parking on Kapahulu Ave",talkStory:"This small Kapahulu gelato shop uses authentic Italian technique with local Hawaiian ingredients to create some of the best frozen treats on the island. The haupia (coconut pudding) and ube flavors are incredible, and the lilikoi sorbetto is refreshingly tart. Everything is made in-house daily. Locals bring their kids after dinner at nearby restaurants. The flavor selection rotates, so there's always something new to try.",cashOnly:false,kamaaina:null},
  {name:"Ala Moana Beach Park",tier:"A",lat:21.2886,lng:-157.8453,category:"beach",subcategory:"kid-friendly",tagline:"The locals' beach in the heart of Honolulu — Magic Island Lagoon is toddler paradise.",area:"Honolulu",price:"Free",parking:"Large free parking lot (fills weekends by 10am)",hours:"Open daily, 4:00 AM – 10:00 PM",bestTime:"Weekday mornings for space; sunset at Magic Island for golden light",kidFriendly:true,talkStory:"Ala Moana means 'path to the sea' in Hawaiian. Magic Island is actually a man-made peninsula built in the 1960s from coral fill — the lagoon on its east side is barely knee-deep, making it the best toddler swimming spot in Honolulu. Locals come at dawn to fish off the channel wall, and at dusk the peninsula tip has a front-row seat to Bowls, one of Oahu's heaviest reef breaks. Stake out a shaded pavilion before 8 AM on weekends or you're sitting in the sun.",kamaaina:null},
  {name:"Bellows Beach",tier:"A",lat:21.3566,lng:-157.7096,category:"beach",subcategory:"hidden",tagline:"On a military base, open weekends only — the trade-off is some of the most untouched white sand on the island.",area:"Waimanalo",price:"Free",parking:"Free lot inside the base gate",hours:"Fri noon – Sun midnight only",bestTime:"Saturday morning for the full day; arrive by 9am for best spot",kidFriendly:true,talkStory:"Bellows sits on an active military base that was one of the first sites hit during the 1941 Pearl Harbor attack — a Japanese midget submarine washed ashore here and you can see a marker for it. The weekend-only access keeps it pristine, and the ironwood tree canopy behind the sand gives rare natural shade. Locals camp here with permits and bodyboard the gentle shore break; it is one of Oahu's safest beginner wave spots.",kamaaina:null},
  {name:"Diamond Head Beach",tier:"B",lat:21.2555,lng:-157.8055,category:"beach",subcategory:"bodyboard",tagline:"A hidden stretch below the lighthouse cliffs that locals use for bodyboarding, tidepooling, and escaping the Waikiki scene.",area:"East Honolulu",price:"Free",parking:"Street parking along Diamond Head Rd near the lighthouse; walk down the cliffside trail",hours:"Open daily, sunrise to sunset",bestTime:"South swell season (summer) for surf; morning for tidepools",kidFriendly:false,talkStory:"Hawaiians called Diamond Head 'Leahi' (brow of the tuna) for its profile. The steep cliffside scramble down keeps tourists away, making this a locals-only bodyboarding spot during south swells. Tide pools along the rocky shelf teem with sea urchins and small eels at low tide. The lighthouse above dates to 1899 and the surf break 'Lighthouse' just offshore is a serious wave that most visitors never see.",kamaaina:null},
  {name:"Ehukai Beach (Banzai Pipeline)",tier:"A",lat:21.6653,lng:-158.0473,category:"beach",subcategory:"surfing",tagline:"Pipeline is the most famous wave on Earth — watching from the sand puts you closer to the action than any surf comp broadcast.",area:"North Shore",price:"Free",parking:"Tiny lot at Ehukai Beach Park or street parking on Ke Nui Rd; come early in winter",hours:"Open daily, sunrise to sunset",bestTime:"Dec–Feb for massive Pipeline surf; summer is calm enough for swimming",kidFriendly:false,talkStory:"Ehukai means 'sea spray' in Hawaiian — fitting for the most famous wave on Earth. Pipeline was first surfed in 1961 by Phil Edwards over a reef just six feet deep; it has claimed multiple lives since. During the Pipe Masters each December, the sand literally vibrates from the impact of 15-foot barrels detonating yards from shore. In summer the same deadly reef disappears under flat turquoise water safe for swimming — a total Jekyll-and-Hyde beach.",kamaaina:null},
  {name:"Electric Beach (Kahe Point)",tier:"B",lat:21.3547,lng:-158.1311,category:"beach",subcategory:"snorkeling",tagline:"Warm water from the power plant outflow attracts spinner dolphins, sea turtles, and tropical fish in ridiculous abundance.",area:"West Side",price:"Free",parking:"Small gravel lot right off Farrington Hwy; comes and goes quickly",hours:"Open daily, sunrise to sunset",bestTime:"Early morning for dolphins and calm water; weekdays to avoid crowds",kidFriendly:false,talkStory:"The Hawaiian name for this area is Kahe, meaning 'to flow.' The adjacent power plant's warm outflow raises water temps several degrees, attracting an unusual concentration of spinner dolphins, green sea turtles, and reef fish to one small area. Snorkel left toward the outflow pipe for the best action, but respect the current — it has pulled inexperienced swimmers out. Locals come at dawn before the wind chops up visibility; this is the only spot on Oahu where you can reliably swim near wild dolphins from shore.",kamaaina:null},
  {name:"Ewa Beach",tier:"C",lat:21.3132,lng:-158.0076,category:"beach",subcategory:"kid-friendly",tagline:"A mellow neighborhood beach where local families set up camp all weekend — no tourists, no fuss.",area:"Ewa",price:"Free",parking:"Street parking in the Ewa Beach neighborhood; free but limited",hours:"Open daily, sunrise to sunset",bestTime:"Morning for calm water; weekdays for peace and quiet",kidFriendly:true,talkStory:"Ewa means 'crooked' or 'astray' in Hawaiian, referring to a surveying error in ancient land division. The actual beach park here is One'ula ('red sand'), named for the rusty coral-and-lava shoreline. This is a generational family beach — you will see the same canopies in the same spots every weekend. The water is shallow, warm, and calm enough for babies, but the real draw is the unfiltered local weekend vibe you will not find at any resort beach.",kamaaina:null},
  {name:"Fort DeRussy Beach Park",tier:"B",lat:21.2822,lng:-157.8365,category:"beach",subcategory:"swimming",tagline:"Waikiki's widest, least-crowded beach — BBQ grills, calm water, and actual space to put your towel down.",area:"Waikiki",price:"Free",parking:"Paid lot off Kalia Rd ($4/hr); street parking on Saratoga Rd if you're lucky",hours:"5am–10pm daily",bestTime:"Weekday mornings for a near-private beach experience; weekends for BBQ vibes",kidFriendly:true,talkStory:"Fort DeRussy was built in 1911 as a coastal defense battery — the concrete bunker that now houses the free U.S. Army Museum once held massive disappearing guns aimed seaward. At 71 acres it is the largest open green space in Waikiki, yet most tourists walk right past. The beach here is wider and less packed than the main Waikiki strip, with the same calm water. BBQ grills and picnic tables make it the only spot in Waikiki where you can actually grill — a move locals have known about for decades.",kamaaina:null},
  {name:"Haleiwa Beach Park",tier:"B",lat:21.5963,lng:-158.1052,category:"beach",subcategory:"kid-friendly",tagline:"A laid-back local park where families picnic, keiki play in calm water, and the North Shore vibe is at its most relaxed.",area:"North Shore",price:"Free",parking:"Large free lot right at the park — rarely fills up",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Year-round; calmer in summer but the protected harbor side stays mellow even in winter",kidFriendly:true,talkStory:"Haleiwa means 'house of the frigate bird' in Hawaiian — the iwa bird was considered a messenger of the gods. The beach sits near the mouth of the Anahulu River, where you can spot sea turtles from the historic Rainbow Bridge. The harbor side stays protected even when winter surf pounds the rest of the North Shore, which is why local families choose this over the famous breaks up the road. Walk to town for Matsumoto's shave ice, but locals know the line is shorter at Aoki's.",kamaaina:null},
  {name:"Hanauma Bay",tier:"S",lat:21.269,lng:-157.6937,category:"beach",subcategory:"snorkeling",tagline:"A protected marine sanctuary inside a volcanic crater — the snorkeling is like swimming in an aquarium.",area:"East Honolulu",price:"$25 non-resident, $5 kama'aina; closed Mondays and Tuesdays",parking:"$3 parking; lot fills by 9 AM, arrive early or take the shuttle",hours:"Wed–Sun, 6:45 AM – 4:00 PM (gates close at 1:30 PM for last entry)",bestTime:"Book online reservation immediately when slots open (2 days in advance); Wed or Thu for fewest crowds",kidFriendly:true,talkStory:"Hanauma means 'curved bay' in Hawaiian — it formed inside a volcanic crater that eroded on one side, letting the ocean flood in thousands of years ago. Elvis Presley filmed scenes from Blue Hawaii here in 1961, cementing its fame. The mandatory conservation video before entry is no gimmick; the bay nearly died from overuse in the 1990s before strict limits brought the reef back. Go before 7 AM on a Wednesday for the emptiest experience, bring your own gear, and stay in the inner reef where 400+ fish species are so tame they brush against you.",kamaaina:"$5 entry for Hawaii residents with valid ID (no reservation needed for residents)"},
  {name:"Kahana Bay",tier:"B",lat:21.5493,lng:-157.8782,category:"beach",subcategory:"hidden",tagline:"A quiet crescent of sand tucked into a lush valley — the kind of spot most tourists drive right past.",area:"Windward",price:"Free",parking:"Small lot off Kamehameha Hwy with additional roadside parking",hours:"Open daily, 7:00 AM – 6:45 PM",bestTime:"Weekday mornings for near-total solitude; spring and summer for calmer water",kidFriendly:true,talkStory:"Kahana means 'cutting' or 'turning point' in Hawaiian, and this bay marks the transition between the windward coast's developed towns and the wild North Shore. The valley behind the beach was a thriving ahupua'a (land division) for centuries, with lo'i kalo (taro fields) fed by Kahana Stream. Locals still fish the shallows with throw nets in the evening the same way their kupuna did. The bay connects to the Kahana Valley trail, one of Oahu's few hikes through a living Hawaiian cultural landscape.",kamaaina:null},
  {name:"Kailua Beach Park",tier:"S",lat:21.3976,lng:-157.7271,category:"beach",subcategory:"swimming",tagline:"The beach Honolulu locals make the drive for — powder-white sand, gentle clear water, views of the Mokes.",area:"Kailua",price:"Free",parking:"3 free lots — arrive before 9am on weekends",hours:"Open daily, 5:00 AM – 10:00 PM",bestTime:"Arrive before 9am weekends; weekday mornings are uncrowded",kidFriendly:true,talkStory:"Kailua means 'two seas' or 'two currents' in Hawaiian, referring to the twin channels flanking the bay. President Obama repeatedly vacationed here, putting this once-sleepy local beach on the global map. Kayak to Moku Nui (the larger Mokulua Island) and hike over the ridge to a hidden back-side beach with zero people. The afternoon trade winds turn the bay into one of the world's best kiteboarding spots — even if you don't kite, the aerial show from shore is worth staying for.",kamaaina:null},
  {name:"Kalama Beach Park",tier:"B",lat:21.4047,lng:-157.7398,category:"beach",subcategory:"kid-friendly",tagline:"Kailua's neighborhood beach park — where locals actually go while tourists crowd Kailua Beach down the road.",area:"Kailua",price:"Free",parking:"Free lot on N Kalaheo Ave; easier to find a spot than Kailua Beach Park",hours:"Open daily, sunrise to sunset",bestTime:"Morning for SUP and kayaking; afternoon for the breeze and kite-watching",kidFriendly:true,talkStory:"Named for King David Kalakaua's wife, Queen Kapiolani's original name Kalama, this park is Kailua's locals-only alternative with the same powder-blue water and half the people. The flat, sandy bottom stays shallow far offshore, making it one of the safest swimming spots for small children on the windward side. Afternoon trades turn the bay into a kiteboarding arena, and watching the kites from Buzz's Steakhouse lanai next door with a mai tai is a legit local move.",kamaaina:null},
  {name:"Kawela Bay",tier:"B",lat:21.697,lng:-157.9965,category:"beach",subcategory:"hidden",tagline:"A secluded crescent bay past Turtle Bay Resort that feels like you stepped into a postcard from old Hawaii.",area:"North Shore",price:"Free",parking:"Park at the public access lot near Turtle Bay Resort; 10-minute walk along the shoreline trail",hours:"Open daily, sunrise to sunset",bestTime:"Mornings for calm water; summer for swimming, winter for dramatic scenery",kidFriendly:true,talkStory:"Kawela Bay was a major filming location for LOST (the survivors' beach camp), Pirates of the Caribbean 4, and The Hunger Games: Catching Fire. The bay was part of the historic Marconi wireless telegraph station site in the early 1900s. A ten-minute walk past Turtle Bay Resort along a coastal ironwood trail rewards you with a crescent of sand you will likely have to yourself. The reef-protected water stays calm year-round, making it one of the few North Shore beaches safe for swimming even in winter.",kamaaina:null},
  {name:"Ko Olina Lagoon 4",tier:"B",lat:21.3283,lng:-158.122,category:"beach",subcategory:"kid-friendly",tagline:"Calm as a bathtub year-round — the best lagoon for families with babies and toddlers.",area:"Ko Olina",price:"Free",parking:"Most public parking of the 4 lagoons — free lot",hours:"Open 24 hours (public beach access)",bestTime:"Arrive by 8am weekends to guarantee parking; weekdays are easy",kidFriendly:true,talkStory:"Ko Olina means 'place of joy' in Hawaiian, and these four lagoons were man-made in the 1990s by blasting channels through the reef to create sheltered coves. Lagoon 4 is the farthest from the resort lobbies, so it draws fewer guests and more locals. All four lagoons are legally public beaches — ignore any resort signage implying otherwise. Sea turtles frequently swim into the lagoons to graze on algae, and the protected water is calm enough for infants year-round.",kamaaina:null},
  {name:"Kualoa Beach Park",tier:"A",lat:21.5137,lng:-157.8378,category:"beach",subcategory:"kid-friendly",tagline:"Chinaman's Hat sits right offshore, the Ko'olau mountains tower behind you — this might be the most scenic beach on the island.",area:"Windward",price:"Free",parking:"Large free lot right at the park",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Morning for best light on the mountains; weekdays to avoid crowds",kidFriendly:true,talkStory:"Kualoa means 'long back' in Hawaiian and was one of the most sacred places on Oahu — ancient chiefs brought their children here to be educated, and it was a pu'uhonua (place of refuge). Mokolii island offshore (nicknamed Chinaman's Hat) is said to be the tail of a mo'o (lizard) slain by the goddess Hi'iaka. At low tide you can wade across the sandbar to the island, but check the tide chart — people get stranded when the water rises. Jurassic Park, 50 First Dates, and Kong: Skull Island were all filmed at Kualoa Ranch directly behind you.",kamaaina:null},
  {name:"Kuilima Cove",tier:"B",lat:21.7075,lng:-157.992,category:"beach",subcategory:"snorkeling",tagline:"A tiny protected cove at Turtle Bay with beginner-friendly snorkeling and green sea turtles just offshore.",area:"North Shore",price:"Free",parking:"Use the Turtle Bay Resort public beach access parking; free but can fill on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Morning for clearest water and turtle sightings; summer for calmest conditions",kidFriendly:true,talkStory:"Kuilima means 'to hold hands' or 'joining of arms' in Hawaiian, describing the protective rocky arms that shelter this tiny cove. The cove's calm, reef-protected water stays swimmable even when the rest of the North Shore is closed out by 20-foot winter surf. Green sea turtles are near-guaranteed sightings here; they feed on the algae growing on the rocks. It is a public beach despite being adjacent to Turtle Bay Resort — park in the public access lot and walk right in.",kamaaina:null},
  {name:"Laniakea Beach",tier:"A",lat:21.5783,lng:-158.1067,category:"beach",subcategory:"wildlife",tagline:"Known as Turtle Beach — where Hawaiian green sea turtles haul out on the sand right in front of you.",area:"North Shore",price:"Free",parking:"Small roadside lot on Kamehameha Hwy; very limited, watch for traffic pulling in",hours:"Open daily, sunrise to sunset",bestTime:"Late morning to early afternoon for best turtle sightings; calmer summer months for swimming",kidFriendly:true,talkStory:"Laniakea means 'wide sky' in Hawaiian, but everyone calls it Turtle Beach. Hawaiian green sea turtles (honu) haul out on this sand to bask almost every afternoon, drawn by the algae-rich reef just offshore. Volunteers from Malama na Honu stand guard daily to keep people at the legally required distance. The turtles here are protected under both federal law and Hawaiian cultural tradition — honu are considered aumakua (family guardians) by many Hawaiian families. Quick stop on the drive to or from Haleiwa, but never touch the turtles.",kamaaina:null},
  {name:"Lanikai Beach",tier:"S",lat:21.3901,lng:-157.7134,category:"beach",subcategory:"swimming",tagline:"Consistently ranked among the world's most beautiful — turquoise water so clear it looks fake.",area:"Kailua",price:"Free",parking:"No public lot — park at Kailua Beach Park and walk 10 min",hours:"Open 24 hours (public beach access via neighborhood paths)",bestTime:"Early morning for calm water and fewer people; sunrise is spectacular",kidFriendly:true,talkStory:"Lanikai means 'heavenly sea' in Hawaiian — a name coined in the 1920s when the area was first developed as a residential neighborhood. There is no public parking lot, no restrooms, and no lifeguards by design; residents fought to keep it that way. Access is through narrow blue-signed paths between beachfront homes on Mokulua Drive that are easy to miss. Do the Lanikai Pillbox hike at sunrise first — the aerial view of the Mokulua Islands from the WWII bunkers above is one of Oahu's most iconic sights, then cool off with a swim below.",kamaaina:null},
  {name:"Makaha Beach",tier:"B",lat:21.4734,lng:-158.2181,category:"beach",subcategory:"surfing",tagline:"World-class surf history and world-class sunsets — the Waianae coast's crown jewel.",area:"Makaha",price:"Free",parking:"Free parking lot",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Summer for calm swimming and snorkeling; winter for big wave watching (stay out of water); sunset year-round",kidFriendly:false,talkStory:"Makaha means 'fierce' or 'savage' in Hawaiian, and the wave here lives up to it. This was the epicenter of big-wave surfing before the North Shore took over in the 1960s — the Makaha International contest, started in 1954, was the sport's first world championship. Buffalo Keaulana's Big Board Surfing Classic every March is a celebration of old-school Hawaiian surf culture with tandem surfing and canoe races. Summer brings crystal-clear snorkeling with turtles; winter brings 20-foot waves and a fierce rip current. Respect the locals — this is their home break.",kamaaina:null},
  {name:"Makapu'u Beach",tier:"A",lat:21.3161,lng:-157.6645,category:"beach",subcategory:"bodyboard",tagline:"A natural amphitheater channeling perfect shore break — bodyboard legends cut their teeth here.",area:"Makapu'u",price:"Free",parking:"Free lot off Kalanianaole Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Oct–Apr for best east swell; mornings for lighter wind",kidFriendly:false,talkStory:"Makapu'u means 'bulging eye' in Hawaiian, likely referring to the prominent headland that juts into the sea. This beach has the most powerful shore break on Oahu and causes more spinal injuries than any other — the waves jack up fast over a shallow sandy bottom and slam swimmers headfirst into the sand. Despite the danger, it is bodyboarding's spiritual home; legends like Mike Stewart and Ben Severson honed their craft here. Bring fins and a board, watch several sets from the sand to read the conditions, and never turn your back on the ocean.",kamaaina:null},
  {name:"Makua Beach",tier:"B",lat:21.524,lng:-158.2332,category:"beach",subcategory:"hidden",tagline:"The last beach before the road ends — remote, wild, and stunningly beautiful with spinner dolphins offshore.",area:"West Side",price:"Free",parking:"Roadside parking along Farrington Hwy; limited spaces",hours:"Open daily, sunrise to sunset; road beyond Makua is gated",bestTime:"Summer mornings for calm water and dolphin sightings; avoid after heavy rain",kidFriendly:false,talkStory:"Makua means 'parents' in Hawaiian; the valley was considered the birthplace of humanity in Hawaiian cosmology. The U.S. military used Makua Valley for live-fire training for decades, and access to the valley remains restricted, though cultural practitioners hold regular ceremonies. Spinner dolphins are frequently spotted in the bay at dawn. Swimming is only safe in calm summer months — winter surf and currents here are genuinely life-threatening. This is sacred land to many Hawaiians, so treat it with the deepest respect.",kamaaina:null},
  {name:"Malaekahana Beach",tier:"A",lat:21.5703,lng:-157.9245,category:"beach",subcategory:"hidden",tagline:"A mile of empty gold sand with a tiny island you can walk to at low tide — one of Oahu's best-kept secrets.",area:"Laie",price:"Free",parking:"Free state park lot off Kamehameha Hwy",hours:"Open daily, 7:00 AM – 7:45 PM (gates locked at closing)",bestTime:"Low tide to walk to Goat Island (Mokuauia); check tide charts before going",kidFriendly:true,talkStory:"Malaekahana means 'song-entwined' in Hawaiian, and this mile-long stretch of golden sand is the quietest beach on Oahu's north-facing coast. At low tide you can wade to Mokuauia (Goat Island), a state bird sanctuary with its own tiny hidden beach on the far side — wear reef shoes for the rocky crossing. Hawaiian monk seals occasionally haul out here to rest; if you see one, stay 50 feet back. Camping is available with a state permit, and even on holiday weekends this beach feels deserted compared to anything in town.",kamaaina:null},
  {name:"Nanakuli Beach Park",tier:"C",lat:21.3897,lng:-158.1542,category:"beach",subcategory:"sunset",tagline:"A wide sandy beach on the Waianae coast with some of the most fiery sunsets you'll see on the island.",area:"West Side",price:"Free",parking:"Free lot at the park",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Late afternoon for golden light and sunsets; summer for calmer swimming",kidFriendly:true,talkStory:"Nanakuli means 'look at knee' or 'pretend to be deaf' in Hawaiian — local lore says it refers to residents who pretended not to hear travelers asking for food during a famine, out of shame at having none to share. The sunsets from this west-facing coast are the most vivid on Oahu because there is nothing but open ocean to the horizon. This is a tight-knit Native Hawaiian community beach; come with genuine aloha and respect and you will be welcomed warmly. Summer water is gentle; winter surf can be dangerous.",kamaaina:null},
  {name:"Pokai Bay",tier:"B",lat:21.4335,lng:-158.1896,category:"beach",subcategory:"kid-friendly",tagline:"The calmest water on the west side thanks to a protective breakwater — a true locals' family beach.",area:"West Side",price:"Free",parking:"Free lot at Pokai Bay Beach Park",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Year-round; the breakwater keeps the bay calm even when other west side beaches are rough",kidFriendly:true,talkStory:"Named after a legendary Polynesian voyager who sailed from this bay, Pokai Bay's breakwater creates the calmest protected swimming on the entire Waianae coast. On the rocky point sits Ku'ilioloa Heiau, one of the oldest navigational temples in Hawaii — ancient voyagers prayed here before setting out across the Pacific. Local families camp here on weekends with full setups, fishing and cooking all day. This is not a tourist beach; it is a living community gathering place, and the respect you give will be returned tenfold.",kamaaina:null},
  {name:"Pounders Beach",tier:"A",lat:21.5958,lng:-157.9125,category:"beach",subcategory:"bodyboard",tagline:"La'ie's powerful shorebreak beach — named for the waves that pound the sand, beloved by bodyboarders and local families.",area:"La'ie",price:"Free",parking:"Small lot off Kamehameha Hwy; roadside parking",hours:"Open daily, sunrise to sunset",bestTime:"Summer for calmer water; winter brings the pounding shorebreak it's named for",kidFriendly:false,talkStory:"Pounders' Hawaiian name is Pahumoa, and the beach earned its English name from the waves that literally pound straight down onto the sand with shocking force. La'ie was designated a gathering place for Mormon missionaries in the 1860s, and BYU-Hawaii students still treat this as their backyard beach. The left side near the rocky point is calmer for wading, while the center shore break is where experienced bodyboarders come for the thrill. Most tourists blow right past on their way to the Polynesian Cultural Center, leaving this raw, beautiful beach uncrowded.",kamaaina:null},
  {name:"Punalu'u Beach",tier:"C",lat:21.5698,lng:-157.8925,category:"beach",subcategory:"hidden",tagline:"A skinny ribbon of sand along the windward coast that locals use for quick dips and fishing — no crowds, ever.",area:"Windward",price:"Free",parking:"Roadside pulloffs along Kamehameha Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Summer mornings; water can be murky after rain",kidFriendly:false,talkStory:"Not to be confused with the Big Island's famous black sand beach of the same name, Oahu's Punalu'u ('coral dived for') is a narrow windward strip where local fishermen have cast throw nets for generations. The offshore reef protects a shallow swimming area, but the beach is more about the drive than the destination — the windward coast highway through here is one of the most scenic roads on the island. Ancient Hawaiians cultivated taro in the Punalu'u Valley above, and the area retains a rural, untouched character rare on Oahu.",kamaaina:null},
  {name:"Sandy Beach",tier:"A",lat:21.2857,lng:-157.6727,category:"beach",subcategory:"bodyboard",tagline:"Oahu's most notorious shore break — where locals prove themselves and lifeguards stay busy.",area:"Hawaii Kai",price:"Free",parking:"Free lot along Kalanianaole Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Best at 2–4 ft swell for bodyboarding; any day for watching from the sand",kidFriendly:false,talkStory:"Locals just call it Sandy's, and it holds the grim distinction of sending more people to the emergency room than any other beach in Hawaii. The powerful shore break slams onto a steep sand shelf, and even experienced bodysurfers get worked. From Here to Eternity's iconic beach scene was filmed nearby, and the grassy bluff above (Koko Crater) is Oahu's premier kite-flying and hang-gliding launch. The parking lot scene on weekends is its own spectator sport — half of east Honolulu shows up to tailgate, watch the bodyboarders, and talk story.",kamaaina:null},
  {name:"Shark's Cove",tier:"A",lat:21.6529,lng:-158.0637,category:"beach",subcategory:"snorkeling",tagline:"The best shore snorkeling on Oahu — a rocky cove teeming with sea turtles, reef fish, and tide pool life.",area:"North Shore",price:"Free",parking:"Gravel lot across Kamehameha Hwy; fills by 10 AM on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Summer (May–Sept) when the water is calm and visibility is 50+ ft; never enter in winter swells",kidFriendly:false,talkStory:"Despite the scary name, there are no sharks — it was likely named for the jagged rock formations framing the cove. In summer, this is the best shore-diving and snorkeling site on Oahu, with underwater lava tubes, caverns, and visibility that can exceed 50 feet. The right side has tide pools full of sea cucumbers and shrimp that kids love exploring. In winter, massive North Shore swells make this spot lethal — waves explode over the rocks. Reef shoes are mandatory for the rocky entry, and the food trucks across the highway (especially the garlic shrimp) are part of the ritual.",kamaaina:null},
  {name:"Sunset Beach",tier:"A",lat:21.6746,lng:-158.0398,category:"beach",subcategory:"surfing",tagline:"The crown jewel of the Seven Mile Miracle — where the world's best surfers come to prove themselves every winter.",area:"North Shore",price:"Free",parking:"Street parking along Kamehameha Hwy fills fast in winter; arrive before 9 AM",hours:"Open daily, sunrise to sunset",bestTime:"Summer for swimming and sunsets; winter (Nov–Feb) for watching world-class surf competitions",kidFriendly:false,talkStory:"Sunset Beach is the crown jewel of the 'Seven Mile Miracle,' the stretch of North Shore coastline that hosts the world's most prestigious surf competitions. The Vans Triple Crown of Surfing runs here November through December, and watching from the sand is free — you are closer to world-class athletes than at any other major sport. In summer, the same beach that produces 30-foot winter faces goes completely flat, revealing a wide sandy beach perfect for families. Grab a plate lunch from a Kam Highway food truck, park on the sand, and watch the sun drop into the Pacific.",kamaaina:null},
  {name:"Waikiki Beach",tier:"S",lat:21.2765,lng:-157.8272,category:"beach",subcategory:"swimming",tagline:"Yes, it's touristy — but the surf break is gentle, the people-watching is elite, and the sunset with Diamond Head is undeniable.",area:"Waikiki",price:"Free",parking:"Use the Waikiki Shell lot ($5) or park at Kapiolani Park; street parking is near impossible",hours:"Open 24 hours",bestTime:"Early morning for calm water and space; sunset for the iconic view",kidFriendly:true,talkStory:"Waikiki means 'spouting waters' in Hawaiian, named for the freshwater springs that once fed taro fields and fishponds where hotels now stand. Duke Kahanamoku, the father of modern surfing and Olympic gold medalist, grew up surfing these breaks and his bronze statue on the beach is the most photographed landmark in Hawaii. The break called 'Canoes' is where generations of locals learned to surf — go at dawn before the rental longboard armada launches. For a quieter stretch, walk east past the Natatorium toward Diamond Head where the sand widens and the crowds thin out.",kamaaina:null},
  {name:"Waimanalo Beach",tier:"A",lat:21.3319,lng:-157.6942,category:"beach",subcategory:"swimming",tagline:"The longest white sand beach on Oahu — nearly 4 miles backed by the Ko'olau mountains.",area:"Waimanalo",price:"Free",parking:"Free lot at Waimanalo Beach Park",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Morning for calm water; any day — rarely crowded",kidFriendly:true,talkStory:"Waimanalo means 'potable water' in Hawaiian, and this nearly four-mile stretch of white sand backed by the Ko'olau cliffs is regularly voted Hawaii's best beach. It was a filming location for Magnum P.I., Hawaii Five-0, and several movies. The shore break here produces perfect small barrels for bodyboarding on east swells. Waimanalo is a proud local Hawaiian community — show respect, don't leave valuables in your car, and grab a plate lunch at Keneke's or poi from the roadside stands on the way out.",kamaaina:null},
  {name:"Waimea Bay",tier:"S",lat:21.6423,lng:-158.0656,category:"beach",subcategory:"swimming",tagline:"Birthplace of big wave surfing in winter, glass-calm swimming hole in summer — two completely different worlds.",area:"North Shore",price:"Free",parking:"Parking fills by 10am — arrive early or use Haleiwa shuttle",hours:"Open daily, 7:00 AM – 7:45 PM",bestTime:"Summer for calm swimming and Jump Rock; winter for watching 30+ ft waves (do NOT swim)",kidFriendly:false,talkStory:"Waimea means 'reddish water' in Hawaiian, from the red soil washing into the bay. This is the birthplace of big-wave surfing — Greg Noll rode the first massive waves here in 1957, and the Eddie Aikau Big Wave Invitational, held only when swells hit 30+ feet, is surfing's most sacred event. Jump Rock on the left side is a summer rite of passage for local kids. In winter the bay becomes a churning death trap — even wading is deadly. Waimea Valley across the road makes a perfect combo day.",kamaaina:null},
  {name:"White Plains Beach",tier:"B",lat:21.3221,lng:-158.0407,category:"beach",subcategory:"surfing",tagline:"A former military beach now open to the public — wide sand, consistent beginner waves, and no Waikiki crowds.",area:"Ewa",price:"Free",parking:"Large free lot; ample parking even on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Morning for glassy surf conditions; year-round for consistent small waves",kidFriendly:true,talkStory:"White Plains was a restricted military beach at Barbers Point Naval Air Station until the base closed in 1999 and public access was restored. The beach breaks here produce small, forgiving waves that peel consistently — locals consider it the best learn-to-surf spot on Oahu, without the chaos and rental-board traffic of Waikiki. Board rentals and lessons are available right on the sand. The beach is wide with soft sand and rarely crowded even on weekends thanks to the Ewa location most tourists overlook.",kamaaina:null},
  {name:"Yokohama Bay",tier:"B",lat:21.5582,lng:-158.2448,category:"beach",subcategory:"sunset",tagline:"The end of the road on the west side — wild, empty, and painted in fire every evening.",area:"Makaha",price:"Free",parking:"Free lot at end of Farrington Hwy",hours:"Open daily, 7:00 AM – 7:45 PM (gates locked at closing)",bestTime:"Sunset year-round; summer for swimming (winter has dangerous surf)",kidFriendly:false,talkStory:"Yokohama Bay's Hawaiian name is Keawaula, meaning 'the red harbor.' It got its English name from the Japanese fishermen from Yokohama who fished these waters in the early 1900s. This is literally the end of the road on the west side — beyond here, the Ka'ena Point trail leads to Oahu's westernmost tip, a sacred site where ancient Hawaiians believed souls leapt into the afterlife. There is zero shade, no lifeguards, and winter surf is genuinely deadly. Come in summer for swimming and at sunset year-round for some of the most spectacular skies on the island.",kamaaina:null},
  {name:"9Bar HNL",tier:"A",lat:21.2914,lng:-157.8524,category:"coffee",subcategory:"specialty-coffee",tagline:"Kakaako's serious specialty coffee bar — single-origin pours, expert baristas, and a minimalist space designed for people who care about the cup.",area:"Kakaako",price:"$",mustOrder:["single-origin pour over — ask what's roasted fresh","cortado — perfectly balanced espresso and milk","cold brew — smooth and clean"],parking:"Street parking; Kakaako lot nearby",talkStory:"Founded by coffee obsessives who wanted to bring third-wave specialty standards to Honolulu, 9Bar rotates single-origin beans from roasters like Onyx, Heart, and local Hawaiian farms. The baristas are trained to competition level — ask them to dial in a pour-over to your taste preference. The minimalist Kakaako space draws architects, designers, and tech workers from the surrounding creative district. Skip the milk drinks and go straight for whatever single-origin they’re pouring that day.",cashOnly:false,kamaaina:null},
  {name:"Ars Cafe",tier:"B",lat:21.266,lng:-157.8105,category:"coffee",subcategory:"cafe",tagline:"Art gallery meets gelato shop meets espresso bar — a charming post-Diamond Head pit stop with homemade Italian gelato.",area:"Kapahulu / Diamond Head",price:"$$",mustOrder:["Homemade gelato — rotating tropical flavors like lilikoi and haupia","Espresso or cappuccino","Affogato — espresso poured over gelato"],parking:"Street parking on Monsarrat Ave. Can be tight on weekends",talkStory:"Run by a Japanese-Italian couple who make authentic gelato in-house daily using local tropical fruits like lilikoi, guava, and haupia coconut. The espresso is pulled on a proper Italian machine, and the affogato — a shot of espresso poured over their homemade gelato — is the best post-Diamond Head hike reward on the island. The rotating art on the walls is from local Honolulu artists and actually for sale. Monsarrat Ave locals treat this as their secret neighborhood gem.",cashOnly:false,kamaaina:null},
  {name:"Arvo Cafe",tier:"A",lat:21.2978,lng:-157.8601,category:"coffee",subcategory:"cafe",tagline:"Aussie-inspired at SALT Kakaako — the ube bread alone is worth the trip.",area:"Kakaako",price:"$$",mustOrder:["ube (purple yam) toast","flat white","cold brew"],parking:"SALT has street parking and a lot behind the complex",talkStory:"Founded by Australian expat Jess Santelices, who brought Melbourne cafe culture to Kakaako. ‘Arvo’ is Aussie slang for afternoon. The signature ube (purple yam) toast became a viral sensation and put this place on the map — it’s made with real Filipino ube, not food coloring. The flat whites are legit Melbourne-style, pulled with Hawaiian-roasted beans. Get there right at 8am opening on weekdays; the pastry case and that famous ube toast sell out fast.",cashOnly:false,kamaaina:null},
  {name:"Bean About Town",tier:"B",lat:21.279,lng:-157.784,category:"coffee",subcategory:"specialty-coffee",tagline:"A semi-hidden Kaimuki coffee spot using beans from top mainland roasters — no-fuss, quality-focused neighborhood vibes.",area:"Kaimuki",price:"$",mustOrder:["espresso","pour-over"],parking:"Street parking on 12th Ave",talkStory:"This tiny Kaimuki spot rotates beans from acclaimed mainland roasters like Sightglass, Verve, and Heart — the owner hand-picks each selection. The 12th Ave location is deliberately off the beaten path, and the regulars like it that way. No flashy latte art competitions here, just precisely dialed-in espresso and honest conversation. Kaimuki’s food scene is all within walking distance, making this the ideal caffeine launchpad for a neighborhood food crawl.",cashOnly:false,kamaaina:null},
  {name:"Beet Box Cafe",tier:"B",lat:21.3947,lng:-157.7447,category:"coffee",subcategory:"cafe",tagline:"Plant-powered cafe in Kailua with the best oat milk lattes and acai bowls on the Windward side.",area:"Kailua",price:"$$",mustOrder:["golden turmeric latte — anti-inflammatory and delicious","acai bowl with local honey and granola"],parking:"Small lot in front; additional parking on Hahani St",talkStory:"A 100% plant-based cafe founded by a North Shore surfer committed to clean eating done right. They source produce from Windward-side farms whenever possible, and the golden turmeric latte uses fresh-ground turmeric root with house-made oat milk — miles better than the powdered versions elsewhere. A Kailua institution for yoga instructors, Crossfit regulars, and Lanikai moms who’ve made this their post-workout ritual. The acai bowls are thick and loaded, not the watered-down tourist kind.",cashOnly:false,kamaaina:null},
  {name:"Brew & Foam",tier:"B",lat:21.573,lng:-158.127,category:"coffee",subcategory:"specialty-coffee",tagline:"Hidden in a Waialua shopping center away from tourist Haleiwa — serious baristas and one of the best matcha lattes on the island.",area:"North Shore",price:"$",mustOrder:["matcha latte","espresso"],parking:"Free lot at shopping center",talkStory:"Tucked in an unassuming Waialua shopping center far from tourist Haleiwa, Brew & Foam is where North Shore locals actually get their coffee. The owners are competition-trained baristas who left Honolulu’s cafe scene for the country lifestyle. Their ceremonial-grade matcha latte is widely considered the best on the island — they whisk it properly, Japanese-style. The espresso pulls rival anything in town. Come any morning for zero wait and genuine talk story with the baristas.",cashOnly:false,kamaaina:null},
  {name:"ChadLou's Coffee",tier:"A",lat:21.3945,lng:-157.7449,category:"coffee",subcategory:"roaster",tagline:"Kailua's most serious roastery — artisan small-batch with cult-following seasonal lattes.",area:"Kailua",price:"$$",mustOrder:["seasonal latte","single-origin pour-over","house roast bag ($14–18)"],parking:"Street parking on Hoolai or in the nearby municipal lot",talkStory:"Chad is a certified Q Grader — the coffee world’s equivalent of a Master Sommelier — and ‘Lou’ is his wife and co-founder. They source beans directly from Hawaiian farms and roast everything in small batches in Kailua. Their seasonal lattes have a cult following; regulars track flavor drops on Instagram like sneaker releases. Buy a bag of their house roast — it’s some of the best roasted-in-Hawaii coffee you can take home.",cashOnly:false,kamaaina:null},
  {name:"Coffee Gallery",tier:"S",lat:21.5943,lng:-158.1045,category:"coffee",subcategory:"roaster",tagline:"North Shore roastery with Oahu, Maui, and Kona beans — the real locals' coffee stop in Haleiwa.",area:"Haleiwa",price:"$",mustOrder:["Waialua estate coffee","bag of Waialua beans ($12–16)","iced mocha"],parking:"Parking in the North Shore Marketplace lot — easy",talkStory:"A Haleiwa fixture since the early 2000s, Coffee Gallery roasts beans from multiple Hawaiian estates in-house: Waialua (grown right here on the North Shore), Kona, Maui, and Kauai. The Waialua estate coffee is the insider move — you’re drinking coffee grown 10 miles away on former Dole plantation land. Grab a bag of Waialua beans as a souvenir most visitors don’t know exists — Oahu-grown coffee is genuinely rare.",cashOnly:false,kamaaina:null},
  {name:"Green World Coffee Farm",tier:"A",lat:21.521,lng:-158.013,category:"coffee",subcategory:"farm-cafe",tagline:"A working 7-acre coffee farm on a former pineapple plantation — free self-guided tours and freshly roasted Waialua coffee.",area:"Wahiawa / Central",price:"$",mustOrder:["Waialua estate coffee","homemade banana bread"],parking:"Free lot on the farm",talkStory:"A working 7-acre coffee farm on former Dole pineapple land in Central Oahu. Free self-guided tours let you walk among coffee trees and see the full bean-to-cup process. The cafe serves freshly roasted Waialua coffee at prices way below Waikiki, and the homemade banana bread is legendary among locals driving to the North Shore. One of the only places on Oahu where you can pick a coffee cherry off the tree and drink the roasted result.",cashOnly:false,kamaaina:null},
  {name:"Haleiwa Bowls",tier:"B",lat:21.5762,lng:-158.1024,category:"coffee",subcategory:"cafe",tagline:"North Shore's go-to for acai bowls and espresso drinks in the heart of Haleiwa town.",area:"North Shore (Haleiwa)",price:"$$",mustOrder:["iced honey latte — pairs perfectly with an acai bowl","cold brew — strong enough for a post-surf revival"],parking:"Free lot behind Haleiwa town shops on Kamehameha Hwy",talkStory:"Started as a tiny acai bowl stand and grew into Haleiwa’s go-to breakfast spot. The bowls use high-quality acai imported from Brazil, blended extra thick — they won’t melt before you finish. The espresso program was added later but is surprisingly legit, with beans from local roasters. The honey latte pairs perfectly with a bowl. Come before 9am to beat the caravan of day-trippers from Honolulu — by mid-morning the line snakes out the door and down the sidewalk.",cashOnly:false,kamaaina:null},
  {name:"Honolulu Coffee Experience Center",tier:"A",lat:21.286,lng:-157.8368,category:"coffee",subcategory:"roaster",tagline:"Their flagship roastery lets you taste the full range of Hawaiian coffee under one roof.",area:"Ward Village",price:"$$$",mustOrder:["Kona peaberry pour-over — the good stuff","coffee flight — taste multiple Hawaiian estates side by side"],parking:"Ward Village parking structure, free with validation",talkStory:"Founded in 1992, Honolulu Coffee is one of Hawaii’s largest specialty roasters. This Ward Village flagship is their mothership — not the same as the airport kiosks. They roast on-site with a Probat roaster you can watch in action, and coffee flights let you taste the difference between Kona, Waialua, and Ka’u beans side by side. They own their own farm in Kona for full seed-to-cup control. Pricey, but worth doing once.",cashOnly:false,kamaaina:null},
  {name:"Island Brew Coffeehouse",tier:"B",lat:21.2887,lng:-157.8447,category:"coffee",subcategory:"cafe",tagline:"Hawaii-grown coffee in an open-air lanai setting right on the Ala Moana waterfront.",area:"Ala Moana",price:"$$",mustOrder:["Hawaiian honey latte — local honey and Waialua coffee","cold brew on nitro — smooth and creamy"],parking:"Ala Moana Center parking garage, free for 4 hours",talkStory:"Locally owned and committed to sourcing exclusively from Hawaiian farms — Waialua, Kona, Ka’u, and Maui estates rotate through the menu seasonally. The open-air lanai seating overlooks Ala Moana Beach Park, and when the trade winds blow through it’s one of the most pleasant coffee spots on the island. The Hawaiian honey latte uses raw honey from Big Island apiaries. Way more relaxed than the Ala Moana food court upstairs, and the coffee is leagues better than any chain in the mall.",cashOnly:false,kamaaina:null},
  {name:"Island Vintage Coffee",tier:"A",lat:21.2842,lng:-157.837,category:"coffee",subcategory:"cafe",tagline:"100% Kona coffee, acai bowls the size of your head, and the best iced latte in Waikiki — tourist-friendly but genuinely good.",area:"Waikiki (Royal Hawaiian Center)",price:"$$",mustOrder:["Mauna Kea Iced Coffee — Kona coffee, coconut gelato, black lava sea salt","Acai Bowl — massive, loaded with granola and fresh fruit","100% Kona drip coffee"],parking:"Royal Hawaiian Center validated parking or street meters on Kalakaua Ave",talkStory:"Founded in 2008 by a local family determined to serve only 100% Hawaiian-grown beans — never the cheap 10% Kona blends sold in tourist shops. The signature Mauna Kea Iced Coffee with coconut gelato and black lava sea salt is iconic and has been copied across the island. Their acai bowls are massive and consistently ranked among Oahu’s best. Multiple locations now, but the Royal Hawaiian Center original has the most energy. The line moves fast even when it looks long — they run a tight operation.",cashOnly:false,kamaaina:null},
  {name:"Kai Coffee Hawaii",tier:"A",lat:21.2783,lng:-157.8272,category:"coffee",subcategory:"cafe",tagline:"A legit local roaster hiding in plain sight on the edge of Waikiki.",area:"Waikiki",price:"$$",mustOrder:["Waialua single-origin drip — clean and bright","macadamia nut latte — tastes like Hawaii"],parking:"Street parking on Monsarrat Ave or park at Kapiolani Park and walk",talkStory:"Founded by a local family of coffee farmers, Kai roasts their own beans in-house — rare for a Waikiki-area shop. The Monsarrat Ave location near Diamond Head attracts neighborhood regulars instead of tourists. Their macadamia nut latte uses real mac nuts, not syrup. Buy a bag of their single-origin roast as a souvenir — genuinely better and cheaper than anything at ABC Store. Perfect fuel stop before or after the Diamond Head hike.",cashOnly:false,kamaaina:null},
  {name:"Kona Coffee Purveyors",tier:"S",lat:21.2794,lng:-157.8307,category:"coffee",subcategory:"roaster",tagline:"100% Kona paired with SF's b.Patisserie pastries — the best coffee in Waikiki, full stop.",area:"Waikiki",price:"$$",mustOrder:["100% Kona pour-over ($8–10)","iced Kona latte","b.Patisserie pastries"],parking:"Validated parking at International Market Place garage (3 hrs free with purchase)",talkStory:"Founded by Brandon Damitz, who personally visits every Big Island farm he sources from and knows the elevation, varietal, and processing method of every bean. He partnered with Belinda Leong of b.Patisserie — a James Beard-nominated SF bakery — so the kouign-amann here is world-class. The upstairs International Market Place location means most tourists walk right past. Go before 9am and ask which estate the current pour-over is from.",cashOnly:false,kamaaina:null},
  {name:"Manifest",tier:"A",lat:21.311,lng:-157.861,category:"coffee",subcategory:"cafe-bar",tagline:"Chinatown coffee shop by day, cocktail bar by night — a creative hub with gallery vibes and excellent espresso.",area:"Chinatown / Downtown",price:"$$",mustOrder:["espresso","latte","evening cocktail"],parking:"Street parking; paid lots on Maunakea St",talkStory:"Opened around 2015 in a restored Chinatown building, Manifest was created by local creatives who wanted a space for both the morning laptop crowd and the nightlife scene. By day, excellent espresso in a serene, gallery-like space. By night, it transforms into a cocktail bar with rotating DJs and art openings. The dual identity has made it a hub for Honolulu’s artists, musicians, and gallery owners. Friday and Saturday nights are the most electric.",cashOnly:false,kamaaina:null},
  {name:"Morning Brew",tier:"A",lat:21.3938,lng:-157.7356,category:"coffee",subcategory:"cafe",tagline:"Kailua's beloved bohemian coffeehouse — strong wifi, all-day breakfast, 100% Hawaiian-roasted coffee.",area:"Kailua",price:"$",mustOrder:["honey macadamia nut latte","cold brew","acai bowl"],parking:"Parking in the Kailua Shopping Center lot — free and usually easy",talkStory:"Founded by Jim Wayman, a Kailua local who wanted a true community coffeehouse for the Windward side. He sources 100% Hawaiian-grown beans and is usually behind the counter — ask him about the latest roast and he’ll talk your ear off in the best way. The honey macadamia nut latte is the signature drink and has a devoted following. Weekend mornings are packed with post-surf and post-beach regulars. Great WiFi and outlets make this one of the best remote work spots on the Windward side.",cashOnly:false,kamaaina:null},
  {name:"Morning Glass Coffee",tier:"A",lat:21.2877,lng:-157.8213,category:"coffee",subcategory:"cafe",tagline:"Manoa's beloved neighborhood cafe where UH professors and surfers share the same lanai.",area:"Manoa",price:"$$",mustOrder:["honey lavender latte — floral and smooth","acai bowl — thick, not watered down"],parking:"Small lot behind the building; street parking on East Manoa Rd",talkStory:"A Manoa institution since 2012, opened by a husband-and-wife team who wanted to create the neighborhood’s living room. The upstairs lanai is magical on a rainy Manoa morning — and it rains a lot up here, which is part of the charm. UH professors, grad students, and Manoa families all share the same tables. The honey lavender latte is the signature, and the breakfast menu is legitimately good. Stop here before Manoa Falls — way better than anything near the trailhead.",cashOnly:false,kamaaina:null},
  {name:"Surfers Coffee",tier:"B",lat:21.5038,lng:-158.0239,category:"coffee",subcategory:"cafe",tagline:"Non-profit coffee shop run by Surfing The Nations — great espresso with an even better mission.",area:"Wahiawa",price:"$",mustOrder:["espresso","drip coffee","mocha"],parking:"Free parking lot",talkStory:"Run by Surfing The Nations, a nonprofit doing humanitarian work across the Pacific for over 20 years — tsunami relief, youth outreach, and surf therapy for at-risk kids. Every cup directly funds these missions. The coffee is solid, with beans from Hawaiian farms. Located in Wahiawa, dead center between Honolulu and the North Shore, it’s the perfect pit stop on the drive up. The vibe is warm and community-oriented — you might end up hearing about their latest project.",cashOnly:false,kamaaina:null},
  {name:"Waialua Estate Coffee & Chocolate",tier:"A",lat:21.5744,lng:-158.1303,category:"coffee",subcategory:"roaster",tagline:"Farm-to-cup coffee grown and roasted right here on the North Shore — this is the real Hawaii coffee experience.",area:"North Shore (Waialua)",price:"$$",mustOrder:["Waialua single-origin drip — grown literally across the road","chocolate-covered coffee beans — made on-site from estate cacao"],parking:"Free lot at the old Waialua Sugar Mill complex",talkStory:"Located in the historic old Waialua Sugar Mill, this operation grows coffee and cacao on former sugarcane fields right across the road. One of the few places on Oahu where coffee is grown, roasted, and served in the same ahupua’a (Hawaiian land division). They also grow cacao on-site, so the chocolate-covered coffee beans are a double-local specialty. Ask about the current harvest — the farmers at the counter love talking story about how elevation and rainfall affect the cup.",cashOnly:false,kamaaina:null},
  {name:"Ali'iolani Hale & King Kamehameha Statue",tier:"A",lat:21.3066,lng:-157.8591,category:"cultural",subcategory:"historic-landmark",tagline:"The iconic King Kamehameha I statue stands before Hawaii's original government building — draped in lei every June 11 for King Kamehameha Day.",area:"Downtown",price:"Free",parking:"Metered street parking on King St",hours:"Exterior and statue always accessible; Judiciary History Center inside open Mon-Fri 8am-4pm",bestTime:"June 11 (King Kamehameha Day) when the statue is draped in enormous lei — one of Hawaii's most iconic sights",kidFriendly:true,talkStory:"Designed by Australian architect Thomas Rowe in 1872 for Kamehameha V as a palace, Ali'iolani Hale was completed after his death and became the Kingdom's government building instead. The 1893 overthrow of the Hawaiian monarchy was staged from its front steps. The famous Kamehameha statue out front is actually a replica — the original was lost at sea off the Falkland Islands, later recovered, and now stands in Kapa'au on the Big Island. On June 11, volunteers drape 25-foot lei using cherry pickers in a ceremony that draws thousands.",kamaaina:null},
  {name:"ARTS at Marks Garage",tier:"B",lat:21.313,lng:-157.8625,category:"cultural",subcategory:"gallery",tagline:"Honolulu's community arts hub — rotating exhibitions, makers' markets, and the heartbeat of Chinatown's First Friday scene.",area:"Chinatown / Downtown",price:"Free",parking:"Street parking; walk from downtown",hours:"Tue-Sat 11am-6pm; late on First Fridays",bestTime:"First Friday of every month for the art walk; regular gallery hours during the week",kidFriendly:true,talkStory:"Founded in 2001 in a converted auto repair shop on Hotel Street, ARTS at Marks Garage was a deliberate effort to revitalize Chinatown through the arts and has become Honolulu's most important grassroots creative space. The nonprofit survives on community donations and volunteer energy — every dollar you spend here supports local artists directly. First Friday nights transform the block into a street festival with live music, open studios, and food vendors spilling onto Bethel Street.",kamaaina:null},
  {name:"Battleship Missouri Memorial",tier:"A",lat:21.3639,lng:-157.9517,category:"cultural",subcategory:"historic",tagline:"Stand on the exact deck where WWII ended — the Mighty Mo pairs perfectly with the Arizona Memorial across the harbor.",area:"Pearl Harbor",price:"$$",parking:"Use the Pearl Harbor Visitor Center lot ($7/day). Shuttle bus takes you to Ford Island",hours:"Daily 8am–4pm. Closed Thanksgiving, Christmas, New Year's Day",bestTime:"Morning — do the Arizona Memorial first (free, timed tickets), then shuttle to the Missouri. Plan 1.5–2 hours aboard",kidFriendly:true,talkStory:"On the surrender deck, two copies of the instrument of surrender were signed — one leather-bound for the Allies, one canvas-covered for Japan. Captain Callaghan ordered the kamikaze pilot who struck the starboard side in 1945 be given a proper burial at sea with military honors, a gesture of respect still recounted by tour guides. The Missouri was deliberately positioned bow-to-bow with the sunken Arizona, symbolically bookending WWII. Ask about the 'Heart of the Missouri' engine room tour that most visitors skip.",kamaaina:"Kamaaina/military rates available with valid ID"},
  {name:"Byodo-In Temple",tier:"S",lat:21.4252,lng:-157.8257,category:"cultural",subcategory:"temple",tagline:"A full-scale replica of a 900-year-old Kyoto temple tucked against the Ko'olau cliffs — ring the 3-ton bell for blessings.",area:"Kaneohe",price:"$",parking:"Free parking at the entrance",hours:"Daily 8:30am–4:30pm. Last entry 4:15pm",bestTime:"Early morning for misty mountain backdrop and fewer crowds — golden hour light is stunning for photos",kidFriendly:true,talkStory:"This 1968 replica of the 950-year-old Byodo-In in Uji, Japan was built entirely without nails using traditional Japanese joinery to honor a century of Japanese immigration to Hawaii. The 3-ton brass bon-sho bell at the entrance was cast in Osaka — ring it before entering to purify your mind. The 18-foot Amida Buddha inside is covered in gold lacquer and is among the largest carved wooden Buddhas outside Japan. Filming location for Lost, Hawaii Five-0, and Magnum P.I. — the surrounding Valley of the Temples is an active multi-faith cemetery, so be respectful.",kamaaina:"Kamaaina rate: $4 adults, $3 seniors, $2 kids (vs $7/$6/$4 general) with Hawaii ID. No cash — card/contactless only"},
  {name:"Chinatown Cultural Plaza",tier:"B",lat:21.313,lng:-157.862,category:"cultural",subcategory:"cultural-center",tagline:"Traditional herbalists, dim sum restaurants, and Maunakea Street lei stands — the living heart of Honolulu's Chinatown.",area:"Chinatown / Downtown",price:"Free",parking:"Paid parking in plaza garage",hours:"Varies by shop; most open 8am-5pm",bestTime:"Mornings for the freshest lei on Maunakea St; Chinese New Year for festivals",kidFriendly:true,talkStory:"Built in 1973 to anchor Honolulu's Chinese community after waves of redevelopment threatened to displace Chinatown's oldest businesses. The courtyard's feng shui layout and statue of Sun Yat-sen reflect deep ties — Sun Yat-sen attended school in Honolulu and partly planned the Chinese revolution from here. Upstairs herbalists have been mixing traditional remedies for decades using the same suppliers. Hit the Maunakea Street lei stands just outside before 9am for the freshest double-orchid lei at a fraction of airport prices.",kamaaina:null},
  {name:"First Friday Art Walk",tier:"A",lat:21.312,lng:-157.862,category:"cultural",subcategory:"cultural-event",tagline:"Chinatown transforms into a block party every first Friday — galleries, street performers, food, and the creative pulse of Honolulu.",area:"Chinatown / Downtown",price:"Free",parking:"Street parking fills fast; take the bus or rideshare",hours:"First Friday of each month, 5-9pm",bestTime:"Start at Hotel Street around 5:30pm and wander; galleries close around 9pm",kidFriendly:true,talkStory:"On the first Friday of every month, Honolulu's Chinatown transforms into a block party centered on the arts. Galleries on Nu'uanu Avenue open their doors late, street performers and musicians set up on corners, restaurants and bars offer special menus, and the streets fill with a creative, diverse crowd. This is where locals go to see and be seen, discover new artists, and enjoy Chinatown's vibrant food and drink scene all in one evening.",kamaaina:null},
  {name:"Foster Botanical Garden",tier:"B",lat:21.317,lng:-157.858,category:"cultural",subcategory:"garden",tagline:"Honolulu's oldest botanical garden (1853) — ancient trees, rare orchids, and a peaceful escape in the heart of the city.",area:"Chinatown / Downtown",price:"$5",parking:"Free lot on Vineyard Blvd",hours:"Daily 9am-4pm",bestTime:"Weekday mornings for the most peaceful experience",kidFriendly:true,talkStory:"Founded in 1853 when German botanist William Hillebrand planted the first specimens on land leased from Queen Kalama, making it the oldest botanical garden in Hawaii. The garden's sacred bo tree was grown from a cutting of the very tree in Sri Lanka under which Siddhartha Gautama attained enlightenment. Several trees here are the last living specimens of their species on Earth — the garden quietly serves as a conservation ark. The prehistoric glen features cycads and ferns whose lineage predates the dinosaurs by 100 million years.",kamaaina:null},
  {name:"Hawaii State Art Museum",tier:"B",lat:21.308,lng:-157.8595,category:"cultural",subcategory:"museum",tagline:"Free museum showcasing Hawaii's best contemporary art in a beautifully restored 1928 Spanish Colonial building downtown.",area:"Downtown",price:"Free",parking:"Metered street parking on Hotel St",hours:"Tue-Sat 10am-4pm",bestTime:"Weekday afternoons for the quietest experience; First Friday evenings",kidFriendly:true,talkStory:"Housed in a beautifully restored 1928 Spanish Colonial building (the former YMCA Armed Services building), HiSAM showcases Hawaii's best contemporary art across multiple galleries — all for free. The permanent collection features works by Hawaii's leading artists, and rotating exhibitions highlight emerging talent. The sculpture garden courtyard is a peaceful surprise. Most tourists walk right past without realizing this free gem exists.",kamaaina:null},
  {name:"Hawaiian Mission Houses",tier:"C",lat:21.305,lng:-157.859,category:"cultural",subcategory:"museum",tagline:"The oldest surviving Western buildings in Hawaii (1821) — honest, nuanced storytelling about missionaries' complex legacy.",area:"Downtown",price:"$12",parking:"Metered street parking on King St",hours:"Tue-Sat 10am-4pm; check for special events",bestTime:"Guided tour times vary; Wednesday evening events are popular",kidFriendly:true,talkStory:"The 1821 Frame House was prefabricated in Boston, shipped around Cape Horn, and is the oldest surviving Western-style structure in Hawaii. Inside the printing house, missionaries and Hawaiian scholars created the 12-letter Hawaiian alphabet and printed the first Hawaiian-language Bible — a project that took 17 years and helped preserve the language. The museum doesn't shy away from the missionaries' role in dismantling Hawaiian cultural practices. Wednesday evening 'Twilight Tours' feature costumed interpreters and candlelight — a totally different vibe from daytime visits.",kamaaina:null},
  {name:"He'eia Fishpond",tier:"A",lat:21.4403,lng:-157.807,category:"cultural",subcategory:"fishpond",tagline:"An 800-year-old Hawaiian fishpond being actively restored — a living classroom where ancient aquaculture meets modern sustainability.",area:"Kaneohe",price:"Free to view; tours by reservation",parking:"Parking at He'eia State Park across the road",hours:"Grounds visible daily; guided tours and volunteer days scheduled through Paepae o He'eia",bestTime:"Join a volunteer restoration day — hands-on experience rebuilding the rock wall while learning from cultural practitioners",kidFriendly:true,talkStory:"This 800-year-old, 88-acre loko i'a is one of the last intact ancient fishponds on Oahu, managed by Paepae o He'eia, a Native Hawaiian nonprofit. Ancient Hawaiians engineered makaha (sluice gates) to let small fish in from Kaneohe Bay but trap them once they grew — sustainable farming genius. The kuapa (rock wall) stretches nearly a mile and was built by hand from basalt and coral. Sign up for a volunteer day to help restore the wall while learning from cultural practitioners — one of the most meaningful experiences on Oahu.",kamaaina:null},
  {name:"Honolulu Museum of Art",tier:"A",lat:21.3038,lng:-157.8485,category:"cultural",subcategory:"museum",tagline:"Hawaii's largest art museum — 50,000 works spanning 5,000 years, housed in a stunning 1927 building with open-air courtyards.",area:"Downtown Honolulu",price:"$$",parking:"Street parking on Beretania St or paid lots nearby. Limited museum lot",hours:"Wed–Mon 10am–6pm, Fri until 9pm. Closed Tuesdays",bestTime:"First Friday of the month — free admission, live music, food trucks, and a festive atmosphere. Weekday mornings are quietest",kidFriendly:true,talkStory:"Founded in 1927 by missionary descendant Anna Rice Cooke, who believed 'that the people of Hawaii should be able to look at great art.' The building was designed by Bertram Goodhue Associates in a Hawaiian-Mediterranean style with open-air courtyards that let the trade winds flow through the galleries. Its Asian art collection is considered one of the finest in the US, including a rare Hokusai 'Great Wave' print and works spanning 5,000 years. First Fridays mean free admission, live music, and food trucks — the best deal in Honolulu's art scene. Also operates Shangri La; book that separately.",kamaaina:"Free admission for Hawaii residents with valid ID. General admission $20"},
  {name:"Iolani Palace",tier:"S",lat:21.3065,lng:-157.859,category:"cultural",subcategory:"historical-site",tagline:"The only royal palace on American soil — home to Hawaii's last monarchs, with electricity before the White House.",area:"Downtown",price:"$27",parking:"Metered street parking; paid lots on King St",hours:"Tue-Sat 9am-4pm; tours at set times",bestTime:"Morning guided tours; Friday noon concerts by the Royal Hawaiian Band on the grounds (free)",kidFriendly:true,talkStory:"Completed in 1882 for King Kalakaua, Iolani had electric lights four years before the White House and telephones before Buckingham Palace. After the 1893 overthrow, Queen Liliuokalani was imprisoned upstairs for eight months — you can see the quilt she sewed during confinement. The palace fell into severe disrepair and a massive restoration beginning in 1969 recovered original furnishings from basements across the state. The koa wood staircase alone took artisans years to restore.",kamaaina:"Kamaaina rates available"},
  {name:"Kawaiaha'o Church",tier:"A",lat:21.3035,lng:-157.8593,category:"cultural",subcategory:"historic-church",tagline:"The 'Westminster Abbey of Hawaii' — built from 14,000 coral blocks in 1842, where Hawaiian royalty worshipped and history was made.",area:"Downtown",price:"Free",parking:"Street parking on Punchbowl St; paid lots nearby",hours:"Open for self-guided visits Mon-Fri 8am-4pm; Sunday services at 9am (Hawaiian language)",bestTime:"Sunday 9am service for the Hawaiian-language hymns — profoundly moving even if you don't understand the words",kidFriendly:true,talkStory:"Completed in 1842, its 14,000 coral blocks were cut by hand from offshore reefs by Hawaiian divers working at depths of 20 feet — construction took five years. King Kamehameha III spoke 'Ua mau ke ea o ka aina i ka pono' here in 1843 after British sovereignty was reversed — now Hawaii's state motto. The rear cemetery holds missionaries, royalty, and sailors from the Thaddeus. The Sunday 9am Hawaiian-language service features hymns that will give you chicken skin.",kamaaina:null},
  {name:"Kukaniloko Birthing Stones",tier:"S",lat:21.5028,lng:-158.0253,category:"cultural",subcategory:"sacred-site",tagline:"The most sacred site on Oahu — where ali'i (royalty) were born for over 700 years, radiating mana from the island's center.",area:"Wahiawa",price:"Free",parking:"Small dirt lot off Whitmore Ave — look for the state historical marker",hours:"Open daily, sunrise to sunset",bestTime:"Early morning when you may have it to yourself — the silence adds to the gravity of the place",kidFriendly:true,talkStory:"For over 700 years, ali'i (royal) women traveled to this site in the geographic center of Oahu to give birth, attended by 36 chiefs who served as witnesses to validate the child's royal lineage. The petroglyphs carved into the stones are among the oldest on Oahu, and the eucalyptus-lined path you walk today follows what was once a ceremonial approach. The stones are believed to hold immense mana — do not sit on or touch them, and do not leave offerings unless guided by a cultural practitioner. Most locals consider this the single most sacred place on the island; treat it accordingly.",kamaaina:null},
  {name:"Lyon Arboretum",tier:"B",lat:21.333,lng:-157.802,category:"cultural",subcategory:"easy",tagline:"A 194-acre rainforest research garden in upper Manoa Valley — quiet trails, rare tropical plants, and the feel of deep jungle.",area:"Manoa",price:"Free (donations welcome)",parking:"Limited lot; arrive early or carpool",hours:"Mon-Fri 8am-4pm, Sat 9am-3pm",bestTime:"Weekday mornings for solitude; expect afternoon showers",kidFriendly:true,talkStory:"Operated by the University of Hawaii, this 194-acre botanical garden in upper Manoa Valley feels like a secret rainforest just minutes from the city. The trails wind through rare tropical plant collections, native Hawaiian species, and groves of towering trees. Far less crowded than nearby Manoa Falls, it offers a more immersive jungle experience. Reservations required — book online in advance.",kamaaina:null},
  {name:"National Memorial Cemetery of the Pacific",tier:"A",lat:21.3122,lng:-157.8487,category:"cultural",subcategory:"historic",tagline:"A sacred resting place inside an extinct volcanic crater — free to visit, with sweeping views of Honolulu and a humbling sense of history.",area:"Punchbowl (Honolulu)",price:"Free",parking:"Free parking inside the crater. Drive up Puowaina Drive",hours:"Daily 8am–5:30pm (Oct–Feb); 8am–6:30pm (Mar–Sep)",bestTime:"Early morning for cooler temps and fewer visitors. Combine with a Tantalus Drive loop",kidFriendly:true,talkStory:"The Hawaiian name Puowaina means 'Hill of Sacrifice' — ancient Hawaiians used this crater for ceremonies long before it became a military cemetery in 1949. Over 53,000 veterans rest here, including 27 Medal of Honor recipients and war correspondent Ernie Pyle. The Courts of the Missing list 28,000+ names of service members never recovered — volunteers still work to identify remains using modern DNA technology. The mosaic murals in the memorial building depict key Pacific and Korean War battles.",kamaaina:null},
  {name:"Pearl Harbor National Memorial",tier:"S",lat:21.3647,lng:-157.95,category:"cultural",subcategory:"historic",tagline:"The USS Arizona Memorial, Battleship Missouri, and the site where December 7, 1941 changed the world — free admission, book ahead.",area:"Pearl Harbor",price:"Free",parking:"$7/day in visitor center lot — arrives early, fills fast. Do NOT leave valuables in your car (high-theft area)",hours:"Daily 7am–5pm. Last Arizona Memorial boat at 3:30pm. Closed Thanksgiving, Christmas, New Year's Day",bestTime:"Arrive by 7am for walk-up tickets or book online 8 weeks ahead on Recreation.gov ($1 service fee). Mornings are cooler and less crowded",kidFriendly:true,talkStory:"The USS Arizona still leaks about a quart of oil per day — sailors call them 'black tears,' and the slick is visible from the memorial platform. The structure was designed by Alfred Preis, an Austrian-born architect who was himself interned as an enemy alien after the attack. Its dip-and-rise shape symbolizes initial defeat and ultimate victory. Arrive by 7am for walk-up tickets or book on Recreation.gov eight weeks ahead. NO BAGS ALLOWED — only wallets, phones, cameras, and water bottles. Plan a full day if visiting all four Pearl Harbor sites.",kamaaina:null},
  {name:"Pu'u o Mahuka Heiau",tier:"A",lat:21.6402,lng:-158.0572,category:"cultural",subcategory:"historical-site",tagline:"Oahu's largest ancient Hawaiian temple — a sacred 17th-century site on a bluff overlooking Waimea Bay with breathtaking views.",area:"North Shore",price:"Free",parking:"Small gravel lot at the end of Pupukea Rd",hours:"Open daily, daylight hours",bestTime:"Sunrise or sunset for the most powerful atmosphere",kidFriendly:true,talkStory:"Oahu's largest heiau spans nearly two acres on a bluff 250 feet above Waimea Bay and was a luakini heiau — a site of human sacrifice reserved for the highest-ranking chiefs. In 1794, three of Captain George Vancouver's crew members from the Daedalus were reportedly sacrificed here. The kahuna nui (high priest) used this site to communicate with the gods and predict the future. Today, you'll see fresh ti-leaf-wrapped stone offerings left by practitioners — never disturb these. The panoramic views of Waimea Valley, the bay, and the winter surf are reason enough to make the drive up Pupukea Road.",kamaaina:null},
  {name:"Queen Emma Summer Palace",tier:"A",lat:21.336,lng:-157.8452,category:"cultural",subcategory:"historic-home",tagline:"The summer retreat of Queen Emma in the cool Nu'uanu Valley — intimate tours reveal the personal side of Hawaiian royalty.",area:"Nu'uanu",price:"$",parking:"Free lot on the grounds",hours:"Mon-Sat 9am-4pm; last tour at 3pm",bestTime:"Weekday mornings for small tour groups and personal attention from docents",kidFriendly:true,talkStory:"Known in Hawaiian as Hanaiakamalama, this 1847 retreat in cool Nuuanu Valley was where Queen Emma and King Kamehameha IV escaped the heat of Honolulu. Emma was one-quarter English, deeply cosmopolitan, and founded Queen's Hospital in 1859 after watching her people die from Western diseases. After the monarchy fell, the home was slated for demolition until the Daughters of Hawaii rescued it in 1915 — they've maintained it ever since. The docents are often Daughters members themselves and share personal, passionate stories you won't get from a textbook.",kamaaina:"Kamaaina discount with Hawaii ID"},
  {name:"Royal Mausoleum (Mauna 'Ala)",tier:"A",lat:21.3263,lng:-157.845,category:"cultural",subcategory:"sacred-site",tagline:"The final resting place of Hawaiian royalty — six kings, six queens, and other ali'i in a quiet Nu'uanu chapel surrounded by sacred ground.",area:"Nu'uanu",price:"Free",parking:"Small parking area at the entrance on Nu'uanu Ave",hours:"Mon-Fri 8am-4pm; closed weekends and state holidays",bestTime:"Weekday mornings — you'll likely have the grounds to yourself",kidFriendly:true,talkStory:"Mauna 'Ala ('fragrant mountain') was established in 1865 by Kamehameha V after the original royal tomb at Iolani Palace ran out of space. The Gothic Revival chapel holds the remains of six kings, six queens, and dozens of high-ranking ali'i from the Kamehameha and Kalakaua dynasties. A single caretaker from the State of Hawaii tends the grounds — a position that has existed continuously since the Kingdom era. The site is sovereign Hawaiian territory by law, one of the few places where the Hawaiian flag still flies without an American flag beside it.",kamaaina:null},
  {name:"Shangri La",tier:"A",lat:21.257,lng:-157.793,category:"cultural",subcategory:"museum",tagline:"Doris Duke's oceanfront Islamic art mansion — a jaw-dropping private estate with 2,500 pieces of art from the Islamic world.",area:"Kahala / Diamond Head",price:"$30",parking:"Tours depart from Honolulu Museum of Art; shuttle provided",hours:"Wed-Sat; tours at set times (must pre-book)",bestTime:"Book well in advance; tours are small and sell out",kidFriendly:false,talkStory:"Tobacco heiress Doris Duke began building this oceanfront estate in 1937 after her honeymoon travels through the Islamic world. She spent 60 years personally collecting over 2,500 pieces — from Syrian mosaic rooms reassembled tile by tile to Mughal garden pavilions and a 14th-century mihrab from Iran. The swimming pool has an ingenious system that lowers one wall to merge visually with the ocean. Tours are capped at 12 people and depart only from the Honolulu Museum of Art by shuttle — book weeks ahead as they sell out fast. No children under 8 allowed.",kamaaina:"Kamaaina rates available"},
  {name:"Ulupo Heiau",tier:"A",lat:21.3928,lng:-157.75,category:"cultural",subcategory:"heiau",tagline:"A massive ancient Hawaiian temple platform in Kailua — legend says the Menehune built it in a single night.",area:"Kailua",price:"Free",parking:"Park at the Windward YMCA and walk to the heiau",hours:"Open daily, sunrise to sunset",bestTime:"Early morning for quiet reflection — the site faces the Ko'olau mountains",kidFriendly:true,talkStory:"This massive stone platform — 140 feet long and 30 feet high — overlooks Kawainui Marsh, once a productive fishpond feeding thousands. Legend says the Menehune built it in a single night, passing basalt stones hand-to-hand from Kailua Bay. It was likely an agricultural heiau dedicated to Lono, god of fertility and harvest, positioned above the marsh to bless the food supply. A short path through a bamboo grove behind the Windward YMCA leads to the base — most Kailua beachgoers have no idea this ancient temple is right behind them.",kamaaina:null},
  {name:"Wahiawa Botanical Garden",tier:"C",lat:21.496,lng:-157.954,category:"cultural",subcategory:"easy",tagline:"A free 27-acre tropical jewel in Central Oahu — lush ravine walks through native ferns and palms that feel primordial.",area:"Wahiawa / Central",price:"Free",parking:"Free lot on California Ave",hours:"Daily 9am-4pm",bestTime:"Mornings for the coolest temperatures and best light",kidFriendly:true,talkStory:"A free 27-acre botanical garden in Central Oahu along a deep ravine, featuring native Hawaiian plants, tropical ferns, and a palm garden that feels primordial. Far from any tourist path, the cool, shaded ravine walk feels like entering a different world. Locals come here for quiet walks and photography. Free admission, open daily.",kamaaina:null},
  {name:"CLIMB Works Keana Farms",tier:"B",lat:21.683,lng:-157.995,category:"experience",subcategory:"adventure",tagline:"Eight ziplines over a working North Shore farm with panoramic ocean and mountain views — Oahu's best zipline, period.",area:"Kahuku",price:"$$$",parking:"Free on-site parking. Check in 40 minutes before tour time",hours:"Mon–Sat 8am–6pm. Closed Sundays",bestTime:"Morning tours for cooler temps and best light on the Ko'olau mountains. Book at least 5 days ahead during busy season",kidFriendly:true,talkStory:"Three-hour tour with 8 dual ziplines (up to half a mile long), 2 rappels, sky bridges, and an ATV ridgetop ride over a 450-acre working farm that grows macadamia nuts, papaya, and taro. Kids as young as 5 can go (must be accompanied by adult); under 80 lbs can ride tandem with a guide. Weight limit 270 lbs (250 if under 5'10\"). Wear closed-toe shoes and clothes you don't mind getting dirty. Lockers provided for phones and valuables. Perfect 5.0 rating on Google with 8,500+ reviews — that's not a typo. The views of the North Shore coastline from the ridgeline are unreal.",kamaaina:"25% kamaaina discount with valid Hawaii ID — brings price from $169 to about $127"},
  {name:"Dole Plantation",tier:"B",lat:21.5265,lng:-158.035,category:"experience",subcategory:"attraction",tagline:"Touristy but fun — ride the Pineapple Express, get lost in the world's largest maze, and eat a Dole Whip at the source.",area:"Central Oahu (Wahiawa)",price:"$$",parking:"Free parking lot, large and usually available",hours:"Daily 9:30am–5pm",bestTime:"Arrive by 10am to beat tour bus crowds. Weekdays are significantly less packed than weekends",kidFriendly:true,talkStory:"Yes, it's a tourist trap — but it's a fun one, especially with kids. The Pineapple Express train ride (20 min, ~$14) gives a nice overview of the plantation and North Shore agriculture. The Pineapple Garden Maze is certified by Guinness as the world's largest — budget 30-45 min. The real move is to skip the gift shop markup and grab a Dole Whip (pineapple soft serve) from the stand out front. Great pit stop on the way to or from the North Shore. Locals rarely go, but visitors love it.",kamaaina:"Kamaaina discounts on train ride and maze with valid Hawaii ID"},
  {name:"Halona Blowhole Lookout",tier:"B",lat:21.2789,lng:-157.6779,category:"experience",subcategory:"scenic-viewpoint",tagline:"A natural lava tube that shoots ocean spray 30 feet in the air — quick roadside stop with views of the rugged east coast.",area:"Hawaii Kai / East Side",price:"Free",parking:"Free pullout lot on Kalanianaole Hwy. Small and fills fast midday",hours:"Open 24/7 (roadside pullout)",bestTime:"Best spray during high surf and high tide — winter swells produce the most dramatic blasts. Morning light is best for photos",kidFriendly:true,talkStory:"A quick but satisfying stop on the east side drive between Hanauma Bay and Makapu'u. The blowhole shoots water through a lava tube formed by volcanic activity — bigger swells mean bigger blasts, sometimes 30+ feet. The lookout also overlooks Halona Cove (aka 'From Here to Eternity Beach' from the 1953 film). DO NOT climb down the rocks to the blowhole — people have been killed by rogue waves and getting sucked into the tube. Stay behind the guardrail. Combine with Sandy Beach (next door), Hanauma Bay, and Makapu'u Lighthouse Trail for a full east side day.",kamaaina:null},
  {name:"Hawaii Nature Center",tier:"B",lat:21.319,lng:-157.826,category:"experience",subcategory:"nature-education",tagline:"Interactive nature education in Makiki Valley — guided rainforest walks, bug hunts, and Hawaiian ecology for curious kids and adults.",area:"Makiki",price:"$15",parking:"Limited lot on Makiki Heights Dr",hours:"Daily 8am-4pm; guided programs at set times",bestTime:"Morning guided programs; weekdays are less busy",kidFriendly:true,talkStory:"Nestled in Makiki Valley just minutes from downtown, the Hawaii Nature Center offers interactive nature education perfect for curious kids. Guided rainforest walks teach about native Hawaiian plants and animals, bug hunts let kids explore with magnifying glasses, and the interpretive center has hands-on exhibits about Hawaiian ecology. Local families love the weekend programs. A great rainy-day or hot-day alternative to the beach.",kamaaina:null},
  {name:"Hawaiian Railway Society",tier:"A",lat:21.3228,lng:-158.0895,category:"experience",subcategory:"heritage-railway",tagline:"Ride a restored 1900s sugar plantation train along the Ewa coast — the last operating stretch of Oahu's original railway.",area:"Ewa",price:"$",parking:"Free parking at the depot on Renton Rd",hours:"Train rides Sundays at 1pm and 3pm; special events monthly",bestTime:"The 3pm ride catches golden light along the coast; check for holiday-themed runs",kidFriendly:true,talkStory:"Most people don't know that Oahu once had an extensive railway network connecting sugar plantations across the island. The Hawaiian Railway Society preserves the last operating stretch — a 6.5-mile round trip along the Ewa coast in restored rolling stock from the early 1900s. The all-volunteer society runs trains on Sundays and maintains a collection of locomotives and cars in their depot. Kids love it, and adults appreciate the history — this was the transportation backbone of plantation-era Hawaii. A unique experience you won't find anywhere else on the island.",kamaaina:null},
  {name:"Ko Hana Distillers",tier:"A",lat:21.452,lng:-158.037,category:"experience",subcategory:"distillery",tagline:"Oahu's only rum distillery — Hawaiian agricole rum made from 34 heritage sugarcane varieties grown on-site.",area:"Kunia / Central",price:"$$",parking:"Free lot on the farm",hours:"Tours and tastings daily; check schedule",bestTime:"Reserve ahead on weekends; weekday tastings are more intimate",kidFriendly:false,talkStory:"Oahu's only rum distillery produces Hawaiian agricole rum from 34 heritage varieties of Hawaiian sugarcane grown on-site. The tasting room tour explains how pre-contact Hawaiians cultivated ko (sugarcane) and how each heirloom variety produces a different flavor. The tasting flight includes single-varietal rums unlike anything you've had. Locals bring visitors here as a proudly Hawaiian alternative to wine tasting. The agricultural setting in Kunia is beautiful.",kamaaina:null},
  {name:"Ko'olau Distillery",tier:"B",lat:21.396,lng:-157.792,category:"experience",subcategory:"tasting",tagline:"A veteran-owned craft distillery in Kailua making whiskey, rum, and gin — tours, tastings, trivia nights, and food trucks.",area:"Kailua",price:"$$",parking:"Free parking in the Kapaa Quarry Pl industrial complex",hours:"Mon & Wed 12pm–7pm. Tue 12pm–8pm. Thu 12pm–9pm. Fri 12pm–10pm. Sat 12pm–9pm. Sun 8am–7pm",bestTime:"Thursday trivia nights or weekends for food trucks and live music. Afternoon tours at 1pm, 3pm, or 4pm",kidFriendly:false,talkStory:"Tucked in an industrial complex near the Kailua/Kaneohe border, this veteran-owned distillery has quietly become one of Oahu's best hangout spots. One-hour tours cover the full whiskey process from mashing to bottling, ending with a 5-spirit tasting. Their signature Old Pali Road Whiskey is the star. Beyond tours, they have a full bar with craft cocktails, local beers, and wine. Thursday trivia nights are packed, and weekends usually have food trucks and live music in the outdoor area. 21+ for tastings.",kamaaina:null},
  {name:"La'ie Point State Wayside",tier:"A",lat:21.6514,lng:-157.9169,category:"experience",subcategory:"scenic",tagline:"A dramatic windswept cliff with views of a natural sea arch and offshore bird sanctuary — free, quick, and totally uncrowded.",area:"Laie",price:"Free",parking:"Only about 10 spots at the end of Naupaka St — park further down and walk if full. Be respectful of residents",hours:"Daylight hours (roughly 7am–6:30pm)",bestTime:"Late afternoon for golden light on the cliffs. Morning for calmer seas and better visibility of Kukuihoolua Island",kidFriendly:true,talkStory:"A 5-minute walk from the parking area to a rocky coastal point with views of Kukuihoolua Island (the one with the natural arch punched through it) and a seabird sanctuary. Wear closed-toe shoes — the lava rock is sharp and uneven. Not a swimming spot (strong currents and dangerous rocks). No facilities or restrooms. It's a 15-minute stop that pairs perfectly with a North Shore day trip — between PCC and Kahuku shrimp trucks. One of the most photographed spots on the Windward Coast but rarely crowded because most tourists don't know about it.",kamaaina:null},
  {name:"Manoa Honey & Mead",tier:"B",lat:21.5011,lng:-158.0269,category:"experience",subcategory:"tasting",tagline:"Hawaii's only meadery — taste local honey wines, tour the apiary, and learn about beekeeping on a working honey farm.",area:"Wahiawa",price:"$$",parking:"Free on-site parking",hours:"Wed–Thu 10am–4pm. Fri–Sun 11am–6pm. Closed Mon–Tue",bestTime:"Saturday for Bees to Mead tours at 10am or 2pm (reservations required). Weekday afternoons for unhurried tastings",kidFriendly:false,talkStory:"Don't let the Wahiawa industrial location fool you — this tiny meadery is doing something nobody else in Hawaii is. They make mead (honey wine) from their own hives and offer tastings of 6 varieties Friday through Sunday (last seating 5pm). The Bees to Mead tour ($10 deposit) takes you through the apiary to see honey harvesting up close before tasting. You can share tasting flights if 6 glasses is too much. The showroom sells local honey products and bottles to take home. It's small, it's not fancy, and that's exactly why it's great. 21+ for mead tastings.",kamaaina:null},
  {name:"Nu'uanu Pali Lookout",tier:"A",lat:21.366,lng:-157.7935,category:"experience",subcategory:"scenic-viewpoint",tagline:"The most dramatic viewpoint on Oahu — sheer cliffs, howling winds, and the entire Windward Coast spread out below.",area:"Nu'uanu (Pali Highway)",price:"$",parking:"$7/vehicle. Small lot fills up midday",hours:"Daily 6am–6pm",bestTime:"Morning for clearest views. Afternoon clouds roll in. Trade winds blast through here — hold onto hats, phones, and small children",kidFriendly:true,talkStory:"This is where King Kamehameha I won the decisive 1795 Battle of Nu'uanu, driving hundreds of O'ahu warriors over the 1,000-foot cliffs to unify the Hawaiian Islands. The views are jaw-dropping — the entire Windward Coast from Kaneohe to Kailua laid out below the Ko'olau cliffs. The wind here is legendary — sustained 30-40 mph gusts are normal, and 60+ mph days happen. It's a quick stop (15-20 min) right off the Pali Highway between Honolulu and Kailua. Great combined with Old Pali Road hike nearby.",kamaaina:"$3 parking for Hawaii residents with valid ID"},
  {name:"Haleiwa Farmers Market",tier:"A",lat:21.5794,lng:-158.1047,category:"farmers-market",subcategory:"weekend-market",tagline:"The North Shore's best farmers market — local produce, prepared food stalls, and the laid-back surf town energy that defines Haleiwa.",area:"North Shore",price:"$",parking:"Waimea Valley parking area",hours:"Thursdays 2-6pm at Waimea Valley",bestTime:"Arrive at 2pm for the best produce selection",kidFriendly:true,talkStory:"The go-to farmers market for North Shore residents and a great stop for visitors exploring the area. Local farmers sell fresh tropical fruits, vegetables, honey, and flowers alongside prepared food vendors serving everything from acai bowls to poke. The setting at Waimea Valley gives it a beautiful backdrop. Smaller and more intimate than KCC, with a distinctly North Shore vibe — you'll see surfers in board shorts buying papayas next to families loading up on weekly produce. Thursday afternoons only.",kamaaina:null},
  {name:"Honolulu Farmers Market (Blaisdell)",tier:"A",lat:21.2955,lng:-157.8492,category:"farmers-market",subcategory:"evening-market",tagline:"Wednesday evening farmers market at Blaisdell — the best weeknight market with prepared food that doubles as dinner.",area:"Ala Moana / Kakaako",price:"$",parking:"Blaisdell Center parking lot (free during market)",hours:"Wednesdays 4-7pm at Neal S. Blaisdell Center",bestTime:"4:30pm — early enough for produce, late enough that food stalls are ready",kidFriendly:true,talkStory:"The best weeknight farmers market in Honolulu. The Wednesday evening timing makes it accessible for working people who can't do Saturday mornings at KCC. The prepared food stalls are excellent — many locals treat it as their Wednesday dinner spot. Fresh produce, flowers, baked goods, and local specialty items round out the offerings. Less touristy than KCC and with a distinctly after-work urban energy. Parking at Blaisdell is easy and free during market hours.",kamaaina:null},
  {name:"Kailua Farmers' Market",tier:"A",lat:21.3935,lng:-157.7423,category:"farmers-market",subcategory:"evening",tagline:"Thursday evening market run by the same folks behind KCC — 20 years of Hawaii-grown-only produce, mochi, and street corn.",area:"Kailua",price:"Free",parking:"Free parking at Kailua Town Center",hours:"Thursdays 4pm–7pm sharp. Alarm sounds at 7pm and all sales stop immediately",bestTime:"Arrive before 5pm — popular items like Mochi Aulelei Hawaii taro mochi and Nozawa Farms street corn sell out early",kidFriendly:true,talkStory:"Run by the Hawaii Farm Bureau, the same organization behind the famous KCC Farmers Market. This one's been going for 20 years and strictly sells Hawaii-grown products — produce, flowers, beef, pork, seafood, and ready-to-eat foods. Look for the family-run German bakery and handmade salsas. Kids love the chalk and live music. The 7pm alarm is no joke — when it goes off, everything shuts down, so don't arrive at 6:45 expecting to browse. Located at 609 Kailua Rd in Kailua Town Center.",kamaaina:null},
  {name:"KailuaTown Farmers Market",tier:"B",lat:21.3942,lng:-157.7459,category:"farmers-market",subcategory:"sunday",tagline:"Sunday morning market with live music, local coffee, and a relaxed Kailua vibe — the Windward side's best weekend ritual.",area:"Kailua",price:"Free",parking:"Free parking near Adventist Health Castle Hospital area. Come early for closest spots",hours:"Sundays 8am–12pm, rain or shine",bestTime:"Arrive at 8am for best selection of fresh produce and baked goods before they sell out",kidFriendly:true,talkStory:"Run by FarmLovers Markets at 640 Ulukahiki St, east of Castle Hospital. Live music sets the mood while you browse local produce, fresh flowers, jams, honey, and prepared foods. The open-air cafe area with locally grown coffee and pastries is where Kailua locals hang on Sunday mornings. Dog-friendly. Most vendors take cards but bring cash for faster transactions. Pairs well with a morning at Kailua Beach or brunch at Moke's down the road.",kamaaina:null},
  {name:"Kakaako Farmers Market",tier:"A",lat:21.2935,lng:-157.8563,category:"farmers-market",subcategory:"weekend-market",tagline:"Saturday morning market in Kakaako's Ward Village — strong food vendor lineup and a growing local following.",area:"Kakaako",price:"$",parking:"Ward Village parking (free on weekends)",hours:"Saturdays 8am-12pm at Ward Village",bestTime:"8:30-10am before it gets too hot and the best items sell out",kidFriendly:true,talkStory:"Kakaako's Saturday farmers market has grown into a legit alternative to KCC for town-side residents. Located at Ward Village with easy parking and a solid mix of produce vendors, prepared food stalls, and local artisans. The food vendor lineup rotates but consistently delivers. Less chaotic than KCC and more accessible for Kakaako and Ala Moana residents. The surrounding Ward Village shops open at 10am, so you can combine market shopping with a brunch walk.",kamaaina:null},
  {name:"KCC Farmers Market",tier:"S",lat:21.269,lng:-157.8,category:"farmers-market",subcategory:"weekend-market",tagline:"Hawaii's biggest and best farmers market — 80+ vendors, incredible prepared food stalls, and a Diamond Head backdrop.",area:"Kapahulu / Diamond Head",price:"$-$$",parking:"Free parking at KCC campus; fills up fast",hours:"Saturdays 7:30am-11am; Tuesdays 4-7pm (smaller)",bestTime:"Arrive at 7:30am Saturday opening; by 9:30am the best items sell out",kidFriendly:true,talkStory:"The biggest and best farmers market in Hawaii takes place every Saturday morning at Kapiolani Community College near Diamond Head. About 80 vendors sell everything from fresh-pressed sugarcane juice and macadamia nut ice cream to fried green tomatoes and local honey. The prepared food stalls are a destination unto themselves. Locals arrive right at 7:30am for the best selection. The Tuesday evening market is smaller but less crowded.",kamaaina:null},
  {name:"Pearlridge Farmers Market",tier:"B",lat:21.385,lng:-157.938,category:"farmers-market",subcategory:"weekend-market",tagline:"Saturday morning market in Aiea drawing local families — strong Filipino food stalls and the best prices on tropical fruit.",area:"Aiea / Pearl City",price:"$",parking:"Free parking at Pearlridge Center",hours:"Saturdays 8am-12pm",bestTime:"Arrive early for the best tropical fruit selection",kidFriendly:true,talkStory:"A Saturday morning market at Pearlridge Center that draws local families from Central and West Oahu. The selection of fresh tropical fruits, locally made pickles and preserves, and Filipino prepared foods is particularly strong. This market sees very few tourists and offers some of the best prices on the island for local produce. A great stop if you're in the Aiea/Pearl City area.",kamaaina:null},
  {name:"Waialua Farmers Market",tier:"B",lat:21.577,lng:-158.13,category:"farmers-market",subcategory:"weekend-market",tagline:"A small but excellent Saturday market inside the historic Waialua Sugar Mill — hyper-local produce and artisan goods.",area:"North Shore",price:"$",parking:"Free lot at the Sugar Mill",hours:"Saturdays 8:30am-12pm",bestTime:"Saturday mornings; combine with shopping at the Sugar Mill artisan shops",kidFriendly:true,talkStory:"Held Saturdays inside the historic Waialua Sugar Mill, this small but excellent market features hyper-local produce, homemade jams, fresh-baked goods, and coffee grown just up the road. The vendors are local farmers and artisans you can chat with about their products. Combined with the nearby shops in the Sugar Mill (including Waialua Coffee & Chocolate and Green Gypsy Thrift), it makes for a perfect North Shore morning.",kamaaina:null},
  {name:"Windward Mall Farmers Market",tier:"B",lat:21.417,lng:-157.811,category:"farmers-market",subcategory:"indoor-market",tagline:"Air-conditioned indoor market every Wednesday — exceptional prepared foods reflecting the true diversity of Windward Oahu.",area:"Windward",price:"$",parking:"Free mall parking",hours:"Wednesdays 2:30-7:30pm",bestTime:"Go hungry — the prepared food stalls (smoked fish, poke, mango sticky rice, ube pastry) are outstanding",kidFriendly:true,talkStory:"A completely air-conditioned indoor farmers market held every Wednesday inside Windward Mall. The selection of prepared foods — smoked fish, fresh poke, mango sticky rice, ube pastry, and taro chips — is exceptional. Locals on the Windward side treat this as their weekly grocery and dinner run. The mix of Asian, Pacific Island, and Hawaiian foods reflects the true diversity of the Kaneohe community.",kamaaina:null},
  {name:"Aiea Loop Trail",tier:"B",lat:21.3986,lng:-157.896,category:"hike",subcategory:"easy",tagline:"Lush forest loop above Pearl Harbor with WWII crash site remnants — underrated and uncrowded.",area:"Aiea",price:"Free",parking:"Free lot at Keaiwa Heiau State Park",hours:"Gates open 7am–7:45pm (Apr–Labor Day); 7am–6:45pm (Labor Day–Mar)",bestTime:"Early morning for cooler temps; avoid after heavy rain (very muddy)",kidFriendly:true,talkStory:"The WWII cargo plane wreckage midway through the loop is from a C-47 that crashed into the ridge in 1943 — rusted fuselage pieces are scattered in the gulch just off-trail if you know where to look. The trailhead sits inside Keaiwa Heiau State Park, an ancient Hawaiian healing temple where kahuna la'au lapa'au grew medicinal plants still found along the trail today. The CCC built much of the park infrastructure in the 1930s. Locals treat this 4.8-mile loop as a neighborhood gym — you'll see Pearl Harbor shimmering below through the canopy.",kamaaina:null},
  {name:"Aihualama Trail",tier:"B",lat:21.334,lng:-157.8047,category:"hike",subcategory:"moderate",tagline:"The trail that starts where Manoa Falls ends — climb up into the bamboo forest most people skip.",area:"Manoa",price:"Free",parking:"Use the Manoa Falls parking lot ($7 non-resident, free for residents) at 3739 Manoa Road",hours:"Open daily 8am-6pm",bestTime:"Morning when the bamboo forest is misty and magical",kidFriendly:false,talkStory:"This trail follows an ancient Hawaiian footpath that once connected Manoa to Nu'uanu Valley over the ridge — the name refers to a mo'o (lizard guardian spirit) of the upper valley streams. The bamboo groves were planted during early 1900s reforestation after sandalwood harvesting stripped the hillsides bare. Locals loop it with Pauoa Flats and Nu'uanu Trail for a 6-mile circuit through the Tantalus network, leaving the hundreds of tourists crowding Manoa Falls far below.",kamaaina:"Free parking with Hawaii state ID"},
  {name:"Crouching Lion Trail",tier:"B",lat:21.5577,lng:-157.8665,category:"hike",subcategory:"ridge",tagline:"Short but steep scramble to a dramatic rock formation with panoramic views of Kahana Bay and the Ko'olau range.",area:"Windward Coast (Ka'a'awa)",price:"Free",parking:"Small pullout on Kamehameha Hwy near mile marker 27. Limited to 5-6 cars",hours:"Daylight hours",bestTime:"Early morning for cooler temps and better light. Trail gets full sun with no shade",kidFriendly:false,talkStory:"In Hawaiian legend this rock is Kauhi, a demigod turned to stone by Hi'iaka (Pele's sister) during her epic journey across the islands — the 'crouching lion' name came later from Westerners who saw a different shape. The trail is unofficial and unmaintained with serious drop-offs near the summit, so treat it with respect. Locals approach from the old Crouching Lion Inn restaurant side, not directly from the highway. The 360-degree panorama of Kahana Bay and the Ko'olau knife-edge ridgeline rewards a short but intense scramble.",kamaaina:null},
  {name:"Diamond Head Summit",tier:"S",lat:21.2613,lng:-157.8047,category:"hike",subcategory:"sunrise",tagline:"Oahu's most iconic crater climb — tunnels, stairs, and 360-degree views that justify the hype.",area:"Waikiki",price:"$",parking:"$10/vehicle inside the crater; $5/person entry (reservations required)",hours:"Gate opens 6am; last entry 4pm",bestTime:"Sunrise — book the 6am slot weeks in advance; it sells out",kidFriendly:true,talkStory:"Hawaiians called it Le'ahi ('brow of the ahi fish') for its profile — British sailors in 1825 mistook calcite crystals for diamonds and the English name stuck. The US Army built Fort Ruger here in 1908, carving the tunnels and fire control station you climb through today as a coastal defense post to spot enemy ships. The spiral staircase and dark tunnel were part of the military observation network. Book reservations at gostateparks.hawaii.gov — the 6am sunrise slot sells out weeks ahead.",kamaaina:"Hawaii residents free entry with valid state ID; $5 parking (vs $10 non-resident)"},
  {name:"Ehukai Pillbox (Sunset)",tier:"A",lat:21.6634,lng:-158.0501,category:"hike",subcategory:"pillbox",tagline:"Watch pros surf Pipeline from a WWII bunker on the ridge — short, steep, and spectacular.",area:"North Shore",price:"Free",parking:"Street parking on Ke Nui Rd near Sunset Elementary",hours:"Sunrise to sunset (no gates)",bestTime:"Golden hour / sunset for best light; winter mornings to watch Pipeline surf from above",kidFriendly:false,talkStory:"These concrete bunkers were built in 1943 as part of Oahu's coastal defense network after Pearl Harbor — the Army placed pillboxes along every ridgeline with ocean sightlines to watch for Japanese invasion. During winter big-wave season, locals hike up with binoculars to watch the Pipe Masters from above, a perspective no beach spectator gets. The second pillbox at the summit gives you a bird's-eye view stretching from Ka'ena Point to Kahuku.",kamaaina:null},
  {name:"Hau'ula Loop Trail",tier:"B",lat:21.6067,lng:-157.9068,category:"hike",subcategory:"moderate",tagline:"A lush windward ridge loop that most tourists never find — all the Norfolk pines and ocean views without the crowds.",area:"Hau'ula",price:"Free",parking:"Free lot at Hau'ula Homestead Road trailhead — small lot, maybe 10 cars",hours:"Open sunrise to sunset daily",bestTime:"Morning for the clearest views — afternoon clouds move in fast on the windward side",kidFriendly:true,talkStory:"The Norfolk pines you walk through were planted in the 1930s by the Civilian Conservation Corps as part of a massive reforestation effort — before that, these hillsides were bare from cattle grazing. Hau'ula means 'red hau tree,' and you can still spot the native hau along the lower trail sections. Go counterclockwise to tackle the steep section first and finish with a gentle ridge walk offering views of sacred La'ie Point below. One of the few windward hikes that stays relatively dry thanks to the ridge position.",kamaaina:null},
  {name:"Hawaii Loa Ridge Trail",tier:"A",lat:21.3035,lng:-157.7365,category:"hike",subcategory:"ridge",tagline:"A steep Ko'olau ridge climb through native forest that delivers summit-caliber views in under 3 miles.",area:"Hawaii Kai",price:"Free",parking:"Free parking inside the Hawaii Loa Ridge subdivision gate — the guard may ask where you're going, just say the trailhead",hours:"Open sunrise to sunset daily; subdivision gate hours may vary",bestTime:"Early morning for clear summit views and cooler temps on the exposed upper ridge",kidFriendly:false,talkStory:"This ridge holds one of the last intact stands of native lowland forest on Oahu — botanists from UH have documented rare native species here found almost nowhere else on the island, including native lobelias and tree ferns. The trail passes through habitat actively managed to control invasive strawberry guava that threatens the native ecosystem. You must pass through the gated Hawaii Loa Ridge subdivision where the guard will ask your destination. The upper ridge narrows to a knife-edge with sheer drops into Waimanalo — 5.5 miles round trip with a brutal 2,200 ft gain.",kamaaina:null},
  {name:"Judd Trail (Jackass Ginger Pool)",tier:"C",lat:21.3394,lng:-157.8166,category:"hike",subcategory:"easy",tagline:"A quick shady loop through Nu'uanu Valley with a hidden swimming hole the locals call Jackass Ginger.",area:"Nu'uanu",price:"Free",parking:"Free roadside parking along Nu'uanu Pali Drive near the trailhead — limited spots",hours:"Open sunrise to sunset daily",bestTime:"Midday when you want a quick shady escape from the heat",kidFriendly:true,talkStory:"Named after Charles S. Judd, a territorial forester who planted these eucalyptus and Norfolk pines in the 1930s to reforest Nu'uanu after decades of logging. The 'Jackass Ginger' pool got its name from the wild yellow ginger growing along the stream and the donkeys that once roamed these hills. For generations local kids have used the muddy hillside above the pool as a natural mud slide — it's a rite of passage. Swim at your own risk though: leptospirosis is a real concern in all Oahu freshwater.",kamaaina:null},
  {name:"Ka'au Crater Trail",tier:"A",lat:21.311,lng:-157.782,category:"hike",subcategory:"advanced",tagline:"One of Oahu's most rewarding secret hikes — past three waterfalls to a volcanic crater rim with jaw-dropping panoramic views.",area:"Palolo Valley",price:"Free",parking:"Street parking on Waiomao Rd; respect residents",hours:"Daylight hours",bestTime:"Early morning on dry days; extremely dangerous when wet",kidFriendly:false,talkStory:"Ka'au is one of several small craters formed during the Ko'olau volcano's last eruptions roughly 30,000 years ago — the same rejuvenation-stage eruptions that created Diamond Head and Koko Crater. Ancient Hawaiians cultivated taro in the lower Palolo Valley, and you can still spot remnants of old lo'i terrace walls near the stream. The three waterfalls are increasingly dramatic, with the final one requiring rope-assisted climbing up a near-vertical face. Multiple rescues happen here yearly — bring gloves, allow 5-6 hours, and never attempt when wet.",kamaaina:null},
  {name:"Ka'ena Point Trail",tier:"S",lat:21.5728,lng:-158.2357,category:"hike",subcategory:"coastal",tagline:"Oahu's raw western tip — monk seals laze on rocks and albatross nest where the island ends.",area:"Waianae",price:"Free",parking:"Free lot at end of Farrington Hwy past Yokohama Bay",hours:"Sunrise to sunset daily (no gates on the Waianae side)",bestTime:"Early morning to beat the heat; Nov–Jun for albatross nesting season",kidFriendly:false,talkStory:"In Hawaiian mythology Ka'ena Point is a leina a ka 'uhane — a sacred 'leaping place of souls' where spirits of the dead depart the physical world into the afterlife realm of Po. The trail follows an abandoned railroad bed built in 1899 by Benjamin Dillingham's Oahu Railway & Land Co., which once connected Honolulu to the North Shore around this rugged coast. The fenced sanctuary protects nesting Laysan albatross (moli) and critically endangered Hawaiian monk seals. Bring 2+ liters of water — zero shade for 5 miles, and the currents here are deadly.",kamaaina:null},
  {name:"Kaipapa'u Gulch Trail",tier:"C",lat:21.595,lng:-157.912,category:"hike",subcategory:"moderate",tagline:"A quiet windward gulch hike through guava and kukui forest — you'll likely have the whole trail to yourself.",area:"Hau'ula",price:"Free",parking:"Free roadside parking along Hau'ula Homestead Road near the trailhead — very limited",hours:"Open sunrise to sunset daily",bestTime:"Morning for the best light filtering through the forest canopy",kidFriendly:false,talkStory:"The gulch was once part of a network of Hawaiian agricultural valleys — the kukui nut trees you see were planted by early Hawaiians who used the nuts for lamp oil, medicine, and dye. Kaipapa'u means 'shallow food garden,' hinting at the taro cultivation that once lined these stream banks. The trail parallels the old irrigation routes that fed lo'i kalo (taro paddies) below. You'll likely have the entire 4-mile trail to yourself — the solitude and forest atmosphere are the whole point.",kamaaina:null},
  {name:"Kamananui (Moanalua) Valley to Dam",tier:"C",lat:21.371,lng:-157.8652,category:"hike",subcategory:"easy",tagline:"A flat, shady valley walk perfect for families who want nature without the workout.",area:"Moanalua",price:"Free",parking:"Free parking at the Moanalua Valley Park trailhead off Moanalua Valley Road",hours:"Open sunrise to sunset daily",bestTime:"Any time of day — the valley stays cool and shaded",kidFriendly:true,talkStory:"Moanalua Valley was the beloved country estate of Prince Lot Kapuaiwa (King Kamehameha V), who hosted elaborate garden parties here in the 1860s. The massive monkeypod trees along the trail are remnants of his royal grounds, and the famous Hitachi Tree (featured in Japanese commercials for decades) stands near the park entrance. Ancient Hawaiians cultivated taro in this valley — you can spot remnants of old lo'i walls along the stream. The easy 3-mile walk to the dam is the gentle beginning of the epic trail to the Ko'olau summit.",kamaaina:null},
  {name:"Kawainui Marsh",tier:"C",lat:21.3922,lng:-157.7426,category:"hike",subcategory:"easy",tagline:"Hawaii's largest freshwater marsh — flat, stroller-friendly, and a birder's paradise.",area:"Kailua",price:"Free",parking:"Free lot at Kaha Park on Kailua Rd",hours:"Open daily, sunrise to sunset",bestTime:"Early morning for best birdwatching; cooler temps",kidFriendly:true,talkStory:"At 830 acres, Kawainui is Hawaii's largest remaining freshwater marsh and was once a fishpond system that fed thousands of ancient Hawaiians — it was among the most productive aquaculture sites in all of Polynesia. In the 1960s developers nearly filled it in for a housing subdivision, but community activists fought for decades to protect it. The marsh is now a critical habitat for endangered Hawaiian waterbirds including the ae'o (stilt), 'alae 'ula (moorhen), and 'alae ke'oke'o (coot). The paved path is fully accessible — combine with a Kailua Beach day.",kamaaina:null},
  {name:"Kealia Trail",tier:"A",lat:21.5253,lng:-158.1835,category:"hike",subcategory:"ridge",tagline:"The best-kept-secret ridge trail on the North Shore — wide open views from Dillingham to the Waianae Mountains.",area:"Mokuleia",price:"Free",parking:"Free dirt pulloff on Farrington Highway past Dillingham Airfield — look for the trail marker on the mauka side",hours:"Open sunrise to sunset daily",bestTime:"Early morning — zero shade on this trail so you'll bake by 10am",kidFriendly:false,talkStory:"The trail follows an old military access road built to service a radar installation on the Waianae Range summit during the Cold War — you can still see concrete pads at the top. The name Kealia means 'the salt-encrusted place,' referencing ancient Hawaiian salt pans near the coast below. As you climb, you'll look down on Dillingham Airfield where skydivers free-fall beneath you — a surreal perspective. It connects to Kuaokala Trail at the top, and the combined through-hike is one of Oahu's most ambitious day trips.",kamaaina:null},
  {name:"Koko Crater Railway",tier:"S",lat:21.2886,lng:-157.6975,category:"hike",subcategory:"challenging",tagline:"1,048 railway ties straight up a crater — the most brutal 1.6-mile workout on the island.",area:"Hawaii Kai",price:"Free",parking:"Free parking at Koko Head District Park",hours:"Open 24 hours (no gates; parking lot at Koko Head District Park always accessible)",bestTime:"Pre-dawn start (bring headlamp) — avoid midday heat at all costs",kidFriendly:false,talkStory:"The 1,048 railroad ties were laid during WWII as a tramway to haul supplies and personnel to a radar tracking station at the summit — the military needed eyes on the ocean approaches after Pearl Harbor. The ties were originally fitted with rails and a cable car system. The notorious bridge section near the top spans a gap where the original trestle crossed a ravine. Inside the crater at the summit sits a forgotten botanical garden planted in the 1950s with plumeria, cacti, and native dryland species. Locals do this as a pre-dawn workout — arrive with a headlamp.",kamaaina:null},
  {name:"Koloa Gulch",tier:"B",lat:21.5815,lng:-157.9205,category:"hike",subcategory:"waterfall",tagline:"A rugged stream-walking adventure to a hidden waterfall deep in the windward mountains.",area:"Hau'ula",price:"Free",parking:"Limited roadside parking on Kamehameha Highway near the trailhead — be respectful of residential areas",hours:"Open sunrise to sunset daily",bestTime:"Dry conditions are critical — never attempt after heavy rain due to flash flood risk",kidFriendly:false,talkStory:"This remote gulch was historically used by native Hawaiians for gathering medicinal plants and freshwater resources — the steep walls created a sheltered microclimate with unique plant species. You're literally walking IN the stream for most of the 5-mile trail, making at least 20 crossings over slippery boulders. The multi-tiered waterfall at the end drops into a narrow volcanic amphitheater that few people ever see. Flash floods have killed hikers here — always check weather radar before going, and never attempt after rain. The trailhead borders private land so verify access.",kamaaina:null},
  {name:"Kuaokala Ridge Trail",tier:"A",lat:21.5369,lng:-158.2293,category:"hike",subcategory:"ridge",tagline:"A remote Waianae ridge trail with views that rival anything on the island — and almost no one there.",area:"Waianae",price:"Free",parking:"Free parking at the Kuaokala Game Management Area access road off Farrington Highway — the gate is sometimes locked, check DLNR for access",hours:"Open sunrise to sunset; access gate may be locked weekdays — check Hawaii DLNR schedule",bestTime:"Weekend mornings when the access gate is reliably open",kidFriendly:false,talkStory:"This ridge trail runs through land jointly managed by the US Army and Hawaii DLNR — the military used Makua Valley below for live-fire training from WWII through 2004, and unexploded ordnance is still a concern off-trail. The views into Makua Valley are haunting, with the valley's cultural significance to Native Hawaiians (it's considered the birthplace of humanity in some traditions) adding weight to the scenery. The access gate may be locked on weekdays, so check DLNR's schedule or call ahead. It connects to Kealia Trail for an ambitious ridge-to-ridge through-hike.",kamaaina:null},
  {name:"Kuliouou Ridge Trail",tier:"A",lat:21.3132,lng:-157.7227,category:"hike",subcategory:"ridge",tagline:"The best beginner-friendly ridge hike on the island — panoramic Ko'olau views without the death-grip scrambles.",area:"Hawaii Kai",price:"Free",parking:"Free street parking on Kalaau Place in the Kuliouou residential area — arrive early on weekends or you'll be circling",hours:"Open sunrise to sunset daily",bestTime:"Early morning for cool temps and clear summit views before clouds roll in",kidFriendly:false,talkStory:"Kuliou'ou means 'sounding knee,' possibly referencing the sound of water flowing over rocks in the valley stream. The lower trail passes through a Cook pine and ironwood forest planted by the Civilian Conservation Corps in the 1930s — these trees replaced native forest lost to grazing and sandalwood trade. The Norfolk pine grove at the midpoint is a perfect rest stop before the final exposed push to the Ko'olau summit. On clear mornings you can see from Koko Head all the way to Kaneohe Bay — locals call this the best beginner ridge hike on the island.",kamaaina:null},
  {name:"La'ie Falls Trail",tier:"B",lat:21.6325,lng:-157.9275,category:"hike",subcategory:"waterfall",tagline:"A muddy, jungly adventure to a secluded North Shore waterfall most visitors never hear about.",area:"La'ie",price:"Free",parking:"Limited parking near the trailhead off Poohaili Street in La'ie — respect the residential neighborhood",hours:"Open sunrise to sunset daily",bestTime:"After light rain for waterfall flow, but not during or right after heavy rain",kidFriendly:false,talkStory:"The trail follows an old irrigation ditch route built by plantation workers to channel water from the Ko'olau streams down to sugar cane fields in La'ie. La'ie is deeply significant as a center of Hawaiian cultural heritage and later became the site of the Polynesian Cultural Center and BYU-Hawaii. The falls at the end drop about 25 feet into a jungle pool that few tourists ever reach. Access has been restricted at times due to the trailhead crossing near private land — always verify current status before heading out. Perpetually muddy, bring shoes you can sacrifice.",kamaaina:null},
  {name:"Lanikai Pillbox",tier:"S",lat:21.3901,lng:-157.719,category:"hike",subcategory:"pillbox",tagline:"Two WWII bunkers over the Mokulua Islands — the most photogenic sunrise hike on the windward side.",area:"Kailua",price:"Free",parking:"Street parking on Kaelepulu Dr — arrive before sunrise to find a spot",hours:"Sunrise to sunset (no gates; unofficial trail on public land)",bestTime:"Sunrise — start 30 min before for the climb; the light over the Mokes is unbeatable",kidFriendly:false,talkStory:"Officially called the Ka'iwa Ridge Trail, these two concrete bunkers were built after Pearl Harbor as part of Oahu's coastal defense against Japanese invasion — soldiers would have watched for enemy ships from these exact vantage points. The name Lanikai means 'heavenly sea,' coined in the 1920s when the area was subdivided for beach homes. The Mokulua Islands (Na Mokulua) offshore are state seabird sanctuaries — the larger one allows visitors to land on the back side. Start 30 minutes before sunrise for the famous golden light that makes this Oahu's most photographed hike.",kamaaina:null},
  {name:"Likeke Falls",tier:"B",lat:21.3563,lng:-157.801,category:"hike",subcategory:"waterfall",tagline:"A short jungle scramble to a waterfall that feels way more remote than it actually is.",area:"Ko'olau",price:"Free",parking:"The Ko'olau Golf Club is permanently closed. Street parking outside the former golf club gate on Kionaole Rd; park completely off the road to avoid tickets. Trail access via the old maintenance road.",hours:"Open sunrise to sunset daily",bestTime:"After rain for the best water flow — morning for fewer people",kidFriendly:false,talkStory:"The trail passes through land that was once part of the vast Ko'olau watershed system that ancient Hawaiians managed through a network of irrigation channels feeding taro lo'i in the valleys below. The name Likeke is the Hawaiian form of 'Richard,' likely honoring a 19th-century figure. The 15-ft waterfall drops into a mossy grotto that feels impossibly remote despite being minutes from the Pali Highway. You can connect this to Old Pali Road for a loop that takes you past the site of the 1795 Battle of Nu'uanu, where Kamehameha I drove O'ahu's warriors over the cliffs.",kamaaina:null},
  {name:"Lulumahu Falls",tier:"A",lat:21.3444,lng:-157.828,category:"hike",subcategory:"waterfall",tagline:"A hidden 50-foot waterfall in the Nu'uanu Valley rainforest — muddy, jungle-choked, and worth every slippery step.",area:"Nu'uanu",price:"Free (BWS watershed permit required)",parking:"Small pulloff on Pali Hwy near the Old Pali Road trailhead",hours:"Daylight hours only",bestTime:"After rain for maximum flow; go early on weekdays to avoid crowds",kidFriendly:false,talkStory:"This 50-foot waterfall sits on the grounds of the former Nu'uanu reservoir system, and the trail crosses remnants of the old aqueduct infrastructure built in the early 1900s to supply Honolulu's water. The valley was sacred to ancient Hawaiians — lulu means 'calm/sheltered' and mahu means 'steam/mist,' describing the perpetual fog that blankets these falls. The trail weaves through dense bamboo groves and past massive banyan trees with aerial roots forming cathedral-like archways. Technically DLNR land requiring a permit — check current access rules before going.",kamaaina:null},
  {name:"Ma'ili Pillbox (Pink Pillbox)",tier:"B",lat:21.4175,lng:-158.1715,category:"hike",subcategory:"pillbox",tagline:"The West Side's colorful pillbox hike with sunset views that absolutely crush the East Side versions.",area:"Waianae",price:"Free",parking:"Free parking at the base trailhead on Ma'ili Point — small gravel lot",hours:"Open sunrise to sunset daily",bestTime:"Late afternoon for the best sunset — West Side faces the ocean sunset directly",kidFriendly:false,talkStory:"These WWII-era bunkers were part of the Waianae coast defense network, built after Pearl Harbor when the military fortified every ridge with ocean sightlines against potential Japanese landing forces. Local artists have transformed the pillboxes into colorful murals that change regularly — the 'Pink Pillbox' nickname comes from the ever-evolving graffiti art. The leeward coast location means this hike is almost always dry and sunny when windward trails are soaked. The sun drops directly into the Pacific from here — locals say it's the best unobstructed sunset viewpoint on the island.",kamaaina:null},
  {name:"Makapu'u Lighthouse Trail",tier:"S",lat:21.3097,lng:-157.6512,category:"hike",subcategory:"coastal",tagline:"Fully paved and stroller-friendly with whale sightings Nov–May and dramatic ocean cliffs.",area:"Makapu'u",price:"Free",parking:"Free lot off Kalanianaole Hwy (fills by 9am weekends)",hours:"Sunrise to sunset daily (parking lot gate opens at sunrise)",bestTime:"Jan–Mar for peak whale watching; early morning to avoid heat and crowds",kidFriendly:true,talkStory:"The lighthouse at the summit has been guiding ships since 1909 and houses one of the largest lighthouse lenses in the country — a hyper-radiant Fresnel lens over 8 feet tall, shipped from Paris. The trail was originally built as an access road for lighthouse keepers who lived at the point. During whale season (Jan-Mar), this is the single best land-based whale watching spot in Hawaii — humpbacks breach so close you can hear the splash. The tidepools below the lookout harbor rare species, but only scramble down when surf is calm. Fully paved and stroller-accessible.",kamaaina:null},
  {name:"Makiki Valley Loop",tier:"B",lat:21.326,lng:-157.8247,category:"hike",subcategory:"moderate",tagline:"Three trails stitched into one perfect loop through the lush valley behind Honolulu — the local's Manoa alternative.",area:"Makiki",price:"Free",parking:"Free parking at the Hawaii Nature Center on Makiki Heights Drive — lot fills by 9am on weekends",hours:"Open sunrise to sunset daily",bestTime:"Early morning for birdsong and cool temps — the canopy keeps it shady all day though",kidFriendly:true,talkStory:"The forest you walk through was planted by the Civilian Conservation Corps in the 1930s as a massive reforestation project — before that, these hillsides were nearly bare from decades of cattle ranching and sandalwood harvesting. The CCC crews, many of them young local men during the Depression, planted thousands of Cook pines, eucalyptus, and tropical hardwoods that now form the lush canopy overhead. The Hawaii Nature Center at the trailhead was originally the CCC's base camp. Way fewer people than Manoa Falls with the same jungle atmosphere — the 3-mile Maunalaha-Makiki Valley-Ualaka'a loop is a local favorite.",kamaaina:null},
  {name:"Manoa Falls",tier:"S",lat:21.3317,lng:-157.8003,category:"hike",subcategory:"waterfall",tagline:"A 150-ft jungle waterfall 15 minutes from Waikiki — Jurassic Park vibes are not an accident.",area:"Manoa",price:"$",parking:"$7 parking at 3739 Manoa Rd (the only lot)",hours:"Open daily 8am–6pm (last entry by 4:30pm); closed during flash flood warnings",bestTime:"Early morning for fewer crowds; after light rain for a fuller waterfall (but trail gets muddier)",kidFriendly:true,talkStory:"Manoa Valley receives over 150 inches of rain annually, making it one of the wettest inhabited places in the US — that's why the 150-ft falls almost never dry up. Parts of Jurassic Park, Lost, and dozens of other productions filmed in this valley, and the ancient Hawaiians considered it home to Kahalaopuna, a beautiful maiden born of the wind and rain of Manoa. The trail follows a route once used by Hawaiian farmers tending taro and banana plots in the upper valley. Do NOT swim at the base — rockfall and leptospirosis are genuine risks.",kamaaina:"Hawaii residents park free with valid state ID"},
  {name:"Maunawili Demonstration Trail",tier:"A",lat:21.3534,lng:-157.7698,category:"hike",subcategory:"moderate",tagline:"A 10-mile one-way traverse through windward paradise — the best single-track on Oahu if you can arrange a car shuttle.",area:"Maunawili",price:"Free",parking:"Free parking at the Pali Highway trailhead (Nu'uanu side) or the Waimanalo trailhead on Kumuhau Street",hours:"Open sunrise to sunset daily",bestTime:"Start in the morning going Pali-to-Waimanalo to keep the sun at your back",kidFriendly:false,talkStory:"This 10-mile single-track was designed and built in the early 1990s as a 'demonstration trail' — a model for sustainable trail construction in Hawaii using local labor and materials. The route contours along the Ko'olau foothills through land once covered in sugar cane and pineapple plantations, passing remnants of old irrigation infrastructure. Mountain bikers share the trail so stay alert on blind corners — the bikers call it the best single-track on Oahu. Best done as a shuttle hike going Pali-to-Waimanalo to keep the sun at your back.",kamaaina:null},
  {name:"Maunawili Falls",tier:"A",lat:21.3535,lng:-157.77,category:"hike",subcategory:"waterfall",tagline:"A 20-ft jungle cascade with a swimming hole and cliff-jump rock — best legal swim-at-falls on the windward side.",area:"Kailua",price:"Free",parking:"Very limited street parking at end of Kelewina St — arrive before 8am",hours:"Sunrise to sunset (no gates)",bestTime:"Early morning before 8am to get parking and beat crowds",kidFriendly:false,talkStory:"The swimming hole at these falls is one of the few on Oahu where swimming is relatively tolerated — locals have been jumping off the rock ledge here for decades, though leptospirosis risk exists in all Hawaii freshwater. The trail passes through land that was once part of the Maunawili sugar plantation, and you can spot remnants of old irrigation channels along the stream. In 2018 severe flooding damaged sections of the trail, prompting significant repair work. Arrive before 8am for parking on tiny Kelewina Street — it's a neighborhood, so be respectful.",kamaaina:null},
  {name:"Moanalua Valley Trail",tier:"A",lat:21.3638,lng:-157.8727,category:"hike",subcategory:"moderate",tagline:"A wild 10-mile valley-to-summit trek through stream crossings and native forest to the Ko'olau ridge.",area:"Moanalua",price:"Free",parking:"Free parking at the end of Moanalua Valley Road — the neighborhood gate is open during daylight hours",hours:"Open sunrise to sunset daily",bestTime:"Start early — this is a long day hike and you want to summit before afternoon clouds",kidFriendly:false,talkStory:"This valley was the cherished estate of King Kamehameha V (Prince Lot), and the trail passes stone ruins of his summer retreat deeper in the valley. The famous Douglas fir at the park entrance was a gift from the Pacific Northwest in the 1800s. Ancient Hawaiians cultivated extensive taro systems here — you'll spot old rock-walled lo'i terraces along the stream during the 12+ stream crossings. The Ko'olau summit at the end was once part of a trail network connecting leeward and windward Oahu. Full-day commitment: 10 miles, 2,600 ft gain, start by 7am.",kamaaina:null},
  {name:"Old Pali Road",tier:"B",lat:21.3571,lng:-157.8044,category:"hike",subcategory:"easy",tagline:"A paved historic road reclaimed by the jungle — the easiest walk to dramatic Ko'olau cliff views.",area:"Nu'uanu",price:"Free",parking:"Park at the Pali Lookout parking lot ($7 non-resident, free for Hawaii IDs; reservations may be required for non-residents via gostateparks.hawaii.gov)",hours:"Open sunrise to sunset daily",bestTime:"Late afternoon when the light hits the cliffs — but expect wind at the lookout any time of day",kidFriendly:true,talkStory:"This crumbling roadway was the main route over the Ko'olau Range before the modern Pali Highway tunnels opened in 1961 — and before that, it was the site of the 1795 Battle of Nu'uanu where Kamehameha I's warriors drove hundreds of O'ahu defenders over the 1,000-foot cliffs to their deaths. Human bones have been found at the base of the pali. The old road was itself built over an ancient Hawaiian footpath. Night hikers report it as one of Oahu's most haunted spots, and many locals won't carry pork over the Pali out of respect for the night marchers.",kamaaina:"Free parking with Hawaii state ID"},
  {name:"Olomana Three Peaks",tier:"A",lat:21.3545,lng:-157.7702,category:"hike",subcategory:"challenging",tagline:"Oahu's most thrilling ridge scramble — first peak is earned, second is gutsy, third is borderline reckless.",area:"Maunawili",price:"Free",parking:"Free parking at the loop on Royal Hawaiian Golf Club access road off Auloa Road in Kailua",hours:"Open sunrise to sunset daily",bestTime:"Start at sunrise to beat the heat — the exposed ridgeline gets brutally hot by midday",kidFriendly:false,talkStory:"Named after a legendary giant warrior who ruled windward Oahu until he was defeated and cut in half by the chief Palila — the three peaks represent his body split apart. The first peak (Olomana, 1,643 ft) is challenging but achievable; the second (Paku'i) and third (Ahiki) involve knife-edge ridges where multiple hikers have died over the years from falls. In 2018 alone, several fatalities prompted calls to restrict access. Locals say never go when it's wet, always bring gloves for the rope sections, and turning back at peak one is the smart move — the views are already world-class.",kamaaina:null},
  {name:"Pauoa Flats Trail",tier:"B",lat:21.346,lng:-157.813,category:"hike",subcategory:"moderate",tagline:"A misty forest trail to a rare flat overlook above Nu'uanu Valley — the trailhead most people walk right past.",area:"Tantalus",price:"Free",parking:"Free roadside parking along Tantalus Drive (Round Top Drive) near the trailhead",hours:"Open sunrise to sunset daily",bestTime:"Early morning when the mist hangs in the valley — bring a rain layer",kidFriendly:true,talkStory:"Pauoa Flats is one of the only level clearings in the Ko'olau Range — ancient Hawaiians used it as a resting point on the footpath connecting Honolulu to the windward side via Nu'uanu Valley. The native 'ohi'a lehua and koa forest in the upper section is some of the most accessible old-growth Hawaiian forest near any city in the state. In Hawaiian mythology, the lehua blossom is the embodiment of a lover separated from the tree by Pele — picking the flowers is said to bring rain. The trail connects to the Tantalus network for loops through Aihualama and Nu'uanu trails.",kamaaina:null},
  {name:"Pu'u Ma'eli'eli Trail",tier:"B",lat:21.3922,lng:-157.7514,category:"hike",subcategory:"pillbox",tagline:"Kailua's lesser-known pillbox hike with the same views and a fraction of the crowds.",area:"Kailua",price:"Free",parking:"Free street parking on Kapa'a Quarry Road near the trailhead",hours:"Open sunrise to sunset daily",bestTime:"Sunrise for golden light over Kailua Bay and the Mokulua Islands",kidFriendly:true,talkStory:"These three WWII bunkers were part of the windward coastal defense system built after Pearl Harbor, positioned to watch for enemy ships approaching Kailua and Kaneohe Bays. Pu'u Ma'eli'eli means 'the hill of caution' in Hawaiian, which is fitting for the steep sections. The trail follows the same ridge as Lanikai Pillbox but from the Kailua side, offering equally stunning views of the Mokulua Islands with a fraction of the Instagram crowds. Locals use this as a quick after-work sunset hike — 2.5 miles round trip with three bunkers and a bonus loop option along the ridge.",kamaaina:null},
  {name:"Pu'u Ualaka'a (Tantalus Sunset)",tier:"A",lat:21.3134,lng:-157.8228,category:"hike",subcategory:"sunset",tagline:"The best free sunset view over Honolulu — Waikiki, Diamond Head, and Pearl Harbor all at once.",area:"Tantalus",price:"Free",parking:"Free lot (about 45 spaces)",hours:"Open 7am–6:45pm (Apr–Labor Day until 7:45pm)",bestTime:"Sunset — arrive 30 min before for parking and a good spot",kidFriendly:true,talkStory:"Pu'u Ualaka'a means 'rolling sweet potato hill' — legend says farmers' sweet potatoes would roll down the steep slopes during harvest. The lookout sits at 1,048 feet on the remains of an ancient volcanic vent in the Tantalus crater complex. Round Top Drive, the winding road up, passes through a forest planted by the CCC in the 1930s that now feels like a tropical rainforest. Locals know this as the best free panoramic viewpoint on Oahu — Waikiki, Diamond Head, Pearl Harbor, and the Waianae Range all visible at once, especially stunning at sunset.",kamaaina:null},
  {name:"Pupukea-Paumalu Trail (Ted Makalena)",tier:"C",lat:21.6536,lng:-158.061,category:"hike",subcategory:"easy",tagline:"A mellow North Shore forest walk through ironwoods and native plants — a breather between surf sessions.",area:"Pupukea",price:"Free",parking:"Free parking at the trailhead on Pupukea Road across from the Boy Scout Camp",hours:"Open sunrise to sunset daily",bestTime:"Any time — it's shaded and low-key",kidFriendly:true,talkStory:"Named after Ted Makalena, a beloved Hawaiian pro golfer who died young in 1976, this trail system was developed by the North Shore community to preserve 1,100 acres of forest from development. The land contains remnants of ancient Hawaiian agricultural terraces and stone walls from pre-contact cultivation. The ironwood and Cook pine canopy creates a shaded, cathedral-like atmosphere that locals call the North Shore's best 'forest bathing' spot. Perfect for a mellow walk or trail run between surf sessions — don't expect summit views, this is about the trees.",kamaaina:null},
  {name:"Wa'ahila Ridge Trail",tier:"B",lat:21.314,lng:-157.7975,category:"hike",subcategory:"ridge",tagline:"A proper ridge hike that starts right behind the University of Hawaii — lunch break adventure material.",area:"St. Louis Heights",price:"Free",parking:"Free parking at Wa'ahila Ridge State Recreation Area off Ruth Place — small lot, comes with restrooms and picnic tables",hours:"Open 7am to 7:45pm (Apr-Sep) or 7am to 6:45pm (Oct-Mar)",bestTime:"Late afternoon for golden hour light on the ridge — but start early enough to finish before gate closes",kidFriendly:false,talkStory:"The ironwood and Cook pine forest at the trailhead was planted by the Civilian Conservation Corps in the 1930s, transforming bare hillsides into the lush canopy you walk through today. The ridge separates Manoa and Palolo valleys, which ancient Hawaiians cultivated extensively for taro — you're walking the spine between two of Oahu's most productive agricultural valleys. UH students have been using this as a study-break escape for decades since the trailhead is minutes from campus. The narrow upper ridge with drop-offs on both sides delivers views from Diamond Head to the Ko'olau summit.",kamaaina:null},
  {name:"Waimano Ridge Trail",tier:"B",lat:21.4207,lng:-157.9147,category:"hike",subcategory:"ridge",tagline:"A long, rewarding ridge hike through native forest to the Ko'olau summit — for hikers who want to earn their views.",area:"Pearl City",price:"Free",parking:"Free parking at the trailhead at the top of Waimano Home Road in Pacific Palisades",hours:"Open sunrise to sunset daily",bestTime:"Very early morning start — you need a full day for the summit push",kidFriendly:false,talkStory:"The trailhead sits above the former Waimano Home, a state institution for people with disabilities that operated from 1919 to 1999 — the name Waimano means 'many waters' for the streams cutting through these ridges. Most locals do the first 3 miles to Waimano Pool, a freshwater swimming hole in the stream valley, as a moderate out-and-back. Beyond the pool the trail gets serious — 14 miles round trip through native 'ohi'a forest to the Ko'olau summit. The upper ridge passes through one of the most pristine native ecosystems accessible by trail on Oahu. Bring a headlamp as backup.",kamaaina:null},
  {name:"Waimea Valley Falls",tier:"A",lat:21.6398,lng:-158.06,category:"hike",subcategory:"waterfall",tagline:"The only place on Oahu where you can legally swim beneath a waterfall — botanical garden walk to boot.",area:"North Shore",price:"$$",parking:"Free lot at 59-864 Kamehameha Hwy",hours:"Daily 9am–4pm (last entry 3:30pm)",bestTime:"Weekday mornings for fewest crowds; after rain for a fuller waterfall",kidFriendly:true,talkStory:"Waimea Valley was a major population center for ancient Hawaiians — over 78 archaeological sites have been documented here including house platforms, agricultural terraces, and heiau (temples). The valley was the home of the kahuna nui (high priests) of O'ahu, making it one of the most spiritually significant valleys on the island. The 45-foot Waihi Falls at the end is the only waterfall on Oahu where swimming is officially permitted with provided life vests. The botanical garden along the path preserves over 5,000 tropical plant species and is managed by Hi'ipaka LLC, a Native Hawaiian nonprofit.",kamaaina:"Kamaaina rate ~$16/adult with valid Hawaii ID (vs $26 regular)"},
  {name:"Wiliwilinui Ridge",tier:"A",lat:21.299,lng:-157.7628,category:"hike",subcategory:"moderate",tagline:"The Ko'olau's best-kept ridge secret — pass through a gated community into native forest with panoramic views.",area:"East Honolulu",price:"Free",parking:"Limited spots — check in with security at the Waialae Iki gate on Okoa St",hours:"Daylight hours only; security gate staffed roughly 7am–6pm",bestTime:"Early morning for clear summit views (clouds roll in by midday)",kidFriendly:false,talkStory:"Named after the wiliwili tree (Erythrina sandwicensis), a native Hawaiian dryland tree that once grew abundantly on these lower slopes before development pushed it to near-extinction in the wild. The trail was historically used by Hawaiian bird catchers who harvested feathers from forest birds for royal featherwork capes and helmets — the upper ridge still harbors native birds including the 'apapane and 'amakihi. You must check in with security at the Waialae Iki gate on Okoa Street. The Ko'olau summit rewards with panoramic views of both coasts — 4.5 miles round trip, 1,500 ft gain.",kamaaina:null},
  {name:"Ala Moana Beach Park Playground",tier:"A",lat:21.2889,lng:-157.8476,category:"kids",subcategory:"playground",tagline:"Huge playground right next to the calmest beach in Honolulu — the ultimate combo for families.",area:"Ala Moana",price:"Free",parking:"Free parking lot in the park (fills fast on weekends — arrive before 10am)",hours:"Park open 4am–10pm daily; playground always accessible during park hours",bestTime:"Weekday mornings for parking and shade; late afternoon for cooler play",kidFriendly:true,talkStory:"Built on a reclaimed coral reef flat in the 1930s as a WPA project, this 100-acre park was engineered with a protective outer reef that creates one of Hawaii's safest swimming areas -- the water stays ankle-to-knee deep for nearly 100 yards out, which is why local families call it 'the baby beach.' The playground was renovated with ADA-accessible structures and shade sails. Insider move: park at the less-known west end near the channel for easy spots even on weekends.",kamaaina:null},
  {name:"Bishop Museum",tier:"S",lat:21.3326,lng:-157.87,category:"kids",subcategory:"museum",tagline:"Hawaii's biggest museum with a world-class planetarium and a hands-on science center that rivals the mainland.",area:"Kalihi",price:"$$",parking:"Free parking on-site in museum lot",hours:"Wed–Mon 9am–5pm. Closed Tuesdays",bestTime:"Arrive at opening on a weekday; planetarium shows sell out so grab tickets first",kidFriendly:true,talkStory:"Founded in 1889 by Charles Reed Bishop in honor of his wife Princess Bernice Pauahi Bishop, this is the largest museum in Polynesia and houses over 24 million artifacts including the world's foremost collection of Hawaiian and Pacific Island natural history. The Science Adventure Center's erupting volcano model was designed by the same firm behind Smithsonian exhibits. Most visitors miss the native Hawaiian garden behind the main hall and the original koa-wood Hawaiian Hall ceilings.",kamaaina:"Kamaaina rate with Hawaii ID; membership pays for itself in 2-3 visits"},
  {name:"Coral Crater Adventure Park",tier:"B",lat:21.3198,lng:-158.074,category:"kids",subcategory:"adventure",tagline:"Ziplines, an aerial adventure course, and ATV rides inside a volcanic crater — an adrenaline rush for older keiki.",area:"Kapolei",price:"$$$",parking:"Free parking on-site",hours:"Daily 8am–4pm; book activities online in advance",bestTime:"Morning for cooler temps; weekdays for shorter waits on courses",kidFriendly:true,talkStory:"Set inside a real 200-foot-deep volcanic crater formed about 100,000 years ago, this adventure park sits on former military land once used for target practice. The crater's natural bowl shape creates a dramatic amphitheater for the zipline course, which spans over 2,000 feet. The aerial ropes course has 60+ elements across multiple difficulty levels. Insider tip: the freefall jump is the newest addition most visitors skip -- a controlled 40-foot drop that thrills older keiki.",kamaaina:"Kamaaina rates with Hawaii ID — check website for current local pricing"},
  {name:"Gunstock Ranch",tier:"B",lat:21.5802,lng:-157.895,category:"kids",subcategory:"adventure",tagline:"Horseback rides through the Koolau foothills with mountain and ocean views — pony rides for the little ones.",area:"Laie",price:"$$",parking:"Free parking on-site at the ranch",hours:"Mon–Sat 9am–4pm. Closed Sundays. Rides by reservation only",bestTime:"Morning rides for cooler weather and better mountain views before clouds build",kidFriendly:true,talkStory:"This 750-acre working cattle ranch has been in operation since the 1960s, nestled against the Koolau Mountains in Laie. Originally part of the old sugar plantation lands, the ranch still runs cattle alongside its trail ride operation. Their horses are Hawaiian-bred and famously calm, trained using natural horsemanship methods. The sunset ride, which most families overlook, follows a ridgeline trail with panoramic views from Laie Point to Kahuku and is only offered seasonally.",kamaaina:"Kamaaina rates available — mention when booking"},
  {name:"Hawaii Children's Discovery Center",tier:"B",lat:21.2936,lng:-157.8619,category:"kids",subcategory:"indoor-play",tagline:"Three-story interactive museum in Kakaako — hands-on exhibits that make learning feel like play.",area:"Kakaako",price:"$",parking:"Free lot on-site",hours:"Tue–Fri 9am–1pm, Sat–Sun 10am–3pm. Closed Mon",bestTime:"Weekday mornings for smallest crowds; great rainy-day option",kidFriendly:true,talkStory:"Opened in 1998 as Oahu's only dedicated children's museum, this 38,000-square-foot center was championed by local educators who traveled to mainland children's museums for inspiration. The 'Your Town' exhibit on the first floor -- complete with a working mini grocery checkout, fire truck, and doctor's office -- was designed with input from Honolulu keiki. Most families miss the third-floor Hawaiian Rainforest exhibit and the rotating cultural gallery.",kamaaina:"Kamaaina rate available with Hawaii ID; check website for current pricing"},
  {name:"Hawaii Plantation Village",tier:"C",lat:21.3925,lng:-158.0136,category:"kids",subcategory:"museum",tagline:"Walk through restored plantation-era homes and learn how Hawaii's multicultural identity was built.",area:"Waipahu",price:"$",parking:"Free parking on-site",hours:"Mon–Sat 10am–2pm. Closed Sundays. Guided tours at 10am, 11am, 12pm, 1pm",bestTime:"First tour at 10am is least crowded and cooler",kidFriendly:true,talkStory:"Founded in 1992 on the grounds of the former Oahu Sugar Company, this open-air museum preserves over 30 restored buildings representing eight ethnic groups who labored on Hawaii's sugar plantations from the 1850s to the 1940s. The volunteer docents are often descendants of plantation workers sharing personal family stories. Don't miss the restored Shinto shrine and Portuguese bread oven, both original to the era.",kamaaina:"Kamaaina rate with Hawaii ID"},
  {name:"Honolulu Zoo Keiki Zoo",tier:"A",lat:21.2711,lng:-157.8214,category:"kids",subcategory:"farm",tagline:"Walk right into the goat pen — mini goats, baby sheep, pigs, ponies, and alpaca.",area:"Waikiki",price:"$",parking:"Street parking on Kapahulu Ave or metered lots nearby",hours:"Daily 9am–4:30pm (zoo gates close at 4pm)",bestTime:"Weekday mornings — animals are most active and crowds are thin",kidFriendly:true,talkStory:"The Honolulu Zoo dates to 1914, making it one of the oldest zoos west of the Mississippi. The Keiki Zoo section lets children walk right into enclosures with Nigerian dwarf goats, Barbados blackbelly sheep, and kunekune pigs. It is the only zoo in the U.S. established by a reigning monarch -- Queen Kapiolani donated the original land in Waikiki. Insider tip: the Twilight Tours on select Friday and Saturday evenings offer behind-the-scenes keeper access that daytime visitors never see.",kamaaina:"Kamaaina: $8/adult, $4/child (vs $19/$11 non-resident) with valid Hawaii ID"},
  {name:"Hoomaluhia Botanical Garden",tier:"A",lat:21.389,lng:-157.8023,category:"kids",subcategory:"nature",tagline:"400 acres of lush gardens backed by the Koolau cliffs — free admission and the most photogenic spot on Oahu.",area:"Kaneohe",price:"Free",parking:"Free parking at visitor center and multiple lots throughout the garden",hours:"Daily 9am–4pm. Closed Christmas & New Year's Day",bestTime:"Early morning for misty mountain views and cooler temps; weekdays to avoid weekend crowds",kidFriendly:true,talkStory:"Built by the U.S. Army Corps of Engineers in 1982 as a flood-control project, this 400-acre garden doubles as a giant retention basin protecting Kaneohe from Koolau runoff -- most visitors have no idea they are walking through an engineering marvel. The 32-acre lake offers free catch-and-release fishing with loaner poles on weekends. The Philippines and Sri Lanka botanical sections are the least visited but most lush.",kamaaina:null},
  {name:"Kahuku Farms",tier:"B",lat:21.6811,lng:-157.9503,category:"kids",subcategory:"farm",tagline:"A real working farm on the North Shore with tractor tours, fruit tastings, and the best acai bowl on the island.",area:"North Shore",price:"$",parking:"Free parking on-site along the farm road",hours:"Wed–Mon 10am–4pm. Closed Tuesdays",bestTime:"Late morning for farm tours; the cafe gets a long line at lunch so go early or late",kidFriendly:true,talkStory:"The Matsuda family has farmed this North Shore land for generations, growing banana, papaya, lilikoi, cacao, and seasonal fruits across 10 acres. The tractor-pulled farm tour lets kids taste fruit right off the trees -- apple bananas and white pineapple are standouts. Their cafe's grilled banana bread with haupia ice cream is island-famous. The farm also grows cacao used in some of Oahu's small-batch chocolate.",kamaaina:null},
  {name:"Kakaako Waterfront Park",tier:"B",lat:21.2912,lng:-157.8633,category:"kids",subcategory:"playground",tagline:"Grassy slopes for rolling, ocean views, and open space for running — a simple, free park locals love.",area:"Kakaako",price:"Free",parking:"Free parking lot on-site",hours:"Daily 7am–7:45pm (gates lock at closing)",bestTime:"Late afternoon for ocean breezes and sunset views; weekday mornings for fewer people",kidFriendly:true,talkStory:"This 35-acre waterfront park was built in the 1990s atop a former municipal landfill, transformed into one of Honolulu's best green spaces. The signature grassy hill where keiki roll endlessly was engineered as a cap over the old fill. The promenade offers unobstructed views of Diamond Head, surf breaks, and passing ships. Locals know it as one of the best kite-flying spots on Oahu when the trades blow.",kamaaina:null},
  {name:"Kaneohe Sandbar (Ahu o Laka)",tier:"A",lat:21.4622,lng:-157.806,category:"kids",subcategory:"nature",tagline:"A sandbar in the middle of Kaneohe Bay where you stand in knee-deep turquoise water with the Koolaus as backdrop.",area:"Kaneohe",price:"$$",parking:"Park at Heeia Kea Boat Harbor; various tour operators depart from here",hours:"Tour operators run morning and afternoon trips; sandbar accessible during low tide",bestTime:"Low tide for maximum sandbar exposure; morning trips for calmer water and better light",kidFriendly:true,talkStory:"Known to Hawaiians as Ahu o Laka, this sandbar is considered sacred -- traditionally an offering site for hula practitioners honoring Laka, goddess of hula and forest plants. At low tide, the bar rises to create a shallow turquoise lagoon perfect for toddlers. Insider tip: rent a kayak from Heeia Kea Harbor instead of booking a tour boat -- it is a short paddle, far cheaper, and you get the sandbar to yourself early morning.",kamaaina:"Some tour operators offer kamaaina rates — ask when booking"},
  {name:"Kapiolani Park Playground",tier:"A",lat:21.2692,lng:-157.8152,category:"kids",subcategory:"playground",tagline:"Huge banyan-shaded playground steps from Waikiki — the go-to for hotel families who need a playground break.",area:"Waikiki",price:"Free",parking:"Free parking along Monsarrat Ave and park side streets; metered spots on Kalakaua",hours:"Open 24 hours (playground best during daylight)",bestTime:"Mornings or late afternoon for shade and cooler temps; weekdays for less crowds",kidFriendly:true,talkStory:"Kapiolani Park, established in 1877 by King Kalakaua and named for his queen, is the oldest public park in Hawaii. The playground sits beneath massive banyan trees planted in the early 1900s that provide natural shade canopy -- a rarity for Hawaiian playgrounds. The Saturday KCC Farmers Market at the park's edge is one of the best on the island for local produce and prepared foods. Few visitors realize the park also has free public tennis courts and a bandstand that hosts free Sunday concerts.",kamaaina:null},
  {name:"Keiki and the Plow",tier:"A",lat:21.2934,lng:-157.7108,category:"kids",subcategory:"farm",tagline:"U-pick veggies, mud kitchens, goats, and a pirate ship — a rare working farm open to families.",area:"Hawaii Kai",price:"$",parking:"Small lot at 587 Pakala St, Hawaii Kai",hours:"Saturdays 9–11am only",bestTime:"Arrive right at 9am — it fills up fast and the 2-hour window goes quickly",kidFriendly:true,talkStory:"Founded by a local family in Hawaii Kai's suburban foothills, Keiki and the Plow is a community-supported urban farm open to families for just two hours each Saturday morning. The pirate ship play structure was built by hand from reclaimed lumber. Kids harvest real vegetables from the rows and the mud kitchen encourages messy creative play. It is one of the few working farms in east Honolulu and a grassroots gem most tourists never find.",kamaaina:null},
  {name:"Kolowalu Park Playground",tier:"B",lat:21.2969,lng:-157.8619,category:"kids",subcategory:"playground",tagline:"Oahu's first inclusive playground — ramps, sensory panels, accessible swings for every kid.",area:"Kakaako",price:"Free",parking:"Free parking at Ward Village",hours:"Dawn to dusk",bestTime:"Late afternoon when it cools down; mornings on weekends before it gets busy",kidFriendly:true,talkStory:"Opened in 2022 as part of Ward Village, Kolowalu Park is Oahu's first fully inclusive playground, designed with disability advocates and occupational therapists. Every element -- ramps, transfer platforms, sensory panels, and adaptive swings -- ensures kids of all abilities play together. The rubberized ground surface stays cooler than sand or concrete in the Hawaiian sun. The adjacent dog park and Ward Village shops make it easy to spend a full morning.",kamaaina:null},
  {name:"Kualoa Ranch",tier:"S",lat:21.5213,lng:-157.8377,category:"kids",subcategory:"adventure",tagline:"Jurassic Valley ATV tours, horseback rides, and ziplines on a working cattle ranch — where they filmed Jurassic Park.",area:"Kualoa",price:"$$$",parking:"Free parking on-site",hours:"Daily 7:30am–5:30pm; tours run on set schedules — book online in advance",bestTime:"Morning tours have better light for Kualoa Valley photos and cooler temps",kidFriendly:true,talkStory:"This 4,000-acre working cattle ranch has been in the Morgan family since 1850, purchased from King Kamehameha III. The valley is considered one of the most sacred places on Oahu in Hawaiian tradition. Over 200 movies and TV shows have filmed here including Jurassic Park, Lost, and Hawaii Five-0. The 'Secret Island' beach -- included with some packages -- has calm shallow water and kayaks, the best-kept secret for families with young children.",kamaaina:"Kamaaina rates available with valid Hawaii ID — significant discount on tour packages"},
  {name:"Makapuu Tide Pools",tier:"A",lat:21.3107,lng:-157.6512,category:"kids",subcategory:"nature",tagline:"Natural lava rock tide pools teeming with sea life — free outdoor aquarium for curious keiki.",area:"East Oahu",price:"Free",parking:"Park at Makapuu Lookout lot (free) or along Kalanianaole Hwy near the pools",hours:"Open 24 hours; best during daylight at low tide",bestTime:"Low tide is essential — check tide charts. Morning for calmer conditions and fewer people",kidFriendly:true,talkStory:"These lava rock tide pools sit below the Makapuu Lighthouse Trail at the easternmost point of Oahu, formed by ancient volcanic flows meeting the ocean. At low tide, the pools trap small fish, hermit crabs, sea urchins, and colorful anemones -- a free natural aquarium. The area is also a prime whale-watching spot from November to April; humpback whales pass remarkably close to shore, making it a rare two-for-one nature experience.",kamaaina:null},
  {name:"Pearl Harbor Aviation Museum",tier:"A",lat:21.3545,lng:-157.9726,category:"kids",subcategory:"museum",tagline:"Real WWII planes in original hangars on Ford Island — the flight simulators are a huge hit with older kids.",area:"Pearl Harbor",price:"$$",parking:"Park at Pearl Harbor Visitor Center; shuttle bus to Ford Island included with admission",hours:"Daily 9am–5pm (last entry 4pm). Closed Thanksgiving, Christmas, New Year's",bestTime:"Weekday mornings; pair with the free USS Arizona Memorial visit",kidFriendly:true,talkStory:"Housed in two original WWII hangars on Ford Island that still bear bullet holes from the December 7, 1941 attack, this museum earned Smithsonian affiliate status. The restored Japanese Zero on display is one of only a handful in the world. The combat flight simulators use actual military training software adapted for civilians. Insider tip: look for the faded wartime markings still visible on the hangar floors where planes were once serviced.",kamaaina:"Kamaaina discount with Hawaii ID"},
  {name:"Polynesian Cultural Center",tier:"S",lat:21.6397,lng:-157.9227,category:"kids",subcategory:"museum",tagline:"Six island villages, canoe rides, fire-knife dancing, and a luau — the best cultural experience on Oahu for families.",area:"Laie",price:"$$$",parking:"Free parking on-site",hours:"Mon–Sat 12:30pm–9pm. Closed Sundays",bestTime:"Arrive at opening to see all six villages before the evening show; weekdays for smaller crowds",kidFriendly:true,talkStory:"Founded in 1963, the center was originally staffed by BYU-Hawaii students who performed and demonstrated crafts to pay tuition -- a tradition continuing today with over 100 student employees from Pacific Island nations. Six villages represent Hawaii, Samoa, Tonga, Fiji, Tahiti, and Aotearoa. The evening 'Ha: Breath of Life' show features a 100-person cast with the world-famous Samoan fire-knife dance. Arrive at 12:30 sharp to start with the least-crowded village.",kamaaina:"Kamaaina annual pass and discounted packages available with Hawaii ID"},
  {name:"Sea Life Park Hawaii",tier:"B",lat:21.3129,lng:-157.6594,category:"kids",subcategory:"aquarium",tagline:"Dolphin shows, sea lion encounters, and a huge reef tank right at Makapuu — touristy but the keiki love it.",area:"Waimanalo",price:"$$$",parking:"Free parking lot on-site",hours:"Daily 10am–4pm; check website for seasonal hours",bestTime:"Arrive at opening to catch the first dolphin show with fewer crowds",kidFriendly:true,talkStory:"Opened in 1964 by oceanographer Taylor 'Tap' Pryor, Sea Life Park was one of the first marine parks in the U.S. and pioneered dolphin research. The park sits at Makapuu Point with dramatic cliff backdrops and was a filming location for 50 First Dates. It is home to the only known 'wholphin' -- a hybrid of a false killer whale and bottlenose dolphin born here in 1985. The walk-through bird aviary with native Hawaiian species is often skipped but included with admission.",kamaaina:"Kamaaina annual pass is a solid deal if you go more than twice a year"},
  {name:"Turtle Bay Resort Pool & Beach",tier:"B",lat:21.7079,lng:-157.9978,category:"kids",subcategory:"splash-pad",tagline:"Day passes let you use the resort pool with waterslide, plus walk to calm Kuilima Cove for baby turtles.",area:"North Shore",price:"$$",parking:"Free self-parking for day-pass guests",hours:"Pool open 8am–8pm daily; day passes available based on capacity",bestTime:"Weekday mornings for pool space; late afternoon for turtle sightings at the cove",kidFriendly:true,talkStory:"Originally opened as the Kuilima Resort in 1972, Turtle Bay sits on 840 acres spanning five miles of North Shore coastline. Kuilima Cove, the sheltered bay in front of the resort, is a natural habitat for Hawaiian green sea turtles feeding on limu seaweed. The cove's reef creates calm shallow water even when North Shore surf is pumping. Day-pass guests get pool waterslide access plus beach gear; book ahead on weekends as they cap numbers.",kamaaina:"Kamaaina day rates available — call ahead for current pricing and availability"},
  {name:"Wai Kai Splash Pad",tier:"B",lat:21.3117,lng:-158.0236,category:"kids",subcategory:"splash-pad",tagline:"West Oahu's waterfront splash zone with floating obstacle course — worth the drive for a full day.",area:"Ewa Beach",price:"$",parking:"Free lot at 91-1621 Keoneula Blvd",hours:"Mon–Thu 10am–8pm, Fri–Sat 10am–9pm, Sun 10am–7pm (seasonal; check website)",bestTime:"Weekday mornings for the least crowds; bring sunscreen for the outdoor areas",kidFriendly:true,talkStory:"Wai Kai opened in 2023 as part of a waterfront development in Ewa Beach built around a 2.5-acre artificial lagoon designed by engineers behind Typhoon Lagoon at Disney World. The wave pool generates surfable standing waves while the floating obstacle course is a hit with kids 6 and up. The splash pad features zero-depth entry and gentle water features for toddlers. Multiple restaurants on-site mean no packing food -- try Nalu for poke overlooking the lagoon.",kamaaina:"Kamaaina rates available with valid Hawaii ID; check website for current pricing"},
  {name:"Waikiki Aquarium",tier:"A",lat:21.2658,lng:-157.8216,category:"kids",subcategory:"aquarium",tagline:"The third-oldest aquarium in the US, right on the Waikiki shoreline — small enough to not overwhelm little ones.",area:"Waikiki",price:"$",parking:"Limited street parking on Kalakaua Ave; paid lot at Kapiolani Park nearby",hours:"Daily 9am–5pm (last entry 4:30pm). Closed Thanksgiving & Christmas",bestTime:"Weekday mornings for fewest crowds; feeding times posted at entrance",kidFriendly:true,talkStory:"Founded in 1904, the Waikiki Aquarium is the third-oldest public aquarium in the United States, operated by the University of Hawaii. It was the first aquarium to breed the chambered nautilus, a deep-sea living fossil unchanged for 500 million years -- specimens are still on display. The outdoor monk seal exhibit houses rescued seals that cannot return to the wild. Its compact size is actually ideal for families with toddlers who get overwhelmed at larger venues.",kamaaina:"Kamaaina rate with Hawaii ID — significantly cheaper than regular admission"},
  {name:"Waimanalo Country Farms",tier:"B",lat:21.346,lng:-157.718,category:"kids",subcategory:"farm",tagline:"Seasonal pumpkin patch, corn maze, and farm activities on a real Waimanalo farm — fall is the best time.",area:"Waimanalo",price:"$",parking:"Free parking in the farm field lot",hours:"Seasonal — typically open Oct–Nov for pumpkin season, check website/social media for dates",bestTime:"Weekday mornings during pumpkin season for shortest lines; arrive at opening on weekends",kidFriendly:true,talkStory:"Run by a multi-generational Waimanalo farming family, this working operation transforms into a beloved seasonal attraction each fall. The pumpkin festival -- corn maze, hayrides, petting zoo, and u-pick pumpkins -- has been an Oahu Halloween tradition since the early 2000s. The farm grows everything on-site using Waimanalo's rich soil, famous across Hawaii for producing the state's best fruits and vegetables. October weekend lines snake around the block, so weekday mornings are the insider move.",kamaaina:null},
  {name:"Wet 'n' Wild Hawaii",tier:"A",lat:21.3343,lng:-158.086,category:"kids",subcategory:"splash-pad",tagline:"26 rides including Keiki Kove splash zone — the full water park experience on the island.",area:"Kapolei",price:"$$",parking:"Free parking at 400 Farrington Hwy, Kapolei",hours:"Daily from 10:30am (closing time varies seasonally)",bestTime:"Weekdays for shorter lines; arrive at opening for the first hour with no waits",kidFriendly:true,talkStory:"Opened in 1999 as the only water theme park in Hawaii, Wet 'n' Wild spans 29 acres in Kapolei and draws over 300,000 visitors annually. The Keiki Kove splash area was designed for children under 48 inches with gentle slides and shallow pools. The 'Tornado' funnel ride -- a 45-foot plunge into a massive rotating bowl -- consistently ranks among the top water park rides in the Pacific. Bring your own tubes and towels to save on rental fees.",kamaaina:"Kamaaina annual passes and discounted day rates with valid Hawaii ID"},
  {name:"Aloha Stadium Swap Meet",tier:"A",lat:21.3728,lng:-157.93,category:"market",subcategory:"flea-market",tagline:"Hawaii's iconic outdoor flea market with 400+ vendors — relocated to the upper Halawa lot while the new stadium is built.",area:"Aiea",price:"$",mustOrder:[],parking:"Park in the lower lot, enter through the Halawa gate. Parking is CASH ONLY",talkStory:"A local institution since the 1970s. The old stadium was demolished in 2025 for the New Aloha Stadium Entertainment District (opening 2029), but the swap meet relocated to the upper Halawa parking lot in October 2025 with improvements — repaved areas, centralized vendors, dedicated food truck section, big-top tent with live music, and modern restrooms. Over 400 vendors selling everything from aloha shirts and local crafts to fresh produce and plate lunches. Great for cheap souvenirs that aren't tourist-trap quality. The swap meet will stay at this location for 5-10 years during construction.",cashOnly:false,kamaaina:"Kamaaina/military admission $1 with valid ID (general admission $2). Kids 11 and under free"},
  {name:"H Mart Keeaumoku",tier:"A",lat:21.295,lng:-157.839,category:"market",subcategory:"korean-grocery",tagline:"Massive Korean grocery with an incredible hot food bar, live seafood counter, and Hawaii-exclusive frozen treats.",area:"Ala Moana",price:"$$",mustOrder:["Korean fried chicken","tteokbokki","poke"],parking:"Paid garage at Keeaumoku shopping area",talkStory:"The largest Korean grocery chain in America has a massive Honolulu location that locals treat as both grocery store and food court. The hot food bar has incredible Korean fried chicken, japchae, and tteokbokki. The banchan section is enormous, and the fresh seafood counter sells live crab and whole fish. Check the freezer section for Hawaiian-exclusive flavors of Korean ice cream bars. Weekday afternoons are best; weekends are packed.",cashOnly:false,kamaaina:null},
  {name:"Marukai Wholesale Mart",tier:"A",lat:21.335,lng:-157.862,category:"market",subcategory:"japanese-grocery",tagline:"Hawaii's first warehouse-style Japanese market — fresh bentos, sushi counters, and Japanese snacks you can't find anywhere else.",area:"Kalihi",price:"$",mustOrder:["daily bento box","poke","sushi rolls"],parking:"Free lot",talkStory:"Marukai is a Japanese discount warehouse that locals have relied on for decades. The daily bento selection is legendary — arrive before lunch for the widest variety of freshly made boxes. The poke and sushi counters rival dedicated restaurants at a fraction of the price. Stock up on Japanese snacks, kitchenware, and specialty ingredients you won't find at Safeway. Membership not required for food purchases.",cashOnly:false,kamaaina:null},
  {name:"Nijiya Market",tier:"B",lat:21.2885,lng:-157.842,category:"market",subcategory:"japanese-grocery",tagline:"Boutique Japanese grocery with impeccable quality sushi, onigiri, and hard-to-find Japanese ingredients.",area:"Ala Moana",price:"$$",mustOrder:["fresh onigiri","chirashi bowl","mochi"],parking:"Shared lot at Ala Moana area",talkStory:"Nijiya is a smaller, more curated Japanese grocery that locals love for its quality over quantity approach. The prepared foods section has restaurant-quality sushi, onigiri, and bento boxes. The produce is pristine and the Japanese snack aisle is a treasure hunt. Less overwhelming than Marukai but the quality is consistently higher. The freshly made onigiri are a perfect quick lunch.",cashOnly:false,kamaaina:null},
  {name:"Palama Supermarket",tier:"B",lat:21.321,lng:-157.861,category:"market",subcategory:"korean-grocery",tagline:"Hawaii's favorite Korean grocery — legendary banchan counter, fresh kimchi, and hot plate lunches that rival any restaurant.",area:"Kalihi",price:"$",mustOrder:["banchan assortment","fresh kimchi","plate lunch"],parking:"Free lot on N King St",talkStory:"Palama is where local Korean and mixed-plate families do their serious grocery shopping. The banchan counter is the star — fill a container with a dozen different Korean side dishes for just a few dollars. The in-house kimchi is made fresh and the hot plate lunches rival dedicated restaurants. The produce section has exceptional quality at prices that beat the big chains. Weekday mornings are best; weekends get packed.",cashOnly:false,kamaaina:null},
  {name:"Tamashiro Market",tier:"S",lat:21.3193,lng:-157.8638,category:"market",subcategory:"fish-market",tagline:"Honolulu's most trusted fish market for over 80 years — where local families buy poke and fresh seafood for parties.",area:"Kalihi",price:"$$",mustOrder:["shoyu ahi poke","spicy tako poke","poke plate"],parking:"Small lot in front; street parking on N King St",talkStory:"Open since the 1940s, Tamashiro Market is a Kalihi institution. The poke counter has a dozen varieties daily — shoyu ahi, spicy tako, limu, and seasonal specials. Come Saturday morning before 10am for the best selection; by noon, the popular cuts are gone. Locals grab a styrofoam plate and eat standing in the parking lot. The fish counter also sells whole fish, sashimi-grade blocks, and shellfish at prices well below supermarkets.",cashOnly:false,kamaaina:null},
  {name:"Anna O'Brien's",tier:"B",lat:21.29,lng:-157.82,category:"nightlife",subcategory:"live-music-venue",tagline:"Honolulu's quintessential dive bar since 1969 — live rock, reggae, and punk upstairs, sticky-floor charm downstairs.",area:"Mo'ili'ili",price:"$",mustOrder:["cheap beer"],parking:"Street parking on Beretania St",talkStory:"Named after original owner Anna O'Brien who opened this Mo'ili'ili dive in 1969, it's outlasted every trendy bar in Honolulu. The upstairs stage launched careers for local punk and reggae acts, and the no-cover policy most nights keeps it democratic. Anthony Bourdain drank here and called it his kind of place. The motorcycle club regulars and UH rugby teams treat it like a second living room.",cashOnly:false,kamaaina:null},
  {name:"Bar Leather Apron",tier:"S",lat:21.309,lng:-157.86,category:"nightlife",subcategory:"cocktail-bar",tagline:"One of the world's best cocktail bars hidden on a downtown Honolulu mezzanine — 15 seats, Japanese technique, local ingredients.",area:"Downtown",price:"$$$",mustOrder:["bartender's choice cocktail","old fashioned with Hawaiian honey"],parking:"Street parking; paid lot nearby",talkStory:"Hidden on the mezzanine of the TOPA Financial Center, this tiny bar was named one of the best in the world. With only about 15 seats, it feels like a private club. Bartenders Justin Park and Tom Park create immaculate craft cocktails using house-made syrups, local ingredients, and Japanese technique. Reserve in advance online. Go early in the week for a more intimate experience. This is where Honolulu's cocktail cognoscenti drink.",cashOnly:false,kamaaina:null},
  {name:"Bevy",tier:"B",lat:21.295,lng:-157.856,category:"nightlife",subcategory:"cocktail-bar",tagline:"Artsy Kakaako cocktail bar doubling as a gallery — creative drinks, locally sourced small plates, and rotating local art.",area:"Kakaako",price:"$$",mustOrder:["signature cocktail","small plates"],parking:"Street parking in Kakaako",talkStory:"An artsy cocktail bar in Kakaako that doubles as an art gallery with rotating exhibitions from local artists. The cocktails are creative and the food menu, focused on small plates and locally sourced ingredients, is consistently good. Locals come for after-work drinks at happy hour (4-6pm) and the weekend brunch cocktail menu is a neighborhood ritual.",cashOnly:false,kamaaina:null},
  {name:"Hana Koa Brewing Co.",tier:"A",lat:21.296,lng:-157.856,category:"nightlife",subcategory:"brewery",tagline:"Oahu's best brewery in a converted Coca-Cola factory — tropical IPAs, spacious beer garden, and rotating food pop-ups.",area:"Kakaako",price:"$$",mustOrder:["Kolsch","tropical IPA","rotating seasonal"],parking:"Street parking in Kakaako; some lot spaces",talkStory:"Occupying a converted Coca-Cola syrup factory in Kakaako, Hana Koa is widely considered the best brewery on Oahu. The spacious industrial taproom serves excellent locally brewed beers — from tropical IPAs to dark stouts — along with a creative food menu. The Kolsch and the IPA are the standouts. Thursday-Saturday evenings are liveliest; check for food truck pop-ups. Local families come for the beer garden atmosphere.",cashOnly:false,kamaaina:null},
  {name:"Honolulu Beerworks",tier:"A",lat:21.2984,lng:-157.8571,category:"nightlife",subcategory:"brewery",tagline:"Kakaako's original craft brewery — industrial taproom pouring Hawaii-brewed beers with rotating food trucks outside.",area:"Kakaako",price:"$-$$",mustOrder:["Cocoweizen — coconut hefeweizen, a local favorite","seasonal IPA — whatever's on the rotating tap","tasting flight — try 4-5 beers at once"],parking:"Street parking on Coral St; Kakaako lots",talkStory:"The brewery that helped launch Kakaako's craft beer scene. An industrial taproom in a converted warehouse with garage doors that open to the street. All beers brewed on-site — the Cocoweizen (coconut wheat beer) is the signature, but the rotating taps always have something interesting. Food trucks park outside most nights. The vibe is relaxed and unpretentious — a neighborhood brewery where Kakaako residents, artists, and off-duty service industry people unwind. Open daily.",cashOnly:false,kamaaina:null},
  {name:"La Mariana Sailing Club",tier:"S",lat:21.315,lng:-157.874,category:"nightlife",subcategory:"tiki-bar",tagline:"Hawaii's original tiki bar since 1957 — hidden in an industrial marina with museum-worthy tiki artifacts and strong mai tais.",area:"Sand Island",price:"$$",mustOrder:["mai tai","blue hawaii"],parking:"Free lot at the marina",talkStory:"Hawaii's original tiki bar since 1957, hidden in an industrial marina you'd never find unless you knew it was there. The interior is a living museum of tiki culture — puffer fish lamps from the original Trader Vic's, rattan chairs from Don the Beachcomber, and hand-carved tikis from the old Kon Tiki Room. The mai tais are strong and the live music on Friday evenings sets a wonderfully retro mood. Founder Annette La Mariana originally charged $2 membership and 50-cent boat slips.",cashOnly:false,kamaaina:null},
  {name:"Lewers Lounge",tier:"A",lat:21.2769,lng:-157.8299,category:"nightlife",subcategory:"cocktail-lounge",tagline:"The most elegant cocktail lounge in Waikiki — live jazz, classic cocktails, and old-school Halekulani glamour.",area:"Waikiki",price:"$$$",mustOrder:["classic mai tai — Halekulani's refined version","martini — expertly made","dessert cocktails — the chocolate options are decadent"],parking:"Halekulani valet; street parking on Lewers St",talkStory:"Inside the Halekulani Hotel, Lewers Lounge is where old Waikiki glamour still lives. Live jazz nightly, impeccable cocktails, and plush Art Deco surroundings that make you feel like you've stepped into a 1940s film. Dress smart casual — this isn't a flip-flops bar. The bartenders are some of the most skilled on the island. Yes, drinks are expensive (it's the Halekulani), but the experience is unmatched in Waikiki. A perfect nightcap after dinner. Nightly 5pm-midnight.",cashOnly:false,kamaaina:null},
  {name:"Pint + Jigger",tier:"A",lat:21.2857,lng:-157.8278,category:"nightlife",subcategory:"gastropub",tagline:"Kaimuki's craft cocktail gastropub — serious drinks, creative pub food, and the best happy hour in the neighborhood.",area:"Kaimuki",price:"$$",mustOrder:["bartender's choice cocktail — they're creative and skilled","pork belly sliders — crispy and rich","truffle fries — the crowd favorite"],parking:"Street parking on Waialae Ave",talkStory:"The cocktail bar that helped put Kaimuki on the nightlife map. Part gastropub, part craft cocktail bar — the drinks are well-made and the food is above-average pub fare. The bartenders know their stuff and are happy to make custom drinks based on your preferences. Happy hour is one of the best values in town. The space is intimate and gets lively on weekends. A great spot to start or end a Kaimuki dining crawl.",cashOnly:false,kamaaina:null},
  {name:"Smith's Union Bar",tier:"A",lat:21.311,lng:-157.8615,category:"nightlife",subcategory:"dive-bar",tagline:"Honolulu's oldest bar (1935) — cheap beers, great jukebox, and the unpretentious soul of Chinatown nightlife.",area:"Chinatown / Downtown",price:"$",mustOrder:["cheap beer","whatever's on tap"],parking:"Street parking; walk from downtown",talkStory:"Established in 1935, Smith's is a no-frills dive where beers are cheap and the jukebox has a great selection. The crowd is a mix of old-timers, off-duty chefs, creatives, and locals who appreciate a bar that hasn't tried to be anything other than what it is for over 90 years. There is nothing fancy here and that is entirely the point. After 9pm is best; Chinatown First Friday nights are especially lively.",cashOnly:true,kamaaina:null},
  {name:"Tchin Tchin Bar",tier:"B",lat:21.3125,lng:-157.8618,category:"nightlife",subcategory:"wine-bar",tagline:"An intimate Chinatown wine and cocktail bar with dim lighting, curated playlist, and a sophisticated but unpretentious vibe.",area:"Chinatown / Downtown",price:"$$",mustOrder:["natural wine selection","craft cocktail"],parking:"Street parking; walk from downtown",talkStory:"A moody, intimate wine and cocktail bar on Hotel Street in Chinatown. The dim lighting, curated playlist, and minimalist decor create a vibe that feels more Brooklyn or Tokyo than Honolulu. The natural wine selection is excellent and the bartenders can guide you to something unexpected. Popular with Chinatown's creative crowd and after-work industry folks. First Friday is especially lively.",cashOnly:false,kamaaina:null},
  {name:"The Dragon Upstairs",tier:"A",lat:21.313,lng:-157.863,category:"nightlife",subcategory:"jazz-club",tagline:"A tiny Chinatown jazz club above a bar — 30-person room where you're practically sitting with the band.",area:"Chinatown / Downtown",price:"$$",mustOrder:["cocktail from the bar downstairs"],parking:"Street parking; walk from downtown",talkStory:"A tiny jazz club above a Chinatown bar that features some of Hawaii's best jazz musicians in an intimate setting. The room holds maybe 30 people, creating a close-knit atmosphere where you're almost sitting with the band. Locals who love live music consider this one of Honolulu's greatest treasures. No cover on some nights; check the schedule online. Arrive early for a good seat.",cashOnly:false,kamaaina:null},
  {name:"53 By The Sea",tier:"B",lat:21.293,lng:-157.862,category:"restaurant",subcategory:"fine-dining",tagline:"Glass-walled waterfront dining at Kewalo Basin — panoramic ocean views and spectacular sunsets for special occasions.",area:"Kakaako",price:"$$$$",mustOrder:["seafood tower","wagyu steak","sunset cocktail"],parking:"Validated valet parking available",talkStory:"Built in the 1990s by Japanese conglomerate Suntory, 53 By The Sea was later transformed by local restaurateur Shawn Ching into the sleek glass-walled showpiece on Kewalo Basin it is today. The name comes from its address at Pier 53. This is Honolulu's premier proposal spot — request a west-facing window table and arrive 30 minutes before sunset. The lounge menu offers the same jaw-dropping ocean views at half the dining room price.",cashOnly:false,kamaaina:null},
  {name:"AGU A Ramen Bistro",tier:"B",lat:21.2913,lng:-157.8383,category:"restaurant",subcategory:"ramen",tagline:"Solid Honolulu ramen chain with rich tonkotsu broth — reliable bowl every single time.",area:"McCully",price:"$$",mustOrder:["Kotteri ramen — thick, rich tonkotsu broth with chashu and soft egg","AGU shoyu ramen — soy-based broth, lighter but still flavorful","Gyoza — pan-fried crispy, good starter while you wait"],parking:"Strip mall parking lot. The McCully location usually has spots available.",talkStory:"Founded by Chef Hideaki Ariga, who spent years perfecting his tonkotsu recipe in Japan before launching AGU in Hawaii around 2013. The name means 'jaw' in Japanese, a nod to the collagen-rich pork jowl bones that give the broth its silky richness. Now with multiple Oahu locations, it's the island's most reliable ramen chain. Order the kotteri (extra-thick) broth and customize your richness level — late-night hours make it a solid post-bar bowl.",cashOnly:false,kamaaina:null},
  {name:"Aiea Bowl Restaurant",tier:"B",lat:21.3863,lng:-157.9319,category:"restaurant",subcategory:"plate-lunch",tagline:"Bowling alley restaurant with surprisingly excellent local food — the oxtail soup draws people from all over.",area:"Aiea",price:"$",mustOrder:["Oxtail soup — clear broth, tender meat, served with mustard cabbage and rice","Fried noodles — local-style chow mein, crispy and savory","Hamburger steak with gravy — classic plate lunch comfort food"],parking:"Large parking lot for the bowling alley. Never an issue.",talkStory:"Aiea Bowl opened in 1960 and the restaurant inside became famous on its own — locals drive from across the island just for the oxtail soup, a crystal-clear broth with fork-tender meat, mustard cabbage, and fresh ginger. Featured on multiple 'Best of Hawaii' lists despite being inside a bowling alley. The same family has run the kitchen for decades. Go weekday lunch, order the oxtail with extra rice, then roll a few frames after — prices still feel stuck in a previous decade.",cashOnly:false,kamaaina:null},
  {name:"Alicia's Market",tier:"A",lat:21.3268,lng:-157.8658,category:"restaurant",subcategory:"poke",tagline:"30+ poke varieties in a Kalihi market — the OG that every other poke shop tries to imitate.",area:"Kalihi",price:"$",mustOrder:["Shoyu ahi poke — the classic that built this place's reputation","Spicy ahi poke — creamy and perfectly balanced heat","Hawaiian-style poke — simple limu and sea salt, old-school preparation"],parking:"Small lot in front of the store on Dillingham Blvd",talkStory:"Founded by the Sniffen family and named after matriarch Alicia, this Kalihi market has been serving 30+ varieties of fresh poke since the 1970s — long before poke bowls became a mainland trend. The shoyu ahi and spicy ahi are legendary, but ask the counter staff what came in freshest that morning. Best selection before 11am; popular flavors sell out by afternoon. Cash only. Pair with a Bishop Museum visit five minutes away.",cashOnly:true,kamaaina:null},
  {name:"Bar MAZE",tier:"A",lat:21.2992,lng:-157.8629,category:"restaurant",subcategory:"fine-dining",tagline:"James Beard-nominated omakase in Kakaako — intimate counter seating where every course is theater.",area:"Kakaako",price:"$$$",mustOrder:["seasonal tasting menu ($125)","cocktail pairing ($200 with pairing)"],parking:"Street parking on Auahi St and surrounding Kakaako blocks; metered spots free after 6pm",talkStory:"From Justin Park (2023 James Beard Outstanding Bartender winner, also behind the acclaimed Bar Leather Apron) and brother Tom, with Chef Ki Chung earning consecutive James Beard Best Chef nominations. Opened 2021 in Kakaako with just 16 counter seats. The seasonal tasting menu spotlights hyper-local ingredients; the cocktail pairing is meticulously matched course-by-course. Book 2-3 weeks ahead — this is one of Hawaii's hardest reservations to score.",cashOnly:false,kamaaina:null},
  {name:"bEASTside Kitchen",tier:"B",lat:21.2803,lng:-157.7421,category:"restaurant",subcategory:"hawaiian-fusion",tagline:"Covid pop-up turned Hawaii Kai neighborhood gem — live music nightly, garlic shrimp that rivals the North Shore trucks.",area:"Hawaii Kai",price:"$$",mustOrder:["umami garlic shrimp — the signature","loco moco — elevated but still local","BBQ bao buns — crowd favorite"],parking:"Lot on Kalanianaole Hwy; ample compared to town restaurants",talkStory:"Born as a pandemic pop-up tent in Waimanalo in September 2021 by James Kiko and his grandmother Nette, bEASTside grew into a Hawaii Kai brick-and-mortar that became the east side's living room. Live music nightly (except Tue), bingo on 2nd and 4th Mondays, and a crowd that's 100% local families. The umami garlic shrimp rivals any North Shore truck. Happy hour until 6pm, kitchen open until midnight most nights — zero tourists, pure community.",cashOnly:false,kamaaina:null},
  {name:"Bob's Bar-B-Que",tier:"A",lat:21.3918,lng:-157.9735,category:"restaurant",subcategory:"plate-lunch",tagline:"Pearl City plate lunch institution — the kalbi and BBQ chicken are old-school Hawaii comfort food at its purest.",area:"Pearl City",price:"$",mustOrder:["kalbi short ribs — smoky, sweet, tender","BBQ chicken — the classic plate","fried noodles — ask for extra crispy"],parking:"Strip mall parking lot",talkStory:"Open since the 1970s in a Pearl City strip mall, Bob's is one of the last old-guard plate lunch shops where recipes haven't changed in 40+ years. The kalbi short ribs are marinated overnight in a guarded family recipe, and the fried noodles are cooked in a wok so seasoned it's practically an heirloom. Regulars call ahead — the staff knows their order by voice. Cash only, no website, no social media — just honest plate lunch the way Hawaii used to do it.",cashOnly:true,kamaaina:null},
  {name:"Boots & Kimo's",tier:"A",lat:21.3943,lng:-157.7396,category:"restaurant",subcategory:"breakfast",tagline:"Banana macadamia nut pancakes with mac nut sauce — worth the hour wait if you get there by 7:30am.",area:"Kailua",price:"$$",mustOrder:["banana mac nut pancakes ($13–15) — do NOT add butter or syrup, the sauce is everything"],parking:"Enchanted Lake Shopping Center has shared parking lot",talkStory:"Founded in 1989 by Jesse 'Boots' Maragos (a Windward Oahu waterman) and Kimo McVay, the legendary entertainment manager who handled Don Ho's career for decades. Their banana macadamia nut pancakes with homemade mac nut sauce became an island-wide obsession. Pro tip: never add butter or syrup — the sauce IS the dish. Tuesday/Wednesday right at the 7:30am opening is the hack to avoid the brutal weekend wait that can stretch past 90 minutes.",cashOnly:false,kamaaina:null},
  {name:"Brick Fire Tavern",tier:"A",lat:21.2849,lng:-157.8226,category:"restaurant",subcategory:"pizza",tagline:"Neapolitan wood-fired pizza with Hawaiian twists — kalua pig pizza, craft cocktails, and a loyal Kaimuki following.",area:"Kaimuki",price:"$$",mustOrder:["kalua pig pizza — Hawaiian BBQ meets Neapolitan crust","margherita — the benchmark, beautifully charred","craft cocktails — the bar program is legit"],parking:"Street parking on Waialae Ave; side streets toward Wilhelmina Rise",talkStory:"Opened around 2016 by pizza obsessive Erick Garza, who spent months sourcing a custom wood-fired oven from Italy and mastering Neapolitan technique before adding Hawaiian twists. The kalua pig pizza — smoky pulled pork on a perfectly charred, leopard-spotted crust — could only come from Hawaii. The craft cocktail program is equally serious. Kaimuki regulars and east Honolulu date-nighters dominate the crowd. Reservations recommended for dinner; Tue-Sun from 11am.",cashOnly:false,kamaaina:null},
  {name:"Broke Da Mouth Grindz",tier:"B",lat:21.344,lng:-158.07,category:"restaurant",subcategory:"plate-lunch",tagline:"The name says it all — braised short ribs so tender they fall apart, and portions so generous Kapolei locals make this their weekly ritual.",area:"Kapolei",price:"$",mustOrder:["Braised beef short ribs plate — fall-off-the-bone tender, the signature dish","Garlic chicken — crispy skin with serious garlic punch","Loco moco — homestyle and massive portion"],parking:"Strip mall parking lot with plenty of stalls",talkStory:"Family-run by the Manglona family in Kapolei, Broke Da Mouth earned a cult West Side following with slow-cooked braised short ribs so tender they collapse at the touch of a fork. The name is local pidgin for 'so delicious it breaks your mouth.' Limited hours and the short ribs sell out regularly — go early or call ahead. Wednesday specials draw the biggest crowds. Portions are built for working families, not Instagram, and priced accordingly.",cashOnly:false,kamaaina:null},
  {name:"Buzz's Lanikai",tier:"A",lat:21.3886,lng:-157.7142,category:"restaurant",subcategory:"seafood",tagline:"Old-school Kailua steakhouse steps from Lanikai Beach — the kiawe-grilled ahi steak is a local institution.",area:"Lanikai",price:"$$",mustOrder:["Kiawe-grilled ahi steak — seared over wood, served with garlic butter","Buzz's original steak — 10oz sirloin, simple and satisfying","Coconut shrimp — crispy and sweet, classic pupu"],parking:"Small parking lot in front, plus street parking on Kawailoa Rd. Beach traffic makes weekends tough — go weekday evenings.",talkStory:"Founded by Buzz Schneider in 1962, making it one of Oahu's oldest continuously operating restaurants. The wood-paneled, tiki-era dining room hasn't changed much in 60 years — sandy-footed families sit next to couples on date night. The kiawe-grilled ahi steak, seared over real local kiawe wood, is the star. Perfect post-beach dinner after a Lanikai day. No reservations, no pretension — just show up and put your name in. Full bar now available.",cashOnly:false,kamaaina:null},
  {name:"Café Kaila",tier:"A",lat:21.2843,lng:-157.829,category:"restaurant",subcategory:"breakfast",tagline:"Four-time Honolulu Magazine gold medalist for Best Breakfast — the meatloaf loco moco is a hangover cure and a life choice all at once.",area:"Moiliili / Kapiolani",price:"$",mustOrder:["Meatloaf loco moco — housemade meatloaf with rich gravy, the signature dish","Macadamia nut pancakes — fluffy with local mac nuts and tropical fruit","Eggs Benedict — perfectly poached with hollandaise on point"],parking:"Upper level of Market City Shopping Center",talkStory:"Opened in 2008 by Chef Christi Kaila Sei in Market City Shopping Center — within two years it won Honolulu Magazine's Best Breakfast Hale Aina Award, eventually earning it four times. The meatloaf loco moco is housemade and legendary, the macadamia nut pancakes are fluffy perfection. Weekday mornings are dramatically less crowded than weekends. Get there by 7:30am Saturday or expect a 30+ minute wait. The daily specials board is always worth checking first.",cashOnly:false,kamaaina:null},
  {name:"Chengdu Taste",tier:"A",lat:21.2965,lng:-157.8505,category:"restaurant",subcategory:"sichuan",tagline:"Authentic Sichuan cuisine from the LA-born mini-chain — mouth-numbing ma la flavors that Honolulu's spice lovers have been craving.",area:"Ala Moana / Kakaako",price:"$$",mustOrder:["boiled fish in chili oil — fiery and numbing","mapo tofu — the Sichuan benchmark","dan dan noodles — rich sesame-chili sauce"],parking:"808 Center parking on Sheridan St",talkStory:"The LA Sichuan sensation that finally opened in Honolulu, filling a massive gap in the island's Chinese food scene. Authentic Sichuan cooking — real ma la (numbing-spicy) heat from quality peppercorns, not just generic chili oil. The boiled fish in chili oil is a table-wide experience. If you grew up eating Sichuan food or fell in love with it in a mainland Chinatown, this is the real deal in Honolulu. Shares the 808 Center complex with Mian (their noodle concept). Lunch and dinner daily.",cashOnly:false,kamaaina:null},
  {name:"Chogajip Korean Restaurant",tier:"B",lat:21.2907,lng:-157.837,category:"restaurant",subcategory:"late-night",tagline:"Open until 4am every single day — the chive pancakes and kimchi stew are why Honolulu's night owls know exactly where to end up.",area:"Ala Moana / Kapiʻolani",price:"$$",mustOrder:["chive pancakes (buchujeon)","kimchi jjigae","galbi"],parking:"Small shared lot off Kapiolani Blvd; street parking on side streets",talkStory:"A Kapiolani Blvd fixture for over two decades, Chogajip is the unofficial canteen of Honolulu's restaurant and bar industry — the place chefs and bartenders go after their own kitchens close. Open daily 8am to 4am, the 2am crowd is its own subculture of night-shift workers, post-club survivors, and insomniacs craving kimchi jjigae. The chive pancakes (buchujeon) are crispy-edged perfection at any hour. No frills, fluorescent lights, and exactly right.",cashOnly:false,kamaaina:null},
  {name:"Chong Qing Hot Pot",tier:"A",lat:21.2938,lng:-157.853,category:"restaurant",subcategory:"hot-pot",tagline:"Sichuan-style hot pot at Ward Village — bubbling split pots of spicy and mild broth, an all-you-can-eat option, and a serious sauce bar.",area:"Kakaako",price:"$$",mustOrder:["split pot — half spicy Sichuan, half mild bone broth","thinly sliced lamb — the hot pot essential","build your own sauce — sesame, garlic, cilantro, chili oil"],parking:"Ward Village parking",talkStory:"The best hot pot on Oahu. Chongqing-style Sichuan spicy broth alongside a milder option in a split pot. The all-you-can-eat option is solid value — meat, seafood, vegetables, noodles, and tofu for a fixed price. The sauce bar lets you build your own dipping sauce from a dozen-plus ingredients. Great for groups and rainy evenings. The Ward Village location is the more popular of their two spots. Dinner nightly, lunch on weekends.",cashOnly:false,kamaaina:null},
  {name:"Cinnamon's Restaurant",tier:"A",lat:21.3923,lng:-157.7453,category:"restaurant",subcategory:"breakfast",tagline:"Kailua brunch institution where the guava chiffon pancakes and red velvet pancakes have a cult following.",area:"Kailua",price:"$$",mustOrder:["Guava chiffon pancakes — fluffy, tangy-sweet, the signature dish","Red velvet pancakes — cream cheese frosting on pancakes, outrageously good","Eggs Benedict — local twist with kalua pork or crab cake"],parking:"Parking lot behind the restaurant off Kailua Rd. Can fill up on weekends — arrive before 8:30am or after 11am.",talkStory:"Opened in 1985 as a tiny breakfast counter, Cinnamon's later moved to a bigger Kailua Road location to handle the crowds — but weekends still pack out. The guava chiffon pancakes, made with real guava puree folded into the batter, are the signature that built a following across three decades. Named a Hale Aina Award winner multiple times. The move: brunch at Cinnamon's, then walk to Kailua Beach. Grab a patio table if you can — it gets warm inside.",cashOnly:false,kamaaina:null},
  {name:"Da Ono Hawaiian Food",tier:"A",lat:21.2765,lng:-157.8135,category:"restaurant",subcategory:"plate-lunch",tagline:"The original Ono Hawaiian Foods closed after 57 years, but Da Ono carries the torch at the same Kapahulu address — kalua pig still hits.",area:"Kapahulu",price:"$",mustOrder:["Kalua pig plate — smoky, tender, and authentic as it gets","Lomi salmon — fresh tomato and salmon, served cold the traditional way","Pipikaula short ribs — Hawaiian-style dried beef, salty and chewy"],parking:"Street parking on Kapahulu Ave, small lot behind building",talkStory:"The original Ono Hawaiian Foods was founded by Sueko Ono in 1962 and ran for 57 years, becoming one of Obama's favorite Honolulu stops (he'd order the kalua pig and lomi salmon). After it closed in 2019, Da Ono opened at the same Kapahulu address, carrying the torch of traditional Hawaiian plate lunches. Wed-Sun only, and popular items sell out by 2pm. Order the combo plate to try multiple dishes — the poi is hand-pounded and the pipikaula is legit.",cashOnly:false,kamaaina:null},
  {name:"Diamond Head Market & Grill",tier:"A",lat:21.2687,lng:-157.8058,category:"restaurant",subcategory:"plate-lunch",tagline:"Monsarrat Ave institution since the '90s — the lemon crunch cake alone is worth the trip.",area:"Kapahulu / Diamond Head",price:"$",mustOrder:["lemon crunch cake — legendary, the signature","ginger wasabi salmon plate","poke bowls — fresh, well-priced"],parking:"Small lot behind the market; street parking on Monsarrat Ave",talkStory:"Opened in 1997 by Chef Kelvin Ro, Diamond Head Market & Grill became a Monsarrat Ave institution with its takeout window serving plate lunches, poke, and the now-iconic lemon crunch cake — locals order full cakes for parties and holidays. Tourists discovered it thanks to the Diamond Head hike route, but this is a legit neighborhood staple. The insider move: go weekday mornings to skip the post-hike weekend rush. The market side has great grab-and-go onigiri too.",cashOnly:false,kamaaina:null},
  {name:"Don Quijote Honolulu (Deli / Poke Counter)",tier:"B",lat:21.2968,lng:-157.8434,category:"restaurant",subcategory:"late-night",tagline:"24 hours, legit poke, fresh bento, spam musubi — the Japanese-style superstore that locals hit at 2am without shame.",area:"Moiliili / Kaheka",price:"$",mustOrder:["Poke by the container — multiple varieties, always fresh and cheap","Spam musubi — perfectly proportioned rice-to-spam ratio","Bento boxes — Japanese-quality prepared meals at supermarket prices"],parking:"Large free parking structure attached to the store",talkStory:"Part of the Japanese Don Quijote discount chain (this Kaheka St location was formerly a Daiei supermarket), the 24-hour deli counter became a Honolulu institution for its surprisingly excellent poke and prepared foods. The late-night poke run is a local tradition — the counter gets restocked throughout the day so even 2am poke is fresh. Takoyaki and tempura near the deli are sleeper hits. Open 24/7, free parking garage, and no judgment at any hour.",cashOnly:false,kamaaina:null},
  {name:"Duc's Bistro",tier:"A",lat:21.314,lng:-157.864,category:"restaurant",subcategory:"fine-dining",tagline:"A swank French-Vietnamese oasis hiding in Chinatown — crispy spring rolls meet bouillabaisse with island fish.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["bouillabaisse with island fish","crispy spring rolls","beef in betel leaf"],parking:"Street parking; paid lots on Maunakea St",talkStory:"Chef Duc Pham fled Vietnam in the 1970s, eventually settling in Hawaii where he opened Duc's Bistro in Chinatown, blending French classical technique with Vietnamese flavors in a white-tablecloth setting. The bouillabaisse features fresh island fish, the spring rolls are impossibly crispy, and the beef in betel leaf is extraordinary. Consistently named one of Honolulu's most underrated restaurants by local food critics. The Chinatown location adds gritty charm to the refined dining.",cashOnly:false,kamaaina:null},
  {name:"Elena's Restaurant",tier:"A",lat:21.3876,lng:-158.0098,category:"restaurant",subcategory:"filipino",tagline:"Waipahu's Filipino food institution — the crispy pata is legendary and the portions are built for sharing with family.",area:"Waipahu",price:"$",mustOrder:["crispy pata — the signature dish, crackling skin and tender meat","pork adobo — textbook version","pancit — loaded with shrimp and pork"],parking:"Strip mall parking lot — easy",talkStory:"Elena Suguitan opened her namesake restaurant in Waipahu — heart of Oahu's Filipino community, one of the largest outside the Philippines. The crispy pata (whole fried pork leg with skin so crispy it shatters) is the must-order that draws people from across the island. Featured on local TV and 'Best of' lists for years. Portions are enormous and priced for local families. If you've never tried Filipino food, Elena's pork adobo and pancit are a proper introduction.",cashOnly:false,kamaaina:null},
  {name:"Ethel's Grill",tier:"A",lat:21.3265,lng:-157.8678,category:"restaurant",subcategory:"plate-lunch",tagline:"Tiny Kalihi gem where the garlic ahi and oxtail soup are worth the early wake-up.",area:"Kalihi",price:"$",mustOrder:["Garlic ahi steak — seared rare with garlic butter, the signature dish","Oxtail soup — rich, fall-off-the-bone, with mustard cabbage","Shoyu pork — tender braised pork belly in sweet shoyu"],parking:"Small lot in front of the strip mall. Gets packed during lunch — arrive by 10:30am.",talkStory:"Run by the same family for decades in an unassuming Kalihi strip mall, Ethel's is where construction workers and off-duty chefs eat side by side at the counter. The garlic ahi — seared rare and swimming in garlic butter — is legitimately one of the best things you can eat on Oahu for under $15. Featured on Guy Fieri's Diners, Drive-Ins and Dives, which caused lines but didn't change the food. Lunch is the move — hot items start rolling at 10am and sell out fast.",cashOnly:false,kamaaina:null},
  {name:"Fête",tier:"S",lat:21.3085,lng:-157.8617,category:"restaurant",subcategory:"fine-dining",tagline:"Hawaii's first James Beard Best Chef winner in 19 years — seasonal New American meets local soul food in a Chinatown bistro.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["carbonara with Portuguese sausage","twice-fried chicken with grits and collard greens","duck fat fries"],parking:"Street parking on Smith/Bethel; paid lots on Maunakea St",talkStory:"Opened 2016 by Chef Robynne Maii — won the James Beard Award for Best Chef Northwest & Pacific in 2022, the first Hawaii-based chef to win the regional award since Alan Wong in 2003. The menu bridges Southern comfort, French technique, and Hawaiian ingredients. Mon–Sat 11am–10pm. Ask for a seat near the open kitchen. Great combined with a Chinatown walk — galleries, Maunakea Marketplace, and Manifest coffee/cocktails all nearby.",cashOnly:false,kamaaina:null},
  {name:"Fook Yuen Seafood Restaurant",tier:"A",lat:21.2862,lng:-157.8233,category:"restaurant",subcategory:"dim-sum",tagline:"Legit dim sum with rolling carts — the har gow and char siu bao are Chinatown quality without the Chinatown parking.",area:"Moiliili",price:"$$",mustOrder:["Har gow — delicate shrimp dumplings with translucent wrappers","Char siu bao — fluffy BBQ pork buns, steamed to order","Siu mai — pork and shrimp dumplings, a dim sum staple"],parking:"Parking lot in the McCully Shopping Center. Usually can find a spot.",talkStory:"Fook Yuen is where Honolulu's Chinese aunties and uncles go for weekend dim sum — the ultimate credibility marker. They still do traditional rolling cart service: flag down the cart ladies and point at what looks good. Operating since the early 1990s in McCully Shopping Center, it's one of the few remaining cart-style dim sum spots on Oahu. Weekend dim sum packs out by 10am; weekday dim sum is the local hack — same food, zero wait. Dinner seafood is solid but dim sum is the event.",cashOnly:false,kamaaina:null},
  {name:"Fort Ruger Market",tier:"A",lat:21.2703,lng:-157.7995,category:"restaurant",subcategory:"plate-lunch",tagline:"Tiny neighborhood deli on a residential side street — Filipino plate lunches with the kind of portions only aunties serve.",area:"Diamond Head",price:"$",mustOrder:["adobo plate — pork or chicken, classic Filipino comfort","lumpia — crispy spring rolls","loco moco — their version is massive"],parking:"Street parking on Alohea Ave; residential neighborhood, usually available",talkStory:"Hidden on residential Alohea Ave near Fort Ruger Park, this corner store evolved into one of Diamond Head's best-kept plate lunch secrets. The Filipino food is cooked from family recipes passed down through generations — pork adobo, lumpia, pinakbet, and dinuguan that taste like someone's lola (grandmother) made them. The same neighborhood regulars come every week. Zero tourist presence, enormous portions, and it closes early afternoon when the food runs out. Mon-Sat only.",cashOnly:false,kamaaina:null},
  {name:"Forty Niner Restaurant",tier:"A",lat:21.386,lng:-157.9384,category:"restaurant",subcategory:"diner",tagline:"Aiea's 50-year-old diner where locals go for banana pancakes, loco moco, and the kind of breakfast that doesn't exist on Instagram.",area:"Aiea",price:"$",mustOrder:["banana pancakes — fluffy, loaded with banana","loco moco — classic diner version","corned beef hash — homemade, not canned"],parking:"Lot in front of the restaurant",talkStory:"A no-frills Aiea diner that's been serving breakfast and lunch since opening in 1973 — over 50 years of banana pancakes, loco moco, and homemade corned beef hash. Three generations of central Oahu families have made this their Saturday morning ritual. The waitresses know regulars by name and start pouring coffee before they sit down. Featured on local 'Best Breakfast' lists for decades. Cash only, no Instagram presence, and nobody is photographing their food here.",cashOnly:true,kamaaina:null},
  {name:"Fujiyama Texas",tier:"A",lat:21.2884,lng:-157.8353,category:"restaurant",subcategory:"izakaya",tagline:"The ultimate late-night salvation — kushi katsu (deep-fried skewers) until 3:30am, perfect for when the clubs close and you need real food.",area:"Moiliili / S. King St",price:"$$",mustOrder:["assorted kushi katsu skewers","ahi poke","mapo tofu"],parking:"Small lot behind restaurant off S. King St; street parking on side streets in Moiliili",talkStory:"A Moiliili institution since the 1980s, Fujiyama Texas was founded by a Japanese chef who fell in love with Texas barbecue — the name itself captures Hawaii's cultural mash-up spirit. The kushi katsu (deep-fried skewers dipped in house sauce) are the real draw, served until 3:30am most nights (closed Tue). The late-night 'Midnight Diner' menu kicks in at 11pm and draws a loyal crowd of service industry workers, insomniacs, and post-bar revelers seeking real food.",cashOnly:false,kamaaina:null},
  {name:"Fumi's Kahuku Shrimp (Ala Moana)",tier:"B",lat:21.2908,lng:-157.8434,category:"restaurant",subcategory:"shrimp",tagline:"The legendary North Shore truck that moved to Ala Moana's Makai Food Court — same garlic butter shrimp recipe, now easier to reach from town.",area:"Ala Moana",price:"$",mustOrder:["Garlic butter shrimp — the signature dish, drenched in buttery garlic sauce","Hot and spicy shrimp — serious heat with great flavor underneath","Shrimp scampi — lighter preparation, still packed with garlic"],parking:"Ala Moana Center parking structure, free for first 4 hours",talkStory:"Fumi's started as one of the original Kahuku shrimp trucks on the North Shore, run by the Robello family who farmed their own shrimp in nearby aquaculture ponds fed by natural mountain spring water. The Ala Moana Makai Food Court location brings that same garlic butter recipe to town without the 45-minute North Shore drive. Order both the garlic shrimp and scampi for comparison, and always ask for extra rice — you'll need it to mop up every drop of that legendary sauce.",cashOnly:false,kamaaina:null},
  {name:"Giovanni's Shrimp Truck",tier:"A",lat:21.6797,lng:-157.953,category:"restaurant",subcategory:"food-truck",tagline:"The OG garlic shrimp truck since 1993 — scrawl your name on the side and join the legend.",area:"Kahuku",price:"$$",mustOrder:["scampi (garlic butter) — the dish that made them famous"],parking:"Gravel parking adjacent",talkStory:"Started in 1993 by Giovanni and Donna Aragon — a white van on the roadside in Kahuku that single-handedly launched the entire North Shore shrimp truck industry. The scampi (garlic butter shrimp) recipe hasn't changed in 30 years and the graffiti-covered truck is now an Oahu landmark. Barack Obama stopped here during a presidential visit. Don't wear a nice shirt — garlic butter splatters are inevitable. Combine with Romy's one mile up the road for the ultimate shrimp showdown.",cashOnly:false,kamaaina:null},
  {name:"Goma Tei Ramen (Ward)",tier:"B",lat:21.2968,lng:-157.8581,category:"restaurant",subcategory:"ramen",tagline:"A local mini-chain that consistently beats out the trendy newcomers — the sesame-rich tonkotsu broth is what keeps Honolulu coming back.",area:"Kakaako / Ward",price:"$$",mustOrder:["Sesame ramen — rich ground sesame broth, the signature bowl that defines this place","Spicy miso ramen — complex broth with layered heat","Gyoza — crispy pan-fried dumplings, perfect starter"],parking:"Ward Centre parking structure, validated with purchase",talkStory:"Goma Tei originated in Sapporo, Japan and brought its signature sesame-based tonkotsu to Honolulu in 2005 — the 'goma' in the name literally means sesame. The ground sesame broth is their proprietary recipe and you genuinely cannot get it anywhere else on the island. Now with multiple Oahu locations, the Ward spot stays packed with locals who consider it their everyday ramen over trendier newcomers. Customize your noodle firmness and spice level at ordering — weekday lunch beats the dinner rush.",cashOnly:false,kamaaina:null},
  {name:"Guava Smoked",tier:"A",lat:21.2756,lng:-157.8136,category:"restaurant",subcategory:"plate-lunch",tagline:"Texas-style BBQ smoked with Hawaiian guava wood — brisket and pulled pork that taste like nowhere else on earth.",area:"Kapahulu",price:"$",mustOrder:["smoked brisket plate","pulled pork — guava wood gives it a subtle sweetness","combo plate to try both"],parking:"Street parking on Kapahulu Ave",talkStory:"Founded by pitmaster Abe Natividad, who perfected the art of smoking meat with locally sourced Hawaiian guava wood — giving the brisket and pulled pork a subtly sweet, floral smoke flavor unlike anything from mesquite or hickory. Started doing pop-ups around Honolulu before landing the Kapahulu brick-and-mortar. The guava wood is harvested on-island, making this a genuinely Hawaii-born BBQ concept you cannot replicate on the mainland. Portions are generous for the price — the combo plate is the move.",cashOnly:false,kamaaina:null},
  {name:"Haili's Hawaiian Food",tier:"A",lat:21.2942,lng:-157.8413,category:"restaurant",subcategory:"hawaiian",tagline:"Family-recipe Hawaiian food since 1950 — laulau, kalua pig, and squid luau that rival Helena's without the hype.",area:"Palama / Kalihi",price:"$",mustOrder:["Laulau — tender pork wrapped in taro and ti leaves, steamed for hours","Kalua pig plate — smoky, salty, fall-apart pulled pork","Squid luau — squid simmered in creamy taro leaf","Haupia for dessert"],parking:"Small lot in front on North King St. Street parking available",talkStory:"Founded in 1950 by the Haili family on North King Street in Palama, this is one of the oldest continuously operating Hawaiian food restaurants on Oahu. The recipes — laulau, kalua pig, squid luau, haupia — are unchanged family originals passed down through generations. Locals consider it the 'no-line alternative' to Helena's, with food that's just as authentic. The neighborhood is deep local Honolulu that tourists never see, which is exactly the point.",cashOnly:false,kamaaina:null},
  {name:"Haleiwa Joe's",tier:"B",lat:21.5793,lng:-158.1035,category:"restaurant",subcategory:"seafood",tagline:"North Shore's sit-down seafood spot with a chill surfer vibe and solid fresh fish plates.",area:"Haleiwa",price:"$$",mustOrder:["Fresh catch of the day — grilled or seared, always local fish","Coconut shrimp — crispy and sweet, a crowd favorite","Joe's salad — mixed greens with macadamia nuts and lilikoi dressing"],parking:"Parking lot at Haleiwa Town Center, right in front of the restaurant.",talkStory:"Opened in 1992 in Haleiwa Town, Haleiwa Joe's became the North Shore's first real sit-down seafood restaurant — before that, your post-surf options were basically food trucks and plate lunch counters. The Haiku Gardens location in Kaneohe eventually closed, making this the sole survivor. Fresh catch is sourced from local harbor boats, and the lilikoi dressing on Joe's salad has a quiet cult following. Sunset on the patio after a North Shore beach day is the move.",cashOnly:false,kamaaina:null},
  {name:"Hank's Haute Dogs",tier:"B",lat:21.2969,lng:-157.8559,category:"restaurant",subcategory:"food-truck",tagline:"Gourmet hot dogs in Kakaako — the lobster dog and Chicago dog are a step above any street cart.",area:"Kakaako",price:"$",mustOrder:["Lobster dog — chunks of lobster on a buttery roll with lemon aioli","Chicago dog — proper Vienna beef, neon relish, sport peppers, the whole deal","Bacon-wrapped dog — crispy bacon-wrapped hot dog with jalapeños"],parking:"Street metered parking on Coral St. SALT at Our Kakaako garage nearby.",talkStory:"Chef Hank Adaniya is a classically trained chef who ran the acclaimed Trio restaurant in Chicago (where Grant Achatz got his start) before moving to Honolulu and opening this gourmet hot dog shop in Kakaako around 2011. The Chicago dog uses authentic Vienna beef with neon relish and sport peppers — the real deal from a guy who grew up on them. The lobster dog with lemon aioli is legit one of the best lunch deals in Kakaako. A pioneer of Honolulu's elevated street food scene.",cashOnly:false,kamaaina:null},
  {name:"Happy Days Chinese Seafood Restaurant",tier:"B",lat:21.2835,lng:-157.8105,category:"restaurant",subcategory:"dim-sum",tagline:"One of the last dim sum spots on Oahu with traditional push-cart service — old-school Cantonese in a Kaimuki strip mall.",area:"Kaimuki",price:"$",mustOrder:["har gow — shrimp dumplings from the cart","sticky rice in lotus leaf — lo mai gai","egg tarts — warm custard in flaky pastry"],parking:"Lot at Waialae Ave strip mall",talkStory:"One of the few remaining dim sum restaurants on Oahu where carts still roll through the dining room — most places have switched to paper menus. The nostalgic atmosphere and traditional cart service make this a throwback to a disappearing style of Chinese dining. Packed on weekends with multigenerational local Chinese families. The food is solid and honest — not reinventing the wheel, just doing classic Cantonese dim sum the old way. If you miss the dim sum cart experience, this is your spot.",cashOnly:false,kamaaina:null},
  {name:"Helena's Hawaiian Food",tier:"S",lat:21.3282,lng:-157.8642,category:"restaurant",subcategory:"hawaiian",tagline:"James Beard Award winner in a Kalihi strip mall — the pipikaula short ribs will ruin you for all other beef.",area:"Kalihi",price:"$$",mustOrder:["Hawaiian plate (pipikaula short ribs, lomi salmon, poi, haupia)"],parking:"Strip mall parking lot on N. School St in Kalihi",talkStory:"Founded in 1946 by Helen 'Helena' Chock in a Kalihi strip mall, Helena's won the James Beard America's Classics Award in 2000 — the only traditional Hawaiian restaurant ever honored and a landmark moment for indigenous cuisine recognition. Now run by her grandson Craig Katsuyoshi, the pipikaula short ribs (Hawaiian-style dried beef) are the signature you cannot skip. Cash only, limited hours (Tue-Fri), and the line moves slow — but this is sacred-level Hawaiian food. Eat poi with two fingers, never one, never a fork.",cashOnly:false,kamaaina:null},
  {name:"Highway Inn Kakaako",tier:"S",lat:21.2964,lng:-157.8568,category:"restaurant",subcategory:"hawaiian",tagline:"Traditional Hawaiian plate lunch since 1947 — the poi, laulau, and pipikaula are as real as it gets.",area:"Kakaako",price:"$$",mustOrder:["Laulau — pork and butterfish wrapped in taro and ti leaves, steamed tender","Pipikaula short ribs — Hawaiian-style dried beef, grilled smoky and chewy","Poi — fresh-pounded, the real deal, order it with your plate"],parking:"Parking lot at SALT at Our Kakaako. Some street parking on Coral St.",talkStory:"Founded in 1947 by Seiichi and Nancy Toguchi on the old Waipahu highway connecting sugar plantation camps — hence the name. Now in its fourth generation under Monica Toguchi, who opened the sleek Kakaako location in SALT while keeping the original Waipahu spot alive. The poi is fresh-pounded, the laulau uses traditional taro and ti leaf wrapping, and the pipikaula is smoky perfection. A James Beard semifinalist, Highway Inn bridges old Hawaiian traditions with a modern setting without compromising the recipes.",cashOnly:false,kamaaina:null},
  {name:"Hihimanu Sushi",tier:"B",lat:21.2862,lng:-157.8247,category:"restaurant",subcategory:"japanese",tagline:"High-end omakase sushi on Waialae — named for the Hawaiian eagle ray, blending island identity with Japanese craft.",area:"Kaimuki",price:"$$$",mustOrder:["omakase — trust the chef's selection","seasonal sashimi — whatever's freshest","the full counter experience"],parking:"Street parking on Waialae Ave",talkStory:"Opened by Chef Jordan Keao on Waialae Ave in Kaimuki, the name 'hihimanu' is Hawaiian for eagle ray — a nod to blending Hawaiian identity with serious Edomae-style sushi craft. This is a $100+ omakase experience in a humble neighborhood setting, not a Waikiki hotel, which is exactly what makes it special. The fish is sourced from local auction and flown in from Tsukiji. Reserve well in advance — only a handful of counter seats. Dinner only, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Himalayan Kitchen",tier:"A",lat:21.2842,lng:-157.8159,category:"restaurant",subcategory:"indian-nepali",tagline:"Kaimuki's beloved Indian and Nepali restaurant — the butter chicken and momos are standouts on an island starved for good South Asian food.",area:"Kaimuki",price:"$",mustOrder:["butter chicken — rich, creamy, perfectly spiced","momos — Nepali-style dumplings, get the jhol sauce","garlic naan — fresh from the tandoor"],parking:"Street parking on Waialae Ave",talkStory:"Run by Nawa Gurung and family, Himalayan Kitchen fills a genuine gap on Oahu — the island has very few quality Indian-Nepali restaurants and this Kaimuki spot delivers the real thing. The momos (Nepali dumplings) with jhol dipping sauce are addictive, the butter chicken rivals mainland standouts, and the garlic naan comes fresh from the tandoor. BYOB-friendly, which locals love. A Kaimuki neighborhood staple since the mid-2010s — closed Tuesdays.",cashOnly:false,kamaaina:null},
  {name:"Honolulu Skewer House",tier:"A",lat:21.2775,lng:-157.815,category:"restaurant",subcategory:"chinese-skewers",tagline:"DIY Chinese skewer grilling on Kapahulu — rotating tabletop machines, lamb skewers, and a late-night vibe unlike anything else on Oahu.",area:"Kapahulu",price:"$$",mustOrder:["lamb skewers — order double, cumin-spiced and smoky","scallop skewers — sweet and charred","enoki mushroom wraps — bacon-wrapped, caramelized"],parking:"Street parking on Kapahulu Ave",talkStory:"A unique concept on Oahu — Chinese-style BBQ skewers that you grill yourself on rotating mechanical skewer machines built into each table. The lamb skewers dusted with cumin and chili are the star — order at least double what you think you need. The vibe is late-night and communal, popular with UH students and young locals. Reservations recommended because the space is small and it fills up fast. Open 5pm-11pm. Nothing else like it on the island.",cashOnly:false,kamaaina:null},
  {name:"HUMU Sandwich & Smoothies",tier:"A",lat:21.3068,lng:-157.8625,category:"restaurant",subcategory:"deli",tagline:"Downtown sandwich shop with a 4.9 Google rating — the Reuben is the best on the island and locals want to keep it secret.",area:"Chinatown / Downtown",price:"$",mustOrder:["Reuben sandwich — consistently called the best on Oahu","bulgogi sub — Korean-meets-deli crossover","smoothies — surprisingly good for a sandwich shop"],parking:"Merchant St metered parking; downtown parking garages",talkStory:"A tiny deli on Merchant Street in Honolulu's financial district with a near-perfect 4.9 Google rating — one of the highest-rated food spots on Oahu. Owner Humu crafts each sandwich by hand, and the Reuben (proper corned beef, sauerkraut, Russian dressing, rye) is consistently called the best on the island. The bulgogi sub is a Korean-meets-deli crossover that shouldn't work but absolutely does. Weekday lunch hours only, primarily feeding downtown office workers who guard this spot like a secret.",cashOnly:false,kamaaina:null},
  {name:"Izakaya Nonbei",tier:"A",lat:21.2753,lng:-157.8121,category:"restaurant",subcategory:"japanese",tagline:"Intimate Tokyo-style izakaya tucked on a side street — the bartender knows your name by the second visit.",area:"Kapahulu",price:"$$",mustOrder:["yakitori — grilled over charcoal, proper izakaya style","sashimi platter — whatever's fresh","agedashi tofu — crispy and silky"],parking:"Street parking on Olu St and Kapahulu side streets",talkStory:"Run by a Japanese chef-owner on tiny Olu Street off Kapahulu, Nonbei (meaning 'drinker' in Japanese) is the intimate, refined counterpart to Honolulu's louder izakayas. The small counter-bar setting genuinely feels like stumbling into a side-street joint in Tokyo's Shinjuku. Charcoal-grilled yakitori, pristine sashimi, and a sake list curated by someone who cares. The crowd is mostly local Japanese-American regulars and expats who know the real thing. Dinner only, reservations strongly recommended.",cashOnly:false,kamaaina:null},
  {name:"J. Dolan's",tier:"B",lat:21.2835,lng:-157.8168,category:"restaurant",subcategory:"pizza",tagline:"New York-style pizza and craft beer in Kaimuki — often cited as the best slice on the island.",area:"Kaimuki",price:"$$",mustOrder:["pepperoni pizza — classic NY style, perfectly charred","craft beer selection — rotating taps worth exploring","garlic knots — if available"],parking:"Street parking on Waialae Ave; Kahala Mall lot nearby",talkStory:"Named after owner John Dolan, who opened this Kaimuki pizza-and-beer joint around 2014 on Waialae Ave. The hand-tossed New York-style pies have a proper thin crust with good char, and the rotating craft beer taps make it Kaimuki's go-to casual night out. Dolan also runs the Irish pub J. Dolan's on Bethel Street downtown — same name, different vibe. If Brick Fire Tavern is Kaimuki's artisan wood-fired option, Dolan's is the grab-a-slice-and-a-pint neighborhood counterpart. Late night friendly.",cashOnly:false,kamaaina:null},
  {name:"Kahuku Superette",tier:"A",lat:21.68,lng:-157.9501,category:"restaurant",subcategory:"poke",tagline:"A five-generation family recipe in a tiny convenience store on the North Shore — the shoyu poke here will ruin you for all others.",area:"Kahuku / North Shore",price:"$",mustOrder:["Shoyu ahi poke bowl — five-generation family recipe, the reason this place exists","Spicy ahi poke — creamy-spicy with fresh ahi","Plate lunch specials — surprisingly solid comfort food from a convenience store"],parking:"Small gravel lot right in front of the store",talkStory:"A five-generation family-owned country store in Kahuku town — the Tanioka family has been making poke here with the same recipe since the plantation era, making it one of the oldest continuously family-made poke preparations on Oahu. It looks like a convenience store because it is one, but the poke counter in the back is the real reason people drive out here. The shoyu ahi poke is the signature — simple, clean, and perfect. Go before noon on weekends because it sells out. Pair with a Kahuku shrimp truck stop nearby.",cashOnly:false,kamaaina:null},
  {name:"Kahumana Farm Cafe",tier:"A",lat:21.447,lng:-158.146,category:"restaurant",subcategory:"farm-to-table",tagline:"A farm-to-table cafe hidden deep in the Waianae Valley, serving food harvested from the surrounding organic gardens.",area:"Waianae",price:"$$",mustOrder:["farm salad","grain bowl","fresh-baked pastry"],parking:"Free lot on the farm property",talkStory:"Kahumana Organic Farm and Cafe is a nonprofit founded in 1974 as a therapeutic community in the back of Waianae Valley. The cafe serves lunch made with ingredients literally harvested that morning from the surrounding 30-acre organic farm. It also functions as transitional housing and job training for adults with developmental disabilities and those experiencing homelessness. The setting — surrounded by Waianae mountains and farmland — feels like another island entirely. Open Wed-Sat for lunch; call ahead to confirm.",cashOnly:false,kamaaina:null},
  {name:"Kaimuki Shokudo",tier:"B",lat:21.2846,lng:-157.8148,category:"restaurant",subcategory:"late-night",tagline:"Izakaya menu that actually runs late — Kaimuki residents' answer to where to eat at 11pm on a Saturday.",area:"Kaimuki",price:"$$",mustOrder:["Garlic fried chicken — crispy, juicy, and perfect with a beer","Pork belly bao buns — rich and savory late-night fuel","Shoyu ramen — solid bowl to close out the night"],parking:"Street parking on Waialae Ave, side streets have more options",talkStory:"Part of the Kaimuki dining renaissance on Waialae Ave, Shokudo brought a modern izakaya concept with late-night hours the neighborhood desperately needed. Open until midnight on weeknights and 1am on weekends — one of the few quality spots on Oahu serving food past 10pm. The garlic fried chicken and pork belly bao are designed for sharing over drinks. The late-night happy hour deals draw UH students and Kaimuki regulars. Sit at the bar for faster service and better people-watching.",cashOnly:false,kamaaina:null},
  {name:"Kalapawai Cafe",tier:"A",lat:21.3924,lng:-157.7349,category:"restaurant",subcategory:"cafe",tagline:"Kailua's neighborhood anchor since 1932 — sunrise coffee to dinner wine, go every day and never get bored.",area:"Kailua",price:"$$",mustOrder:["Kailua Club","Hot Pastrami","Bacon Wrapped Figs","Fish Tacos"],parking:"Small lot behind cafe on Kailua Rd; additional street parking on surrounding blocks",talkStory:"The Kalapawai brand dates back to 1932 as a plantation-era corner store in Kailua — the name comes from the Hawaiian word for the area near Kalapawai Beach. The modern cafe at 750 Kailua Road is the flagship, run by the Becker family with a focus on locally sourced ingredients and a wine program featuring small family-owned wineries. The Kailua Club sandwich and bacon-wrapped figs are local favorites. Open breakfast through dinner, making it Kailua's all-day neighborhood anchor.",cashOnly:false,kamaaina:null},
  {name:"Kapa Hale",tier:"A",lat:21.275,lng:-157.8051,category:"restaurant",subcategory:"fine-dining",tagline:"James Beard semifinalist in Kaimuki — hyper-seasonal Hawaiian ingredients in a cozy neighborhood room.",area:"Kaimuki",price:"$$$",mustOrder:["seasonal tasting menu"],parking:"Street parking on Waialae Ave and Kaimuki side streets (9th-12th Ave)",talkStory:"Chef Kevin Lee earned James Beard semifinalist nods for Best Chef Northwest & Pacific with this intimate Kaimuki tasting-menu restaurant. The hyper-seasonal approach means the menu changes constantly based on what Hawaiian farmers and fishermen bring in that week — taro, pohole fern, local reef fish, Waianae greens. The tiny dining room feels like eating at a friend's house, and sitting near the open kitchen lets you watch the meticulous plating. Reservations essential — this is Kaimuki fine dining done with aloha, not pretension.",cashOnly:false,kamaaina:null},
  {name:"Ken's Fresh Fish",tier:"A",lat:21.6452,lng:-157.9236,category:"restaurant",subcategory:"seafood",tagline:"Takeout-only, tiny, and almost impossible to find — the ahi katsu here is possibly the single best dish on the entire North Shore.",area:"Laie / North Shore",price:"$",mustOrder:["Ahi katsu — panko-crusted seared ahi, rare inside, possibly the best thing on the North Shore","Fresh poke — made daily from locally caught fish","Marlin tacos — unique preparation you won't find anywhere else"],parking:"Small gravel lot next to the shop",talkStory:"Ken Higa is a working fisherman in Laie who started selling his daily catch directly to the community from a tiny takeout window — word spread through the North Shore surf network and now people drive from town for his ahi katsu. The panko-crusted seared ahi (rare inside) is arguably the single best prepared fish dish on the North Shore. Menu changes daily based on what Ken caught that morning. Open only Tue/Wed/Fri/Sat with limited hours — call ahead to check if they're open. No seating, takeout only, and once it's gone, it's gone.",cashOnly:false,kamaaina:null},
  {name:"Keneke's Grill",tier:"A",lat:21.3467,lng:-157.7139,category:"restaurant",subcategory:"plate-lunch",tagline:"Waimanalo's go-to plate lunch spot — kalua pig, laulau, and honest Hawaiian food steps from the best beach on the island.",area:"Waimanalo",price:"$",mustOrder:["kalua pig plate — smoky, tender, classic","laulau — pork and butterfish wrapped in taro leaf","spam musubi — grab one for the beach"],parking:"Small lot off Kalanianaole Hwy",talkStory:"The heart of Waimanalo's food scene — Keneke's has been the community plate lunch stop for decades, feeding construction crews, beach families, and mailmen alike from a no-frills counter off Kalanianaole Highway. The kalua pig and laulau are done in the traditional Hawaiian style, portions are generous, and prices stay local-friendly. Grab a plate before or after Waimanalo Beach (often called the best beach on Oahu) — spam musubi travels well for the sand. Not gourmet, just honest everyday Hawaiian food.",cashOnly:false,kamaaina:null},
  {name:"Khan Skewer Restaurant",tier:"A",lat:21.2918,lng:-157.8362,category:"restaurant",subcategory:"chinese",tagline:"Xinjiang-style lamb skewers heavy on cumin and charcoal — the only spot on Oahu doing this regional Chinese BBQ right.",area:"McCully / Mōʻiliʻili",price:"$$",mustOrder:["lamb skewers — cumin-crusted, charcoal-grilled, the signature","hand-pulled noodles","cold dishes — cucumber salad, wood ear mushroom"],parking:"Street parking on Isenberg St; side streets toward University",talkStory:"The only authentic Xinjiang-style BBQ restaurant on Oahu, tucked on Isenberg Street near UH Manoa with zero tourist foot traffic. The lamb skewers are cumin-crusted and charcoal-grilled in the Northwest Chinese tradition — the same style you'd find at night markets in Urumqi or Xi'an. The clientele is overwhelmingly local Chinese and Asian community who know exactly what this food should taste like. Hand-pulled noodles and cold cucumber salad round out the order. Open for dinner, closed Tuesdays.",cashOnly:false,kamaaina:null},
  {name:"Koa Pancake House",tier:"B",lat:21.3942,lng:-157.8001,category:"restaurant",subcategory:"breakfast",tagline:"Old-school Kaneohe breakfast spot where retirees, surfers, and families all converge over macadamia nut pancakes.",area:"Kaneohe",price:"$",mustOrder:["Macadamia nut pancakes — fluffy stacks topped with mac nut syrup","Portuguese sausage, eggs, and rice — the local breakfast standard","Dutch baby pancake — puffy oven-baked pancake with powdered sugar and lemon"],parking:"Windward Mall parking lot. Plenty of spaces.",talkStory:"A Windward Side breakfast institution inside Windward Mall in Kaneohe — don't let the mall food court location fool you. The macadamia nut pancakes with mac nut syrup are legendary among Kaneohe locals, and the Dutch baby (puffy oven-baked pancake with powdered sugar and lemon) is the insider order. The crowd is mostly retirees, surfers, and local families who've been coming for years. Opens early, closes mid-afternoon. If you're heading to Kaneohe or the Windward coast, this is the breakfast move.",cashOnly:false,kamaaina:null},
  {name:"Koko Head Cafe",tier:"A",lat:21.2814,lng:-157.7996,category:"restaurant",subcategory:"breakfast",tagline:"Lee Anne Wong's brunch spot — Cornflake French Toast and kimchi fried rice are mandatory.",area:"Kaimuki",price:"$$",mustOrder:["Cornflake French Toast ($16–18, battered in cornflake cereal — cult following)","breakfast bibimbap ($17–19)"],parking:"Park on Kaimuki side streets (12th Ave, Harding Ave)",talkStory:"Opened in 2014 by Chef Lee Anne Wong — Top Chef Season 1 alum and multiple James Beard nominee — who left New York's fine dining world to build a life in Hawaii. The Cornflake French Toast (battered in crushed cereal) has a cult following, and the breakfast bibimbap fuses Korean and local flavors perfectly. Wong also opened Papa Kurt's smash burger spot nearby. No reservations — walk-in waitlist only. The move: weekday mornings right at 7am opening for zero wait, then walk Waialae Ave for Kaimuki's boutiques.",cashOnly:false,kamaaina:null},
  {name:"Kona Brewing Co. Hawaii Kai",tier:"B",lat:21.2891,lng:-157.7075,category:"restaurant",subcategory:"seafood",tagline:"Hawaii Kai's waterfront brewpub — solid food, great beer, and sunset views over the marina.",area:"Hawaii Kai",price:"$$",mustOrder:["Longboard Lager or Big Wave on tap — always better on draft at the source","Kona Brewing pizza — wood-fired, crispy, better than expected","Poke nachos — ahi poke on won ton chips, great pupu"],parking:"Koko Marina Center parking lot. Plenty of spaces.",talkStory:"Kona Brewing Company was founded in 1998 on the Big Island by father-son duo Cameron Healy and Spoon Khalsa. The Hawaii Kai brewpub in Koko Marina Center is their Oahu flagship and the beer is always fresher here on draft than anywhere else. The marina-side patio is perfect for sunset beers after a Hanauma Bay or Koko Head hike day. The wood-fired pizza is better than expected for a brewpub, and the poke nachos (ahi on won ton chips) are the best pupu on the menu. Good family spot.",cashOnly:false,kamaaina:null},
  {name:"Legend Seafood Restaurant",tier:"A",lat:21.3128,lng:-157.8615,category:"restaurant",subcategory:"dim-sum",tagline:"Chinatown's classic dim sum hall — cart service, Hong Kong Cantonese seafood, and a packed dining room that hasn't slowed down since 1990.",area:"Chinatown / Downtown",price:"$$",mustOrder:["har gow — crystal shrimp dumplings, the dim sum benchmark","char siu bao — fluffy steamed BBQ pork buns","salt and pepper shrimp — crispy and addictive"],parking:"Chinatown Cultural Plaza parking garage",talkStory:"Inside the Chinatown Cultural Plaza since 1990, Legend is the anchor dim sum destination in Honolulu. Traditional cart service rolls through the packed dining room — point at what you want as it passes. The har gow and siu mai are textbook, and the seafood dinners at night are excellent. Weekend dim sum is a zoo — arrive before 10am or expect a wait. The crowd is overwhelmingly local Chinese and Filipino families, which tells you everything. Dim sum daily until 2pm, dinner nightly.",cashOnly:false,kamaaina:null},
  {name:"Like Like Drive Inn",tier:"B",lat:21.2966,lng:-157.8363,category:"restaurant",subcategory:"local-grinds",tagline:"A 24-hour diner serving old-school Hawaiian comfort food since 1953 — oxtail soup, pancakes, and loco moco at 3am.",area:"Kalihi",price:"$",mustOrder:["oxtail soup","pancakes","loco moco"],parking:"Free lot",talkStory:"Pronounced 'lee-keh lee-keh' (named after nearby Likelike Highway, which honors Princess Miriam Likelike, sister of King Kalakaua), this 24-hour diner has been feeding Honolulu since 1953. The oxtail soup with ginger and star anise is the signature — locals debate whether it rivals Asahi Grill's version. The pancakes are old-school fluffy, and the loco moco hits different at 3am. After-bar crowds, night-shift workers, and early-morning fishermen all converge in vinyl booths and Formica tables that haven't changed in decades.",cashOnly:false,kamaaina:null},
  {name:"Livestock Tavern",tier:"A",lat:21.3107,lng:-157.8618,category:"restaurant",subcategory:"new-american",tagline:"Chinatown's rustic-chic dinner spot — seasonal farm-to-table dishes, killer cocktails, and a vibe that straddles casual and refined.",area:"Chinatown / Downtown",price:"$$",mustOrder:["bone marrow — a signature starter","seasonal pasta — changes with what's local","craft cocktails — the bar program is legit"],parking:"Street parking on Bethel St; nearby paid lots",talkStory:"Opened in 2013 by chef Jesse Cruz and Dusty Grable in a former Chinatown warehouse, helping ignite the neighborhood's dining renaissance. Cruz, a Culinary Institute of America grad, changes the menu weekly based on what local farms deliver. Won multiple Hale 'Aina awards for Best New Restaurant and Best Farm-to-Table. The bone marrow appetizer has been on since day one because regulars refuse to let it go. The cocktail program uses house-made syrups and local citrus.",cashOnly:false,kamaaina:null},
  {name:"Lucky Belly",tier:"A",lat:21.3108,lng:-157.8614,category:"restaurant",subcategory:"ramen",tagline:"Chinatown's modern ramen and small-plates spot — the belly bowl is a tonkotsu-style revelation with pork belly and a poached egg.",area:"Chinatown / Downtown",price:"$$",mustOrder:["belly bowl — rich pork broth, pork belly, poached egg","pork belly bao — perfectly steamed","seasonal small plates — Asian-fusion creativity"],parking:"Street parking on Hotel St; paid lots nearby",talkStory:"Opened in 2012 by Jesse Cruz and Dusty Grable — the same duo behind Livestock Tavern next door. Chef Kris Kitazaki runs the kitchen, turning out a belly bowl with 18-hour pork bone broth that became an instant Honolulu icon. The pork belly bao started as a special and became permanent after customer demand. Part of the trio (with Livestock and Tchin Tchin bar) that anchored Chinatown's food revival on Hotel Street. The small plates rotate seasonally and often outshine the ramen.",cashOnly:false,kamaaina:null},
  {name:"Maria Bonita Restaurant",tier:"A",lat:21.3097,lng:-157.8614,category:"restaurant",subcategory:"mexican",tagline:"28-year Chinatown Mexican institution — BYOB, no AC, just fans and the Mexican flag on the walls. The wet chile verde burrito is legendary.",area:"Chinatown / Downtown",price:"$",mustOrder:["wet chile verde burrito — smothered in green sauce, the signature","ahi burrito — Hawaiian-Mexican fusion done right","combo plate — try multiple things"],parking:"Street parking on Hotel St; paid lots on Maunakea St",talkStory:"Owner Diego Giusti, originally from Mexico City, started slinging burritos from a lunch wagon in Waimanalo around 1998 and named the restaurant after his mother. The Chinatown storefront has ceiling fans instead of AC and a Mexican flag on the wall — Diego says it keeps things real. BYOB with no corkage is the move: regulars bring six-packs of Modelo. The wet chile verde burrito, smothered in tangy green sauce, has been the signature for over 25 years. Portions are enormous — one burrito genuinely feeds two.",cashOnly:false,kamaaina:null},
  {name:"Marugame Udon",tier:"A",lat:21.2793,lng:-157.8282,category:"restaurant",subcategory:"noodles",tagline:"Locals genuinely love it despite the Waikiki address — watch them pull fresh noodles through the glass.",area:"Waikiki",price:"$",mustOrder:["kamaage udon ($5–7, the purist's choice — plain dipping noodles, taste the quality)","nikutama ($8–10, beef + egg)"],parking:"Don't drive — no parking in Waikiki",talkStory:"Part of Japan's Toridoll Holdings chain (800+ locations worldwide), the Waikiki outpost opened in 2011 and immediately drew lines around the block — it's been that way for over a decade. Modeled after Kagawa Prefecture's self-serve sanuki udon shops where you watch noodles being hand-pulled through glass. The cafeteria format (grab tray, choose udon, pick tempura, pay) keeps bills under $10, making it Waikiki's best food value. Barack Obama was spotted here during holiday visits.",cashOnly:false,kamaaina:null},
  {name:"Maui Mike's Fire-Roasted Chicken",tier:"A",lat:21.5023,lng:-158.0186,category:"restaurant",subcategory:"chicken",tagline:"Wahiawa's fire-roasted chicken joint — smoky, juicy birds cooked over kiawe wood that people drive across the island for.",area:"Wahiawa",price:"$",mustOrder:["half chicken plate — kiawe-smoked, impossibly juicy","garlic rice — the perfect sidekick","corn on the cob — charred and buttery"],parking:"Small lot on California Ave",talkStory:"Founded by Mike Nishida (not from Maui — the name is a play on words) in Wahiawa around 2000, cooking whole chickens over kiawe wood in a custom rotisserie. Kiawe is Hawaii's mesquite, giving the birds a sweet, smoky flavor you can't replicate with gas or charcoal. Military families from nearby Schofield Barracks helped build the early following. Featured on local TV and won 'Best Chicken' in multiple Honolulu Magazine polls. The garlic rice recipe is a closely guarded secret.",cashOnly:false,kamaaina:null},
  {name:"Max & Lucy's",tier:"A",lat:21.2989,lng:-157.8567,category:"restaurant",subcategory:"plate-lunch",tagline:"The chef is also your server — weekday-only, sells out daily, and the lemon bars are famous.",area:"Kakaako",price:"$",mustOrder:["kalbi ribs — the go-to plate","prime rib — when available, don't hesitate","lemon bars — famous for a reason, grab one before they're gone"],parking:"Street parking on Halekauwila St; Kakaako side streets",talkStory:"Run by Max and Lucy Bolosan — Max cooks everything himself and then personally walks each plate to your table. Named after the couple, operating from a tiny Kakaako kitchen since the mid-2000s, Mon-Fri 5am-2pm only. The lemon bars became so famous that people order trays for office parties island-wide. Max sources kalbi from a specific local supplier and marinates overnight. There's no website, no social media push — just three decades of Kakaako construction workers and office employees spreading the word.",cashOnly:false,kamaaina:null},
  {name:"Mei Sum Dim Sum",tier:"A",lat:21.3112,lng:-157.8598,category:"restaurant",subcategory:"dim-sum",tagline:"A Chinatown dim sum staple for over 20 years — 150+ Cantonese dishes, cart service, and a Honolulu Magazine reader favorite.",area:"Chinatown / Downtown",price:"$",mustOrder:["siu mai — the classic pork and shrimp dumpling","cheung fun — silky rice noodle rolls","egg tarts — flaky, custard-filled, warm from the cart"],parking:"Metered street parking on Nu'uanu Ave; nearby lots",talkStory:"One of Chinatown's most reliable dim sum spots, voted a top pick in Honolulu Magazine's reader poll. Over 150 Cantonese dishes on the menu, with dim sum carts rolling from 10am to 2pm daily. The space is no-frills and the pace is fast — this is working-class Chinatown dim sum, not a polished brunch experience. Prices are remarkably low for the quality. If Legend is the bigger, flashier dim sum hall, Mei Sum is the neighborhood regular's choice. Cash preferred.",cashOnly:true,kamaaina:null},
  {name:"Mian & Bao",tier:"A",lat:21.2938,lng:-157.8545,category:"restaurant",subcategory:"shanghai-sichuan",tagline:"Soup dumplings and Sichuan noodles at Ward Village — James Beard semi-finalist Chef Tony Xu bridges Shanghai and Chengdu.",area:"Kakaako",price:"$$",mustOrder:["xiao long bao — soup dumplings, the star of the menu","sheng jian bao — pan-fried pork buns with crispy bottoms","chili oil wontons — numbing, spicy, addictive"],parking:"Ward Village parking",talkStory:"Chef Tony Xu (James Beard semi-finalist) brings serious Shanghai and Sichuan cooking to Ward Village. The xiao long bao are the draw — delicate wrappers filled with hot soup and pork. The sheng jian bao (pan-fried buns) have a crispy bottom that shatters into soupy filling. Also offers a daily yum cha dim sum tea service. If you've been to Din Tai Fung on the mainland and wished Honolulu had something comparable, this is your spot. Lunch and dinner.",cashOnly:false,kamaaina:null},
  {name:"Mitch's Fish Market & Sushi Bar",tier:"B",lat:21.3339,lng:-157.908,category:"restaurant",subcategory:"seafood",tagline:"Fresh-off-the-boat seafood right next to the fishing pier — sashimi doesn't get more local than this.",area:"Honolulu Fish Auction",price:"$$",mustOrder:["Sashimi platter — whatever's freshest that day, caught that morning","Garlic shrimp — simple and garlicky, local style","Poke bowl — fresh ahi, rice, and furikake"],parking:"Parking lot at Pier 38. Easy to find, usually has spots.",talkStory:"Run by Mitch Arakawa since the 1990s in an unassuming Kaimuki strip mall on Harding Ave. Mitch hand-selects fish daily from the Honolulu Fish Auction at pier 38, one of the only places in the US where tuna is still auctioned Japanese-style. The sashimi is auction-fresh and priced well below Waikiki omakase spots. Regulars sit at the counter and let Mitch choose — the unofficial omakase. A true neighborhood sushi bar where the chef knows every regular by name.",cashOnly:false,kamaaina:null},
  {name:"Moke's Bread & Breakfast",tier:"C",lat:21.3958,lng:-157.7466,category:"restaurant",subcategory:"cafe",tagline:"Famous for lilikoi pancakes, but the coffee is no afterthought here.",area:"Kailua",price:"$$",mustOrder:["house coffee with lilikoi pancakes — the full experience","iced coffee — strong, you'll need it for the wait"],parking:"Street parking on Kailua Rd or public lot on Hahani St",talkStory:"Yeah, Moke's is known for breakfast, but they brew solid coffee and you're gonna be here anyway for those lilikoi pancakes. The line can be 30-45 minutes on weekends — come at 7am or accept your fate. Named after the family dog. The vibe is pure local breakfast spot energy. If the Kailua location is packed, they have one in Honolulu too.",cashOnly:false,kamaaina:null},
  {name:"Mud Hen Water",tier:"A",lat:21.2826,lng:-157.8128,category:"restaurant",subcategory:"hawaiian",tagline:"Modern Hawaiian cuisine in Kaimuki that showcases native ingredients — Ed Kenney's love letter to the land.",area:"Kaimuki",price:"$$",mustOrder:["Poi sourdough bread — tangy, purple-tinged, baked fresh daily","Kalo (taro) nachos — local twist on nachos with taro chips and kalua pork","Seasonal fish — always fresh, prepared with native Hawaiian flavors"],parking:"Street parking on Waialae Ave or side streets. Kaimuki parking can be tough on weekends — go early.",talkStory:"Chef Ed Kenney opened Mud Hen Water in 2014 as a love letter to native Hawaiian ingredients — the name is the literal English translation of 'Waikiki' (wai=water, kiki=spouting, but the area was historically known for mud hen habitat). Kenney, also behind Town restaurant, was a James Beard semifinalist and advocates a 'local first, organic whenever possible' sourcing philosophy. The poi sourdough bread uses real poi from Waiahole Valley taro farmers. A key voice in Hawaii's food sovereignty movement.",cashOnly:false,kamaaina:null},
  {name:"MW Restaurant",tier:"A",lat:21.2925,lng:-157.8515,category:"restaurant",subcategory:"fine-dining",tagline:"Chef Wade Ueoka's elevated take on local comfort food — the ahi cake and foie gras loco moco are iconic Honolulu dishes.",area:"Kakaako",price:"$$$",mustOrder:["ahi cake","foie gras loco moco","fried kalo"],parking:"Validated parking in building garage",talkStory:"Husband-and-wife team Chef Wade Ueoka and pastry chef Michelle Karr-Ueoka opened MW in 2013 after both spent years at Alan Wong's flagship. Wade's ahi cake — layers of seared ahi, avocado, and wontons — won 'Best Dish' at multiple Hale 'Aina awards. Michelle, who also does Senia's pastry program, trained at Thomas Keller's Per Se and French Laundry. The foie gras loco moco is a $30 riff on a $5 plate-lunch staple that somehow works perfectly. James Beard semifinalists.",cashOnly:false,kamaaina:null},
  {name:"New Char Siu House",tier:"A",lat:21.313,lng:-157.8638,category:"restaurant",subcategory:"chinese-bbq",tagline:"Chinatown's takeout-only roast meat institution — 4.6 stars, legendary char siu and roast duck, sold out by afternoon.",area:"Chinatown / Downtown",price:"$",mustOrder:["roast duck — crispy skin, succulent meat","char siu — glistening, caramelized pork","roast pork belly — crackling perfection"],parking:"Metered street parking on Maunakea St",talkStory:"A Chinatown institution on Maunakea St — takeout only, no seats, just a glass case of glistening roast meats and a line out the door. The char siu is deeply caramelized with that perfect balance of sweet and savory. The roast duck rivals Roast Duck Kitchen in Aiea. Opens early (7:30am) and popular items sell out by early afternoon. Point at what you want, it gets chopped and bagged. This is how Chinatown has operated for generations. Cash only.",cashOnly:true,kamaaina:null},
  {name:"No Name Sandwich",tier:"B",lat:21.2836,lng:-157.8196,category:"restaurant",subcategory:"vietnamese",tagline:"Word-of-mouth banh mi shop on Waialae — the name tells you everything about the vibe.",area:"Kaimuki",price:"$",mustOrder:["classic banh mi — proper baguette, pickled veg, cilantro, jalapeño","grilled pork banh mi","try whatever daily special is on the board"],parking:"Street parking on Waialae Ave",talkStory:"A Kaimuki banh mi shop that literally has no name on its original signage — regulars just called it 'that sandwich place on Waialae.' Run by a Vietnamese family since the early 2010s, the baguettes are baked fresh and the classic banh mi with pate, pickled daikon, and cilantro rivals anything in Chinatown at half the wait. The prices have barely moved in a decade. The daily specials board is handwritten and often features items not on the regular menu — ask what's fresh.",cashOnly:false,kamaaina:null},
  {name:"O'Kims",tier:"A",lat:21.3118,lng:-157.8601,category:"restaurant",subcategory:"korean",tagline:"Korean fusion with French and Japanese technique — Yelp's #58 US restaurant in 2024. Truffle mandoo that'll rewire your brain.",area:"Chinatown / Downtown",price:"$$",mustOrder:["truffle mandoo — Korean dumplings elevated with truffle","kalbi short ribs — the classic, perfectly executed","black sesame cake — don't skip dessert"],parking:"Street parking on Nuuanu Ave; paid lots on Smith/Maunakea St",talkStory:"Chef Hyun Kim fuses Korean home cooking with French and Japanese technique — trained in fine dining before opening this intimate Chinatown spot around 2019. The truffle mandoo (Korean dumplings with black truffle) became a viral sensation and put the restaurant on Yelp's Top 100 US Restaurants list at #58 in 2024. Family-run with Hyun's wife managing front of house. Extensive vegan menu including house-made vegan kimchi. A genuinely original voice in Honolulu dining.",cashOnly:false,kamaaina:null},
  {name:"Olive Tree Cafe",tier:"A",lat:21.2757,lng:-157.7954,category:"restaurant",subcategory:"mediterranean",tagline:"The only legit Greek food on Oahu — cash only, BYOB, counter service, and a 20-year local cult following.",area:"Kahala",price:"$",mustOrder:["souvlaki plate — chicken or lamb, both excellent","falafel — crispy outside, fluffy inside","fresh fish special — ask what's available"],parking:"Small lot on Kilauea Ave; street parking on side streets",talkStory:"Opened in the late 1990s by Savas Mojarrad, an Iranian-born chef who brought Mediterranean flavors to Kahala. Over 25 years later, it remains the only dedicated Greek restaurant on Oahu. Cash only, BYOB with no corkage, counter service — the format hasn't changed because regulars won't let it. The fresh fish specials use whatever is best at the Honolulu Fish Auction that morning. Zagat-rated and consistently voted Honolulu's best Mediterranean. Located next to Kapa Hale, making a two-stop dinner easy.",cashOnly:true,kamaaina:null},
  {name:"Omakase By Aung",tier:"A",lat:21.2756,lng:-157.8135,category:"restaurant",subcategory:"fine-dining",tagline:"Burmese-Japanese chef, 8 seats, no menu — just trust and exceptional fish.",area:"Kapahulu",price:"$$$",mustOrder:["omakase — there is no menu, the chef decides based on what's fresh"],parking:"Street parking on Kapahulu Ave; side streets off Winam Ave",talkStory:"Chef Aung Thein Hlaing, born in Myanmar and trained in Tokyo, opened this 8-seat Kapahulu counter around 2021. His edomae-style sushi incorporates Burmese spice knowledge — subtle heat and fermented flavors that differentiate his nigiri from traditional Japanese preparation. Fish sourced daily from Honolulu Fish Auction. The intimate format means direct chef-diner conversation throughout the 15-20 course meal ($150-250). No signage outside — you have to know the address. Book via Instagram DM weeks ahead.",cashOnly:false,kamaaina:null},
  {name:"Ono Seafood",tier:"S",lat:21.2811,lng:-157.8139,category:"restaurant",subcategory:"poke",tagline:"Made-to-order poke that locals will wait 30 minutes for — the shoyu ahi is non-negotiable.",area:"Kapahulu",price:"$",mustOrder:["shoyu ahi ($14–16)","spicy ahi"],parking:"Only 5–6 parking spots behind shop; park on side streets off Kapahulu",talkStory:"Founded by the Ono family in 1995 on Kapahulu Ave — 'ono' means 'delicious' in Hawaiian, and the name delivers. They cut and season fish to order, never pre-mixed, using a shoyu-sesame marinade recipe that hasn't changed in nearly 30 years. Featured on countless 'Best Poke' lists including Travel Channel, Food Network, and Bon Appetit. The tiny shop has no seating — the local move is to walk your bowl to Kapiolani Park for a Diamond Head view picnic. Sells out by early afternoon most days.",cashOnly:false,kamaaina:null},
  {name:"Over Easy",tier:"B",lat:21.3951,lng:-157.7427,category:"restaurant",subcategory:"breakfast",tagline:"Kailua locals' go-to morning spot — no-fuss, no-gimmick breakfast done exceptionally well with a relaxed neighborhood vibe.",area:"Kailua Town",price:"$",mustOrder:["Brunch Bowl — rice, eggs, protein, and veggies all in one perfect bowl","Loco moco — classic Hawaii comfort breakfast done right","Seasonal specials — always worth asking about, changes frequently"],parking:"Street parking on Kailua Rd and side streets, small lot nearby",talkStory:"Opened around 2014 by husband-and-wife team Ryan and Erica Arakaki in downtown Kailua. Ryan, a former line cook at several Honolulu restaurants, wanted a simple breakfast spot using local eggs and produce. The brunch bowl — rice, eggs, local greens, and choice of protein — became the Windward side's signature breakfast. Named one of Honolulu Magazine's best breakfast spots. The relaxed vibe matches Kailua's surf-town energy. Weekday mornings are mellow; weekends pack out by 8:30am — call ahead for the waitlist.",cashOnly:false,kamaaina:null},
  {name:"Pai Honolulu",tier:"C",lat:21.3059,lng:-157.8632,category:"restaurant",subcategory:"fine-dining",tagline:"Hidden courtyard fine dining near Aloha Tower — chef-owned, locally sourced, and genuinely hard to find unless someone tells you.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["seasonal tasting menu — changes regularly based on local sourcing","a la carte dishes — everything is made in-house","ask chef Kevin Lee what's best that night"],parking:"Harbor Court parking; street parking on Merchant St",talkStory:"Chef Kevin Lee opened Pai in 2017, tucked in Harbor Court near Aloha Tower — the hidden courtyard entrance is intentionally hard to find. Lee, who trained under Mavro and other top Honolulu chefs, changes the tasting menu weekly based on what small Hawaiian farms deliver. The name 'Pai' references the Hawaiian concept of eating communally. Everything from pasta to bread to charcuterie is made in-house. One of Honolulu's most under-the-radar fine dining spots — no Instagram hype, just craft.",cashOnly:false,kamaaina:null},
  {name:"Palace Saimin",tier:"S",lat:21.3283,lng:-157.8542,category:"restaurant",subcategory:"hawaiian",tagline:"Hand-wrapped won tons since 1946 — if this place closes, Honolulu loses its soul.",area:"Kalihi",price:"$",mustOrder:["won ton min ($9–12, hand-wrapped won tons in pork-shrimp broth)","teriyaki beef sticks ($2–4 each — NON-NEGOTIABLE side order)"],parking:"Small lot next to the building on King Street",talkStory:"Family-run since 1946. Saimin is Hawaii's own noodle soup — evolved on sugar plantations where Japanese, Chinese, Filipino, and Portuguese workers shared ingredients. Open Tue–Fri 10am–8pm, Sat 10am–3pm. Closed Sun and Mon. Combine with Helena's (also in Kalihi) for a full local food pilgrimage.",cashOnly:true,kamaaina:null},
  {name:"Pioneer Saloon",tier:"A",lat:21.2667,lng:-157.8135,category:"restaurant",subcategory:"plate-lunch",tagline:"Japanese-Hawaiian fusion plate lunches on Monsarrat Ave — the garlic ahi and curry are legendary neighborhood favorites.",area:"Kapahulu / Diamond Head",price:"$$",mustOrder:["garlic ahi steak","Japanese curry","SPAM musubi"],parking:"Street parking on Monsarrat Ave; arrive early",talkStory:"Owner Guy Ogawa opened Pioneer Saloon in 2013 on Monsarrat Ave near Diamond Head, blending Japanese precision with Hawaiian plate-lunch culture. The garlic ahi steak — seared rare with a rich garlic butter sauce — became the signature dish that regulars order every single visit. Ogawa previously worked in Tokyo restaurants and brings that discipline to everything including the Japanese curry, made from scratch daily. Perfect post-Diamond Head hike refuel. The tiny space seats maybe 20 — most locals grab and go to Kapiolani Park.",cashOnly:false,kamaaina:null},
  {name:"Podmore",tier:"B",lat:21.3077,lng:-157.8619,category:"restaurant",subcategory:"gastropub",tagline:"Sophisticated British gastropub by the Senia team — emerald booths, $30 cocktails, and everything made from scratch.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["fish and chips — elevated but still recognizable","pot pie — rich and from-scratch","craft cocktails — the real draw"],parking:"Street parking on Merchant St; downtown parking garages",talkStory:"Opened in 2022 by Chef Anthony Rush, Katherine Nomura, and the Senia team as a British gastropub concept — named after a street in London. The emerald-green booths and brass fixtures evoke a Mayfair lounge. Fish and chips uses local catch battered in Kona Brewing ale; the pot pie has a from-scratch puff pastry lid. Cocktails run $25-30 and are meticulously crafted. A completely unique concept for Honolulu — nobody else is doing elevated British food in Hawaii. Same hospitality DNA as Senia next door.",cashOnly:false,kamaaina:null},
  {name:"Poke by the Pound",tier:"A",lat:21.3318,lng:-157.8712,category:"restaurant",subcategory:"poke",tagline:"Industrial-park address, zero ambiance, insane poke — Kalihi's best-kept secret that locals don't want you to know about.",area:"Kalihi",price:"$",mustOrder:["Shoyu ahi — classic and perfectly seasoned, sold by the pound","Spicy salmon — creamy spicy sauce with fresh salmon","Hawaiian-style ahi — traditional preparation with limu and Hawaiian salt"],parking:"Industrial park lot with plenty of free stalls",talkStory:"Run by the Sagawinit family out of a Kalihi industrial park since the mid-2010s — originally started selling poke to warehouse workers and construction crews in the neighborhood. The name is literal: buy by the pound instead of by the bowl and save 30-40% compared to Waikiki poke shops. Fresh ahi delivered daily from local fishing boats. The industrial-park location with zero ambiance is a feature, not a bug — it keeps tourist traffic near zero and prices honest. Grab a pound, buy rice separately, and feed two people.",cashOnly:false,kamaaina:null},
  {name:"Pupukea Grill",tier:"B",lat:21.6438,lng:-158.0562,category:"restaurant",subcategory:"poke",tagline:"Parked across from Banzai Pipeline since 2008 — the surfers lining up here aren't wrong, this is the North Shore's best poke bowl.",area:"Pupukea / North Shore",price:"$",mustOrder:["spicy tuna poke bowl","fish plate lunch"],parking:"Between Pupukea Beach Park and Sharks Cove",talkStory:"Started as a roadside food truck across from Banzai Pipeline around 2008, serving surfers coming out of the water. Built a loyal North Shore following for fresh, no-frills poke bowls using fish from Haleiwa harbor boats. The location between Shark's Cove and Pipeline means you're eating with a view of world-class surf. Pro surfers from the WSL circuit eat here during the Triple Crown season. Prices stay reasonable because there's no sit-down overhead — just a truck, a window, and the ocean across the road.",cashOnly:false,kamaaina:null},
  {name:"Rainbow Drive-In",tier:"S",lat:21.2753,lng:-157.8142,category:"restaurant",subcategory:"plate-lunch",tagline:"The plate lunch cathedral since 1961 — mixed plate with gravy is the move.",area:"Kapahulu",price:"$",mustOrder:["mixed plate with gravy ($12–14) — teriyaki beef + mahimahi + fried chicken, 2 scoops rice, mac salad"],parking:"Small lot in front, fills up fast at lunch — street parking on Kanaina Ave",talkStory:"Founded in 1961 by Seiju Ifuku, a WWII veteran of the legendary 442nd Regimental Combat Team — the most decorated unit in US military history, composed entirely of Japanese-Americans from Hawaii. 'Plate lunch' evolved from plantation-era bento boxes; Rainbow helped codify the modern two-scoop-rice format. Barack Obama ate here regularly growing up and during presidential visits. The mixed plate with gravy over rice is the canonical order. Take your plate one block to Kapiolani Park and eat under a monkeypod tree facing Diamond Head.",cashOnly:false,kamaaina:null},
  {name:"Raised by the Waves",tier:"B",lat:21.6802,lng:-157.9521,category:"restaurant",subcategory:"vegan",tagline:"Kahuku Sugar Mill's plant-based gem — when North Shore surf culture goes vegan and does it exactly right, this is what you get.",area:"Kahuku / North Shore",price:"$",mustOrder:["acai bowls","smoothies","veggie sandwiches"],parking:"Located at Kahuku Sugar Mill",talkStory:"Founded by North Shore surfer and plant-based advocate Brie Witte inside the historic Kahuku Sugar Mill, which operated from 1890 to 1971. The mill complex now houses small local vendors, and Raised by the Waves fits the surf-culture-meets-sustainability ethos perfectly. Acai bowls use locally sourced honey and fruit; smoothies feature Waialua-grown cacao and North Shore bananas. Popular refuel stop for surfers and cyclists doing the North Shore loop. Hours are irregular — check their Instagram before making the drive.",cashOnly:false,kamaaina:null},
  {name:"Roast Duck Kitchen",tier:"A",lat:21.3893,lng:-157.9395,category:"restaurant",subcategory:"chinese-bbq",tagline:"Aiea's roast duck legend — voted #1 on Oahu by Honolulu Magazine readers, with crispy skin and juicy meat that sells out daily.",area:"Aiea",price:"$",mustOrder:["roast duck — the signature, crispy skin shatters on contact","char siu — sweet and caramelized","roast pork — crackling skin, tender meat"],parking:"Aiea Shopping Center lot",talkStory:"When Honolulu Magazine asked readers for their best roast duck, 10 out of 18 respondents named Roast Duck Kitchen — it wasn't even close. A no-frills counter-serve spot in Aiea Shopping Center turning out some of the best Chinese roast meats on the island. The duck has impossibly crispy skin and juicy, flavorful meat. Popular items sell out by early afternoon, so go for lunch. The crowd is almost entirely local Chinese families who know exactly what they're getting. Cash preferred.",cashOnly:true,kamaaina:null},
  {name:"Romy's Kahuku Prawns",tier:"A",lat:21.6912,lng:-157.9728,category:"restaurant",subcategory:"food-truck",tagline:"Farm-raised shrimp from their own ponds — the butter garlic are plumper than Giovanni's, fight me.",area:"Kahuku",price:"$$",mustOrder:["steamed garlic prawns (steaming preserves the sweetness better than frying)"],parking:"Dirt lot next to the shrimp ponds",talkStory:"Founded by Romy and Amy Aquino, a Filipino-American family who started raising prawns in converted sugar cane irrigation ponds in the early 2000s. One of the only Kahuku shrimp spots where the prawns literally come from ponds on the same property — you can see them from where you eat. The steamed preparation (versus the heavy garlic butter at Giovanni's) lets the natural sweetness shine. Featured on Bizarre Foods with Andrew Zimmern. Cash only, small family operation — be patient. The wait is part of the North Shore experience.",cashOnly:true,kamaaina:null},
  {name:"Saigon's Restaurant",tier:"B",lat:21.2835,lng:-157.8108,category:"restaurant",subcategory:"vietnamese",tagline:"Honest Southern Vietnamese cooking on Waialae — the yellow curry wins people over and the pho is among the better bowls on the island.",area:"Kaimuki",price:"$",mustOrder:["pho — rich broth, generous noodles","yellow curry — the sleeper hit","vermicelli bowl — a solid everyday lunch"],parking:"Street parking on Waialae Ave",talkStory:"Run by the Nguyen family on Waialae Ave since the early 2000s, serving Southern Vietnamese home cooking to the Kaimuki neighborhood. The pho broth simmers for 12+ hours and the yellow curry — a Southern Vietnamese specialty less common in Hawaii — is the sleeper hit that converts first-timers into regulars. While The Pig and the Lady gets the press for Vietnamese-fusion, Saigon's is where local Vietnamese families actually eat on their days off. No frills, honest prices, generous portions.",cashOnly:false,kamaaina:null},
  {name:"Seasons Taiwanese Eatery",tier:"A",lat:21.3128,lng:-157.8613,category:"restaurant",subcategory:"taiwanese",tagline:"Chinatown's top-rated Taiwanese spot — popcorn chicken, beef noodle soup, and huge portions at prices that feel like Taipei.",area:"Chinatown / Downtown",price:"$",mustOrder:["popcorn chicken — crispy, five-spice seasoned","beef noodle soup — rich braised broth, tender beef shank","lu rou fan — braised pork belly over rice"],parking:"Chinatown Cultural Plaza parking",talkStory:"Expanded from a shaved ice and boba shop into a full Taiwanese eatery in the Chinatown Cultural Plaza. The owner is passionate and the portions are enormous — you'll struggle to finish a bowl of beef noodle soup. The popcorn chicken is addictive and the lu rou fan (braised pork rice) is textbook comfort food. Prices are shockingly reasonable. The top-rated Taiwanese restaurant on Oahu for good reason. Lunch and dinner Mon-Sat, Sunday lunch only.",cashOnly:false,kamaaina:null},
  {name:"Senia",tier:"S",lat:21.3107,lng:-157.8622,category:"restaurant",subcategory:"fine-dining",tagline:"Three-Michelin-star trained chef running two experiences under one roof — casual a la carte downstairs, elite 8-seat Chef's Counter upstairs.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["Chef's Counter tasting menu (Fri/Sat only, reserve weeks ahead)","seared foie gras with haupia","any dessert — pastry chef Michelle Karr-Ueoka trained at Per Se and French Laundry"],parking:"Street parking on King/Nuuanu; paid lots on Smith St",talkStory:"Opened in 2016 by Chef Chris Kajioka and pastry chef Michelle Karr-Ueoka, both Alan Wong alumni. Kajioka trained at Per Se under Thomas Keller and at Vintage Cave. The 8-seat Chef's Counter (Fri-Sat only) is a multi-course tasting menu ranked among Hawaii's best dining experiences — book 3-4 weeks ahead. Won Hale 'Aina Gold for Best Restaurant and Best Tasting Menu multiple years. The a la carte dining room downstairs is more approachable for a weeknight. Michelle's desserts draw on French Laundry precision with local Hawaiian flavors.",cashOnly:false,kamaaina:null},
  {name:"Seven Brothers",tier:"B",lat:21.6413,lng:-158.0628,category:"restaurant",subcategory:"cafe",tagline:"Samoan family-run cafe in Kahuku serving hearty food and solid coffee near the shrimp trucks.",area:"North Shore (Kahuku)",price:"$",mustOrder:["iced mocha — thick and sweet, fuels the drive home","any plate lunch with a drip coffee — full local experience"],parking:"Free lot in Kahuku town center",talkStory:"Seven Brothers is named because there are literally seven brothers running it. It's a Samoan family operation and the portions are massive. The coffee is simple but good — you're here for the full vibe. Right in Kahuku town near the famous shrimp trucks. If you're doing a North Shore loop, this is a legit stop for both food and caffeine. Aloha spirit is strong here.",cashOnly:false,kamaaina:null},
  {name:"Seven Brothers Burgers",tier:"A",lat:21.6435,lng:-157.9231,category:"restaurant",subcategory:"food-truck",tagline:"Samoan-Hawaiian family joint in Laie — the banana bread alone is worth the stop, the burgers are a bonus.",area:"Laie",price:"$",mustOrder:["Shez's Paniolo burger (thick patties, homemade onion rings, grilled pineapple, bacon, BBQ sauce)","Mom's Banana Bread"],parking:"Lot in front of the restaurant on Kamehameha Hwy",talkStory:"Founded in 2009 by Art and Peggy Hannemann — a Samoan-Hawaiian family with literally seven brothers who all pitch in. They bought the former Kahuku Grill and built a following with BYU-Hawaii students and North Shore locals. Mom's banana bread sells out by noon, and Guy Fieri featured them on Diners, Drive-Ins and Dives. The Laie location has the best vibe — picnic tables, family energy, and burgers stacked with homemade onion rings and grilled pineapple.",cashOnly:false,kamaaina:null},
  {name:"Shige's Saimin Stand",tier:"A",lat:21.5028,lng:-158.0211,category:"restaurant",subcategory:"saimin",tagline:"Townies willingly make the 30-minute drive to Wahiawa because nobody else makes saimin noodles in-house like Shige's does.",area:"Wahiawa / Central Oahu",price:"$",mustOrder:["saimin","teri cheeseburger"],parking:"Strip mall parking lot",talkStory:"Opened in 1990 by Shige Tamashiro in a Wahiawa strip mall, this is one of the last spots on Oahu making saimin noodles from scratch daily. The handmade noodles have a chewier, silkier texture you won't find anywhere else. Locals drive 30+ minutes from town specifically for this. The teri cheeseburger is a sleeper hit — get it as a combo with saimin. Featured on Hawaii's Best multiple times.",cashOnly:false,kamaaina:null},
  {name:"Side Street Inn",tier:"S",lat:21.2946,lng:-157.8472,category:"restaurant",subcategory:"plate-lunch",tagline:"Where Honolulu chefs eat on their day off — the fried rice feeds four and costs sixteen bucks.",area:"Ala Moana",price:"$$",mustOrder:["pan-fried pork chops ($16–20, THE signature dish)","signature fried rice ($14–16, enormous portions)"],parking:"Street parking",talkStory:"Colin Nishida opened Side Street Inn in 1992 as a neighborhood bar, then his pan-fried pork chops got so famous he earned a James Beard semifinalist nod. After Honolulu's top chefs close their own kitchens at 10-11pm, they come here — this is literally where the restaurant industry eats. Anthony Bourdain visited and called it essential. Order family-style, 3-4 dishes for two people. The fried rice portion feeds a small army for $16.",cashOnly:false,kamaaina:null},
  {name:"Side Street Inn (Kapahulu)",tier:"A",lat:21.276,lng:-157.8139,category:"restaurant",subcategory:"plate-lunch",tagline:"Where Honolulu's best chefs eat on their nights off — the pan-fried pork chops and signature fried rice are legendary for a reason.",area:"Kapahulu",price:"$$",mustOrder:["pan-fried pork chops","boneless kalbi","signature fried rice"],parking:"Small lot behind building, street parking on side streets",talkStory:"Colin Nishida opened this second Side Street Inn on Kapahulu in 2010 to serve the Kaimuki/Kapahulu crowd. Same legendary pork chops and massive fried rice as the original Hopaka St location, but with a bigger dining room and easier parking. The Kapahulu spot draws more families early evening while the original stays late-night chef territory. Same menu, same portions that could feed a football team.",cashOnly:false,kamaaina:null},
  {name:"Southern Love",tier:"A",lat:21.3017,lng:-157.8577,category:"restaurant",subcategory:"southern",tagline:"The only serious soul food on Oahu — shrimp and grits that locals call the best in Hawaii, cooked to order in Kakaako.",area:"Kakaako",price:"$$",mustOrder:["shrimp and grits — widely called the best in Hawaii","cajun salmon — perfectly seasoned","catfish po'boy — Southern classic done right"],parking:"Street parking on Queen St; paid lots in Kakaako",talkStory:"Chef Corey Love, originally from Tennessee, and partner Elizabeth Martinez opened in 2023 and immediately filled a gaping hole in Oahu's food scene — real Southern soul food. Everything cooked to order: fried chicken, catfish, shrimp and grits that locals call the best in Hawaii. Featured on Hawaii News Now. Short hours, closed Sun-Mon, tiny space — classic signs of a legit operation. Already at 4.8 Google stars with a devoted local following.",cashOnly:false,kamaaina:null},
  {name:"St. Louis Drive Inn",tier:"B",lat:21.2854,lng:-157.8233,category:"restaurant",subcategory:"plate-lunch",tagline:"Old-guard plate lunch drive-inn near Chaminade — formica tables, walk-up counter, and food that tastes like someone's tutu made it.",area:"Kaimuki / St. Louis Heights",price:"$",mustOrder:["fried chicken plate — crispy and generous","beef stew — local-style comfort food","loco moco — classic drive-inn execution"],parking:"Small lot on Waialae Ave; street parking available",talkStory:"Operating since the 1960s near Chaminade University, St. Louis Drive Inn is old-guard plate lunch at its purest — walk-up counter, formica tables, two scoops rice, mac salad, and protein. The fried chicken is crispy perfection and the beef stew is grandma-level comfort food. While Rainbow Drive-In gets all the tourist fame, locals know St. Louis is the quieter, equally good neighborhood equivalent. Chaminade students and Kaimuki families have been eating here for generations.",cashOnly:false,kamaaina:null},
  {name:"Sunrise Restaurant Hawaii",tier:"A",lat:21.2762,lng:-157.8155,category:"restaurant",subcategory:"japanese",tagline:"Okinawan-style home cooking on Kapahulu — a cuisine you can't find outside Hawaii or Okinawa itself.",area:"Kapahulu",price:"$",mustOrder:["Okinawan soba — different from mainland Japanese soba, thicker and heartier","goya champuru — bitter melon stir-fry, the classic Okinawan dish","andagi — Okinawan-style doughnut"],parking:"Street parking on Kapahulu Ave; small lot nearby",talkStory:"Hawaii has the largest Okinawan diaspora outside Japan, and Sunrise has been keeping that culinary heritage alive on Kapahulu since the 1980s. Family-run, serving home-style Okinawan dishes you literally cannot find outside Okinawa or Hawaii — goya champuru, Okinawan soba, and fresh andagi doughnuts. The crowd is mostly older Okinawan and Japanese families. A deeply cultural pick that connects to Hawaii's immigration story. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Surf N Salsa",tier:"B",lat:21.5955,lng:-158.1034,category:"restaurant",subcategory:"mexican",tagline:"Handmade corn tortillas and house-made salsa in a food truck on Kamehameha Highway — the fish tacos here make you question why you ever ate elsewhere.",area:"Haleiwa / North Shore",price:"$",mustOrder:["Fish tacos — fresh catch in handmade corn tortillas with house salsa","Carnitas tacos — slow-cooked pork, tender and well-seasoned","Housemade salsa — get the hot if you can handle it"],parking:"Dirt pulloff lot right next to the truck",talkStory:"A roadside food truck on Kamehameha Highway near Haleiwa run by a Mexican-American family that built a cult following with North Shore surfers. The tortillas are handmade daily, the fish changes based on the morning catch, and the green salsa is the sleeper hit. Lines build at lunchtime so going slightly off-peak pays off. Closed Sundays. One of the few spots doing real-deal Mexican food on the North Shore.",cashOnly:false,kamaaina:null},
  {name:"Sushi Ginza Onodera",tier:"A",lat:21.2836,lng:-157.8303,category:"restaurant",subcategory:"fine-dining",tagline:"Tokyo-level omakase in Waikiki — the fish is flown in from Toyosu and the craft is impeccable.",area:"Waikiki",price:"$$$",mustOrder:["Omakase — the full chef's counter experience, ~20 pieces of seasonal nigiri","Otoro — fatty tuna belly, melt-in-your-mouth perfection","Uni — seasonal sea urchin, often from Hokkaido"],parking:"Valet at the hotel or public parking at Waikiki Trade Center garage on Kuhio Ave.",talkStory:"Part of a global omakase empire founded by Koji Onodera with flagship locations in Ginza, New York, and LA. The Honolulu outpost opened in the Trump International Waikiki and flies fish directly from Tokyo's Toyosu Market. Omakase runs $200-300+ per person — a genuine splurge, but the craft rivals top sushi-ya in Japan. Sit at the counter for the full itamae experience. Reservations essential, especially weekends.",cashOnly:false,kamaaina:null},
  {name:"SXY Szechuan",tier:"B",lat:21.291,lng:-157.845,category:"restaurant",subcategory:"sichuan",tagline:"Sichuan specialist inside Ala Moana Center — bold, spicy dishes and strong ratings make it an easy stop after shopping.",area:"Ala Moana",price:"$$",mustOrder:["mapo tofu — silky tofu in fiery chili-bean sauce","spicy chicken with dried chilies — la zi ji","shredded pork with garlic sauce — a milder option"],parking:"Ala Moana Center parking (free)",talkStory:"A Sichuan-focused restaurant inside Ala Moana Center that punches above the typical mall food court. Featured in Honolulu Magazine as 'Spicy is the New Sexy.' The mapo tofu and dry-fried chicken with chilies are legit spicy — not toned down for a mall crowd. Convenient location makes it easy to combine with Ala Moana shopping. Not as deep a menu as Chengdu Taste, but more accessible and easier to park. Lunch and dinner daily.",cashOnly:false,kamaaina:null},
  {name:"Taco Kahuku",tier:"B",lat:21.6803,lng:-157.9557,category:"restaurant",subcategory:"food-truck",tagline:"North Shore taco truck with fresh fish tacos that rival the shrimp trucks without the crazy lines.",area:"North Shore (Kahuku)",price:"$",mustOrder:["Fresh fish taco — grilled catch of the day with slaw and crema","Garlic shrimp taco — North Shore shrimp truck flavors in taco form","Burrito bowl — rice, beans, fresh fish, and all the fixings"],parking:"Roadside pull-off area on Kamehameha Hwy near the other Kahuku food trucks.",talkStory:"While everyone queues 45 minutes at Giovanni's and Romy's shrimp trucks, Taco Kahuku quietly serves some of the best fish tacos on the North Shore with almost no wait. Located in the same Kahuku food truck strip, it's the smart local move — fresh-caught fish, generous portions, and you can mix and match with shrimp from next door. Great alternative if someone in your group doesn't want shrimp.",cashOnly:false,kamaaina:null},
  {name:"Tamura's Fine Wine & Liquors",tier:"A",lat:21.4225,lng:-157.7487,category:"restaurant",subcategory:"poke",tagline:"Walk into a wine shop, walk out with the best poke in Kailua — trust the process.",area:"Kailua",price:"$",mustOrder:["spicy ahi (top seller)","garlic shrimp poke (hard to find elsewhere)","furikake salmon poke"],parking:"Ample parking at Aikahi Park Shopping Center",talkStory:"The Tamura family has run this Kailua wine and liquor shop for decades, but the poke counter they added became equally legendary. They cure and season their own poke in-house — the spicy ahi is the top seller. The local move: grab a pound of poke plus a bottle of wine, then drive five minutes to Kailua Beach for sunset. You can taste before buying. Best selection before 1pm when the fresh batches are still full.",cashOnly:false,kamaaina:null},
  {name:"Tamura's Fine Wine & Liquors (Waialae)",tier:"A",lat:21.2794,lng:-157.7901,category:"restaurant",subcategory:"poke",tagline:"The Kahala-area location of Oahu's best poke-inside-a-liquor-store situation — grab a bottle and a pound of spicy ahi, you've cracked the code.",area:"Kaimuki / Kahala",price:"$",mustOrder:["spicy ahi poke","furikake salmon"],parking:"Strip mall lot on Waialae Ave",talkStory:"The Waialae branch brings the Tamura family's famous poke counter and curated wine selection to the Kaimuki/Kahala side of town. Same family, same in-house preparations, same quality as the Kailua original. Regulars call ahead to check which preparations are available. The spicy ahi and furikake salmon are consistently top sellers. Best poke selection before 1pm — they make everything fresh daily and popular flavors sell out.",cashOnly:false,kamaaina:null},
  {name:"Tanioka's Seafoods",tier:"A",lat:21.3841,lng:-158.0011,category:"restaurant",subcategory:"poke",tagline:"West-side pilgrimage spot — the smoked meat counter alone is worth the drive from town.",area:"Waipahu",price:"$",mustOrder:["limu ahi poke","ahi patties ($3–4 each, crispy outside, tender inside — tourists overlook these)","the smoked marlin"],parking:"Strip mall lot, decent parking",talkStory:"The Tanioka family has been rooted in Waipahu's plantation community since the 1970s, and Grandma Tanioka's original recipes still form the foundation. Their poke counter is elite, but the sleeper hits are the ahi patties ($3-4 each, crispy outside, tender inside) and the smoked marlin that tourists walk right past. You can taste before buying a pound. Bring a cooler if you're driving back to town — the smoked meats are incredible take-home.",cashOnly:false,kamaaina:null},
  {name:"Teishoku Restaurant",tier:"A",lat:21.3297,lng:-157.8614,category:"restaurant",subcategory:"japanese",tagline:"Japanese set meals in a Kalihi shopping center — miso butterfish, miso soup, rice, pickles, all for one price. Tourists will never find this.",area:"Kalihi",price:"$$",mustOrder:["miso butterfish teishoku — the signature set meal","chicken katsu set — crispy and satisfying","any daily special — the rotating items are where the kitchen shines"],parking:"Kamehameha Shopping Center lot on N School St",talkStory:"Teishoku means \"set meal\" in Japanese, and this Kalihi spot on N School Street has been serving complete trays — miso soup, salad, pickled vegetables, rice, and protein — at prices that feel like 2005. Deep in neighborhood territory where no tourist has ever wandered. Featured in Honolulu Magazine as a hidden gem. The miso butterfish teishoku is the signature. Fast service, family-run, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"The Hibachi (Kailua)",tier:"B",lat:21.3933,lng:-157.7397,category:"restaurant",subcategory:"poke",tagline:"Windward side's hidden poke gem — assembled fresh to order right in front of you, with variety that puts the tourist spots to shame.",area:"Kailua",price:"$",mustOrder:["Fresh poke bowl — built to order with your choice of fish and toppings","Spicy ahi poke — creamy and flavorful, always a solid pick","Daily specials — ask what's new, they rotate preparations regularly"],parking:"Shopping center lot with ample parking",talkStory:"A neighborhood poke and grill counter in a Kailua shopping center that earned a fiercely loyal Windward side following by keeping fish fresh and prices honest. They build your bowl right in front of you — ask what fish came in fresh that day. Regulars come multiple times a week. The sweet spot is mid-afternoon when the lunch rush has cleared but the selection is still good. Check hours as they can vary.",cashOnly:false,kamaaina:null},
  {name:"The Nighthawk",tier:"A",lat:21.3076,lng:-157.8618,category:"restaurant",subcategory:"american",tagline:"Chicago-style comfort food in a historic Chinatown building — Italian beef sandwiches, Maxwell Street Polish, and late-night Kung Fu Ham.",area:"Chinatown / Downtown",price:"$",mustOrder:["Italian beef sandwich — Chicago-style, juicy and proper","Chicago-style hot dog — no ketchup, ever","Kung Fu Ham — deep-fried pork belly with Thai chili garlic"],parking:"Street parking on S King St; paid lots on Smith/Maunakea",talkStory:"Opened by a Midwest transplant who brought authentic Chicago-style Italian beef sandwiches, Maxwell Street Polish, and proper Chicago dogs (no ketchup, ever) to a beautifully restored Chinatown building. The Kung Fu Ham — deep-fried pork belly with Thai chili garlic — is a house original that bridges Chicago grit and Honolulu creativity. Downtown workers fill it at lunch, the Chinatown bar crowd takes over late night. Open until midnight.",cashOnly:false,kamaaina:null},
  {name:"The Pig and the Lady",tier:"A",lat:21.3118,lng:-157.8628,category:"restaurant",subcategory:"fine-dining",tagline:"Vietnamese-Hawaiian fusion that put Chinatown dining on the map — Chef Andrew Le's pho French dip is genius.",area:"Chinatown",price:"$$$",mustOrder:["Pho French dip — prime rib dipped in pho broth, absolute game changer","Crispy crepe banh xeo — stuffed with shrimp, pork, and herbs","Smoked meat pho — rich bone broth with brisket and all the fixings"],parking:"Street parking on Smith or Hotel St. Chinatown garage at 1130 N Nimitz Hwy is cheapest. Meter parking free after 6pm.",talkStory:"Chef Andrew Le, son of Vietnamese refugees, started selling pho at the KCC Farmers Market and blew up from there. His Chinatown restaurant earned a James Beard semifinalist nomination for Best Chef West. The pho French dip — prime rib dipped in pho broth — is genius-level fusion. Saturday farmers market booth still has lines. Dinner reservations recommended; the bar takes walk-ins. Friday and Saturday nights have serious energy in the Chinatown dining room.",cashOnly:false,kamaaina:null},
  {name:"Tokkuri Tei",tier:"S",lat:21.275,lng:-157.8156,category:"restaurant",subcategory:"izakaya",tagline:"Honolulu's original izakaya — the garlic ahi belly and tofu steak are why reservations fill a week out.",area:"Kapahulu",price:"$$",mustOrder:["ika yaki (squid pancake, $12–14 — THE signature dish)","maguro tataki ($14–16)","garlic edamame","nasu dengaku (miso eggplant)","black sesame ice cream"],parking:"Street parking on side streets mauka of Kapahulu",talkStory:"Opened in the early 1990s by chef/owner Hide Yoshimoto (Hide-san), Tokkuri Tei was one of the first authentic izakayas in Hawaii and helped spark the island's entire izakaya boom. The ika yaki (squid pancake) is the legendary signature dish. Order multiple small plates to share — izakaya style means rounds of dishes, not one entree per person. Ask staff for sake pairing guidance. Go Tue/Wed for walk-in seating; weekends book up fast.",cashOnly:false,kamaaina:null},
  {name:"Tonkatsu Tamafuji",tier:"A",lat:21.2799,lng:-157.785,category:"restaurant",subcategory:"japanese",tagline:"Kaimuki's tonkatsu master — perfectly fried heritage pork cutlets with house-ground cabbage and secret dipping sauce.",area:"Kaimuki",price:"$$",mustOrder:["rosu katsu set","hire katsu set","menchi katsu"],parking:"Street parking on Waialae Ave; small lot behind",talkStory:"Run by a Japanese chef who trained in Tokyo tonkatsu houses before opening this Kaimuki spot, Tamafuji serves what many locals consider the best tonkatsu on Oahu. The pork cutlets use premium heritage pork, breaded in ultra-fine panko and fried to impossibly crispy perfection while staying juicy inside. The house-ground cabbage is fluffy and the dipping sauce recipe is closely guarded. Lunch lines form early — arrive by 11:30am or expect a 30-minute wait.",cashOnly:false,kamaaina:null},
  {name:"Totoya Kaimuki",tier:"A",lat:21.2844,lng:-157.8145,category:"restaurant",subcategory:"japanese",tagline:"Sixteen-seat kaisendon counter where the sashimi is piled so thick you can barely see the rice — get there early or join the wait.",area:"Kaimuki",price:"$$",mustOrder:["kaisen don — the signature sashimi rice bowl with daily fish selection","negitori don — torched salmon belly over rice","miso soup — yuzu or ginger-infused, not an afterthought"],parking:"Street parking on 12th Ave and side streets; competitive during lunch rush",talkStory:"Opened in late 2024 on 12th Ave in Kaimuki by a Japanese chef and instantly became one of the hardest lunch reservations on Oahu. Only 16 counter seats with an open kitchen where you watch your kaisen don being built with exceptional daily-sourced fish. Lines form before opening. The move is weekday 1:30pm or late dinner for shorter waits. Already at 4.8 Google stars with 200+ reviews — one of the highest-rated new restaurants on the island.",cashOnly:false,kamaaina:null},
  {name:"Uncle Bo's",tier:"A",lat:21.2828,lng:-157.8136,category:"restaurant",subcategory:"izakaya",tagline:"Kaimuki pupu bar with creative local-Asian fusion — the garlic truffle fries and dynamite are legendary.",area:"Kaimuki",price:"$$",mustOrder:["Garlic truffle fries — crispy, truffled, and addictive","Dynamite — baked seafood with spicy mayo, a local izakaya classic","Bo's fried rice — loaded with whatever's good, different every time"],parking:"Street parking on Waialae Ave and side streets. Kaimuki is tight — circle once or twice.",talkStory:"Chef Bo Pathammavong, born in Laos and raised in Hawaii, brings Lao and local flavors together in creative pupus that are perfect for sharing over drinks. Uncle Bo's is the Kaimuki spot for late-night grinds — they stay open late by Honolulu standards, making it a go-to after other restaurants close. The garlic truffle fries are dangerously addictive. Order a bunch of small plates for the table. Reservations recommended on weekends; the vibe is loud, fun, and always packed.",cashOnly:false,kamaaina:null},
  {name:"Utage Restaurant & Lounge",tier:"A",lat:21.3243,lng:-157.8564,category:"restaurant",subcategory:"japanese",tagline:"Family-run Okinawan restaurant in Kalihi that literally calls regulars when specials are coming — 25 years of that kind of aloha.",area:"Kalihi",price:"$$",mustOrder:["ahi nori tempura — the signature","konbu maki — only made twice a year, ask when the next one is","daily specials — whatever the kitchen is excited about"],parking:"City Square Shopping Center lot on Kalani St",talkStory:"Run by the Kishimoto family since 2001 — daughter Edna handles front of house, son Ivan runs the kitchen. They keep a handwritten call list of regulars and phone them when favorite specials are available. That detail alone tells you everything about this place. Okinawan and Japanese cuisine in Kalihi's City Square Shopping Center, far from any tourist path. The ahi nori tempura is the signature. Konbu maki is only made twice a year — ask when the next batch is coming.",cashOnly:false,kamaaina:null},
  {name:"Waiahole Poi Factory",tier:"A",lat:21.4832,lng:-157.8514,category:"restaurant",subcategory:"hawaiian",tagline:"One of the last real poi factories on Oahu — fresh poi, laulau, and squid luau in a Windward valley setting.",area:"Waiahole",price:"$",mustOrder:["Fresh poi — hand-pounded, creamy, the real deal","Laulau — pork and fish wrapped in taro leaves, steamed until melt-tender","Squid luau — squid simmered in coconut milk and taro leaves"],parking:"Small gravel lot right off Kamehameha Hwy. Easy to spot.",talkStory:"One of the last real poi factories on Oahu, operating in the Waiahole Valley for generations. They make fresh poi the traditional way — hand-pounded from Windward-grown taro. The laulau and squid luau are deeply authentic Hawaiian food, not tourist luau fare. The setting is stunning — lush valley with the Ko'olau mountains as backdrop. Open limited hours (usually weekends and some weekdays), so always call ahead. Cash only. This is a cultural treasure, not just a restaurant.",cashOnly:true,kamaaina:null},
  {name:"Yakitori Ando",tier:"A",lat:21.28,lng:-157.783,category:"restaurant",subcategory:"japanese",tagline:"Tiny Kaimuki izakaya serving omakase-only yakitori over binchotan charcoal — Oahu's best-kept dining secret.",area:"Kaimuki",price:"$$$",mustOrder:["omakase yakitori course","tsukune with egg yolk","chicken hearts"],parking:"Street parking on Center St and Waialae Ave",talkStory:"With only about 10 counter seats, Chef Ando grills each skewer over imported binchotan charcoal with Tokyo-level precision — chicken hearts, tsukune with runny egg yolk, seasonal specials. The omakase-only format means you sit back and trust the chef through about 15 courses over 90 minutes. Book 3-4 weeks in advance; locals consider this Oahu's best-kept dining secret. Quietly earned one of the highest per-seat reputations in the state.",cashOnly:false,kamaaina:null},
  {name:"Yama's Fish Market",tier:"A",lat:21.2877,lng:-157.8229,category:"restaurant",subcategory:"plate-lunch",tagline:"The local plate lunch and poke counter that office workers plan their whole week around.",area:"Moiliili",price:"$",mustOrder:["Ahi poke — classic shoyu or spicy, always fresh-cut","Kalua pig plate — smoky pulled pork with cabbage, rice, and mac salad","Laulau plate — steamed pork and taro leaf with two scoops rice"],parking:"Small lot that fills up fast at lunch. Try street parking on Young St or Isenberg.",talkStory:"The Yamashiro family has been running this Moiliili plate lunch and poke counter for decades, and office workers from UH to Ala Moana plan their week around it. Locals argue endlessly whether Yama's or Ono Seafood has better ahi poke — both are great, different styles. The kalua pig plate is enormous and the poke is always fresh-cut. Lunch rush is 11:30-1pm with lines out the door. Go at 11am or after 1:30. They sell poke by the pound — perfect beach day move.",cashOnly:false,kamaaina:null},
  {name:"Yi Pin Mala Tang",tier:"B",lat:21.277,lng:-157.8145,category:"restaurant",subcategory:"malatang",tagline:"Kapahulu's pick-your-own malatang shop — choose your ingredients, pick your spice level, and get a customized bowl of numbing-spicy soup.",area:"Kapahulu",price:"$",mustOrder:["build your own bowl — pick proteins, veggies, noodles, and spice level","add extra chili oil and Sichuan peppercorn","pair with a cold drink — you'll need it"],parking:"Street parking on Kapahulu Ave",talkStory:"Malatang is China's customizable street food soup — you pick your raw ingredients from a display (meat, tofu, vegetables, mushrooms, noodles), choose your spice level, and it's all cooked together in a spicy numbing broth. Yi Pin on Kapahulu is the best version on Oahu. 4.6 stars, friendly owner, open late (until 11:30pm most nights). Different from hot pot because someone else cooks it for you. A great solo meal or late-night option after a Kapahulu dinner crawl.",cashOnly:false,kamaaina:null},
  {name:"Young's Fish Market",tier:"A",lat:21.3152,lng:-157.858,category:"restaurant",subcategory:"hawaiian",tagline:"Old-school Hawaiian plate lunch counter in Kalihi — massive portions, family recipes, and some of the best poke on the island.",area:"Kalihi",price:"$",mustOrder:["Hawaiian plate — laulau, kalua pig, lomi salmon, poi or rice","Poke by the pound — ahi, tako, or shoyu varieties","Pipikaula (dried beef)","Squid luau"],parking:"Small lot on Liliha St. Street parking on side streets",talkStory:"Young's has been serving Hawaiian food in Kalihi since 1951, making it one of the oldest continuously operating Hawaiian food spots on Oahu. Three generations of the Young family have run it. The Hawaiian plate — laulau, kalua pig, lomi salmon, poi — is a complete meal and a cultural education. Their poke counter is among the island's best, with fresh ahi and tako sold by the pound. The pipikaula (Hawaiian dried beef) is hard to find anywhere else. Not fancy — order at the counter, eat at plastic tables. This is real local food.",cashOnly:false,kamaaina:null},
  {name:"Youpo Noodles HI",tier:"A",lat:21.3125,lng:-157.8635,category:"restaurant",subcategory:"hand-pulled-noodles",tagline:"Chinatown's hand-pulled biang biang noodle shop — thick, chewy, ripped-to-order noodles with bold Northwestern Chinese flavors.",area:"Chinatown / Downtown",price:"$",mustOrder:["cumin lamb noodles — the signature, aromatic and spicy","youpo noodles — hot oil poured over hand-pulled noodles","beef noodle soup — rich broth, tender beef"],parking:"Metered street parking on Maunakea St",talkStory:"Started as a farmers market stand and grew into a Chinatown brick-and-mortar — that trajectory tells you the noodles are legit. Specializes in biang biang noodles from Northwestern China — thick, wide, hand-pulled noodles ripped to order. The youpo (hot oil) technique pours sizzling oil over chili flakes and noodles tableside. Flavors are bold — cumin lamb, chili oil, black vinegar. Featured in Honolulu Magazine. A completely different experience from the Cantonese noodle shops that dominate Chinatown.",cashOnly:false,kamaaina:null},
  {name:"Zippy's Restaurant",tier:"S",lat:21.2854,lng:-157.8365,category:"restaurant",subcategory:"plate-lunch",tagline:"Hawaii's diner chain that every local grew up on — chili and zip packs are a way of life.",area:"King Street",price:"$",mustOrder:["Zippy's Chili — the iconic thick, beefy chili that's been the same since 1966","Zip Pack — fried chicken, chili, rice, and mac salad in one legendary combo","Napoleon Bakery cream puffs — the grab-and-go bakery case is dangerously good"],parking:"Most locations have their own lot. King Street location has a parking lot behind the building.",talkStory:"Founded in 1966 by Francis Higa and Charles Toguchi, Zippy's is Hawaii's most beloved diner chain with 20+ locations across Oahu. The chili recipe is a legit state secret — they've never revealed it in nearly 60 years. Every local kid grew up eating here after practice, after prom, at 2am. The Zip Pack (fried chicken, chili, rice, mac salad) is an institution. Napoleon Bakery inside sells cakes and cream puffs for every birthday party on the island. It's not fancy, but for locals it's home.",cashOnly:false,kamaaina:null},
  {name:"Aoki's Shave Ice",tier:"A",lat:21.5908,lng:-158.1022,category:"shave-ice",subcategory:"classic",tagline:"Directly across from Matsumoto with a fraction of the line — locals' quiet favorite since 1981.",area:"Haleiwa",price:"$",mustOrder:["lychee","lilikoi","tiger's blood","green tea","azuki beans + condensed milk combo"],parking:"Street spots fill fast — same parking situation as Matsumoto",talkStory:"The Aoki family are Haleiwa OGs — while tourists mob Matsumoto, locals quietly slip into Aoki's. Open since 1981. If you want to compare the two (and you should), get a small at each. The azuki beans + condensed milk combo is the local move.",cashOnly:false,kamaaina:null},
  {name:"Island Snow",tier:"S",lat:21.3946,lng:-157.7384,category:"shave-ice",subcategory:"classic",tagline:"Obama's Kailua go-to — every presidential visit = a stop here. Also a legit surf shop.",area:"Kailua",price:"$",mustOrder:["any flavor with vanilla ice cream on the bottom (the Island Snow signature)","li hing mui powder on top","passion orange guava (POG)"],parking:"Parking in the Kailua Shopping Center lot next door",talkStory:"A Kailua institution way before the Obama fame, doubling as a surf/skate shop since the '90s. The shop sponsors local surf groms and is deeply embedded in the Kailua community. Combine with a Kailua Beach day — it's a 5-minute walk. Every order comes with a scoop of vanilla ice cream buried at the bottom of the cone — that's the Island Snow signature. Add li hing mui powder on top for the local move.",cashOnly:false,kamaaina:null},
  {name:"Island Vintage Shave Ice",tier:"B",lat:21.2841,lng:-157.8306,category:"shave-ice",subcategory:"gourmet",tagline:"Organic syrups and fresh fruit toppings in the heart of Waikiki — gourmet done right.",area:"Waikiki",price:"$$",mustOrder:["Aloha — organic guava, passion fruit, and coconut cream","North Shore — pineapple with fresh mango chunks on top","add mochi balls and condensed milk drizzle"],parking:"Royal Hawaiian Center parking garage — validate at the shop",talkStory:"Yeah it's in Waikiki and yeah it's pricier, but Island Vintage actually uses organic Hawaiian-grown fruit syrups and the quality is legit. The shave ice is topped with real fruit pieces, not just syrup. It's connected to their acai bowl operation so everything is fresh. Best spot if you're already in Waikiki and don't want to drive 45 minutes for shave ice. The line moves fast even when it looks long.",cashOnly:false,kamaaina:null},
  {name:"Kaimana Shave Ice",tier:"A",lat:21.5791,lng:-158.1026,category:"shave-ice",subcategory:"gourmet",tagline:"All-natural fruit syrups with half the sugar and scratch-made ice cream — Haleiwa's gourmet contender to Matsumoto.",area:"Haleiwa",price:"$",mustOrder:["Any flavor with homemade mac nut ice cream — the signature combo","Liliko'i or mandarin — the tropical fruit syrups shine","Coffee flavor — unique and surprisingly good"],parking:"Street parking along Kamehameha Hwy in Haleiwa town",talkStory:"Opened in 2018 in a barn-red building on Haleiwa's main road, Kaimana quickly became the locals' alternative to the Matsumoto tourist line. All syrups are made from real fruit with about half the sugar of conventional shave ice. The ice cream is made from scratch daily — vanilla, mac nut, banana, and a vegan option that's surprisingly rich. One size, one or two flavors, done right. Mon–Sat noon–4:30pm, closed Sundays. Small-batch means flavors rotate, so ask what's fresh.",cashOnly:false,kamaaina:null},
  {name:"Matsumoto Shave Ice",tier:"S",lat:21.5911,lng:-158.1028,category:"shave-ice",subcategory:"classic",tagline:"The North Shore icon since 1951 — the rainbow combo is non-negotiable.",area:"Haleiwa",price:"$",mustOrder:["rainbow combo (strawberry-lemon-pineapple)","lilikoi","li hing mui","coconut","azuki beans + ice cream on the bottom"],parking:"Street parking — fills fast on weekends",talkStory:"The original wooden building and vintage sign are historic landmarks. Open since 1951. The T-shirt they sell ($15–20) is a legit souvenir. If the line is insane, walk 50 feet to Aoki's instead. ALWAYS add azuki beans + ice cream on the bottom ($1–2 extra) — that's the real order. Lines can hit 30+ min on weekends so go early or late.",cashOnly:false,kamaaina:null},
  {name:"Monsarrat Shave Ice",tier:"A",lat:21.2709,lng:-157.8164,category:"shave-ice",subcategory:"gourmet",tagline:"Real fruit compotes layered into silky ice — the gourmet shave ice that Diamond Head locals swear by.",area:"Diamond Head",price:"$",mustOrder:["Any flavor with ice cream and mochi balls — the full experience","Coconut cream or matcha — the house signatures","Mango or mixed berry — pure real fruit, no artificial syrup"],parking:"Street parking on Monsarrat Ave — limited but usually findable on weekdays",talkStory:"This little window next to Pioneer Saloon uses real organic fruit jams and compotes instead of artificial syrups — you can taste the difference immediately. Each cup is carefully layered by hand. Open daily 11am–5:30pm, closed on rainy days (they're serious about that). Add the Meadow Gold ice cream and shiratama mochi balls for the full experience. One of the best kept secrets on Monsarrat Ave's food row.",cashOnly:false,kamaaina:null},
  {name:"Shimazu Shave Ice",tier:"B",lat:21.3207,lng:-157.8696,category:"shave-ice",subcategory:"classic",tagline:"Old-school Kalihi corner shop — shave ice the way your tutu remembers it.",area:"Kalihi",price:"$",mustOrder:["rainbow with ice cream on the bottom","li hing mui — perfectly sour-sweet","vanilla with azuki beans"],parking:"Street parking on Kalihi St — not hard to find a spot",talkStory:"Shimazu has been around for decades in Kalihi, a neighborhood tourists never see. The shave ice is classic-style with fine ice and local-brand syrups. The aunties who work here know every kid in the neighborhood by name. It's cash-friendly and no-frills — just a counter window and a bench outside. This is the kind of place that makes Kalihi feel like old Hawaii.",cashOnly:true,kamaaina:null},
  {name:"Uncle Clay's House of Pure Aloha",tier:"S",lat:21.2857,lng:-157.8011,category:"shave-ice",subcategory:"gourmet",tagline:"All-natural syrups and real fruit — this is shave ice elevated to an art form.",area:"Aina Haina",price:"$",mustOrder:["lilikoi cream — tangy and rich, their signature","strawberry lemonade with li hing mui powder on top","haupia with azuki beans on the bottom"],parking:"Small lot in Aina Haina Shopping Center — easy parking",talkStory:"Uncle Clay's is the real deal — all syrups are made in-house from real fruit, no artificial colors or flavors. They've won every shave ice award the islands have. The shop is in a humble strip mall in Aina Haina, which keeps it mostly locals. Ask for the 'Pure Aloha' combo if you can't decide — they'll set you up right. Clayton and his family run the place with genuine aloha spirit.",cashOnly:false,kamaaina:null},
  {name:"Waiola Shave Ice",tier:"S",lat:21.2919,lng:-157.8358,category:"shave-ice",subcategory:"classic",tagline:"Honolulu institution since 1979 — cloud-soft ice that soaks up syrup better than anywhere.",area:"Moiliili",price:"$",mustOrder:["any flavor — the ice texture is the star here","azuki beans","li hing mui"],parking:"Street parking on Waiola St or in the small lot behind the shop",talkStory:"This is where UH Manoa students and Moiliili families have come for decades — no tourists, just neighborhood people. The owner is there most days. Won Hawaii's Best Shave Ice multiple years running. It's in a residential area so don't blast music or take up the whole sidewalk. Known for having the softest, finest-shaved ice on the island — it's almost powdery, which means the syrup absorbs completely instead of pooling at the bottom.",cashOnly:false,kamaaina:null},
  {name:"Bailey's Antiques & Aloha Shirts",tier:"S",lat:21.2765,lng:-157.8152,category:"shopping",subcategory:"vintage",tagline:"The world's largest collection of vintage aloha shirts — 15,000+ pieces in a Kapahulu warehouse that's a museum you can shop.",area:"Kapahulu",price:"$-$$$",parking:"Street parking on Kapahulu Ave",hours:"Daily 10am-6pm",bestTime:"Weekday afternoons for unhurried browsing",kidFriendly:true,talkStory:"Over 15,000 vintage aloha shirts packed floor to ceiling in a Kapahulu warehouse — the largest collection in the world. Prices range from $5 racks to museum-quality silks from the 1930s-50s worth thousands. Owner Dave Bailey has been collecting for decades and the staff can tell you the history of any shirt you pull. Barack Obama, Anthony Bourdain, and every serious vintage collector has shopped here. Even if you don't buy, it's a cultural education in Hawaii's most iconic garment. The $5-$20 rack near the door has legitimate treasures if you dig.",kamaaina:null},
  {name:"Green Gypsy Thrift Shop",tier:"B",lat:21.577,lng:-158.1295,category:"shopping",subcategory:"thrift-store",tagline:"A curated thrift store in the old Waialua Sugar Mill — vintage aloha shirts, surfwear, and bohemian North Shore finds.",area:"North Shore",price:"$",parking:"Free lot at the Sugar Mill",hours:"Daily 10am-5pm (hours may vary)",bestTime:"Saturday when combined with the Waialua Farmers Market",kidFriendly:true,talkStory:"A hidden gem thrift store inside the old Waialua Sugar Mill compound on the North Shore. The curated selection includes vintage aloha shirts, jewelry, hats, shoes, swimsuits, and wetsuits at excellent prices. The vibe is bohemian and laid-back, fitting perfectly with the North Shore lifestyle. Locals who surf the North Shore regularly shop here for gear and vintage finds. Combine with the Waialua Farmers Market on Saturday mornings.",kamaaina:null},
  {name:"Mori by Art + Flea",tier:"B",lat:21.31,lng:-157.863,category:"shopping",subcategory:"local-design",tagline:"Local fashion, home goods, and art from up-and-coming Hawaii-based artists and designers — each visit feels fresh.",area:"Chinatown / Downtown",price:"$$",parking:"Street parking; walk from downtown",hours:"Tue-Sat 11am-6pm; later on First Fridays",bestTime:"First Friday evenings when Chinatown's art walk is happening",kidFriendly:true,talkStory:"The brick-and-mortar location of Art + Flea (Hawaii's first urban street market) curates local fashion, home goods, stationery, and art from up-and-coming Hawaii-based artists and designers. The selection changes regularly, so each visit feels fresh. This is where creative Honolulu shops for locally designed T-shirts, prints, ceramics, and accessories you can't find anywhere else.",kamaaina:null},
  {name:"Na Mea Hawaii",tier:"A",lat:21.2937,lng:-157.8489,category:"shopping",subcategory:"hawaiian-goods",tagline:"The best shop on Oahu for genuinely Hawaiian-made gifts — koa wood bowls, lauhala weaving, and books by Native Hawaiian authors.",area:"Kakaako",price:"$$-$$$",parking:"Ward Centre parking (1200 Ala Moana Blvd, Suite 270)",hours:"Mon-Sat 10am-6pm, Sun 10am-4pm",bestTime:"Weekday afternoons; check for cultural workshops and author events",kidFriendly:true,talkStory:"The single best shop on Oahu for gifts and goods that are genuinely Hawaiian-made. Relocated from Ward Warehouse to Ward Centre at 1200 Ala Moana Blvd, Suite 270. From hand-carved koa wood bowls to books by Native Hawaiian authors, lauhala weaving, and Hawaiian music, everything here supports Hawaiian artisans and cultural practitioners. The staff is knowledgeable and passionate. Locals come here for meaningful gifts, not the cheap made-in-China souvenirs you find in Waikiki. Regular cultural workshops and events.",kamaaina:null},
  {name:"Roberta Oaks",tier:"A",lat:21.3114,lng:-157.8617,category:"shopping",subcategory:"local-fashion",tagline:"Modern aloha wear designed and made in Honolulu — bold prints on classic silhouettes that locals actually wear to work.",area:"Chinatown / Downtown",price:"$$-$$$",parking:"Street parking on Bethel St",hours:"Mon-Sat 10am-5pm",bestTime:"Weekdays for personal attention; check for new print drops on social media",kidFriendly:true,talkStory:"Designer Roberta Oaks creates modern aloha wear in her Chinatown studio — bold, original prints on well-tailored shirts, dresses, and accessories. This isn't the mass-produced aloha shirt you find in ABC stores — each print is designed in-house and the clothing is made in Honolulu. Locals wear these to work, weddings, and everywhere in between. The Chinatown shop doubles as a studio, so you might see production happening behind the retail space. A perfect example of Hawaii's evolving fashion identity beyond the vintage aloha shirt.",kamaaina:null},
  {name:"Surf n Sea",tier:"S",lat:21.594,lng:-158.107,category:"shopping",subcategory:"surf-shop",tagline:"The oldest surf shop in Hawaii (1965) — real surfers sell and rent gear in a colorful Haleiwa waterfront landmark.",area:"North Shore",price:"$$",parking:"Small lot; street parking on Kamehameha Hwy",hours:"Daily 9am-7pm",bestTime:"Morning for the best advice on where to surf that day; check the used board section in back",kidFriendly:true,talkStory:"The oldest surf shop in Hawaii (since 1965), located right on the Haleiwa waterfront in a colorful wooden building. This is not a tourist trap — it's a working surf shop where North Shore locals buy and rent gear. The staff are real surfers who can tell you where the best waves are breaking that day. The used board section in the back has great deals. The building itself is a North Shore landmark worth photographing.",kamaaina:null},
  {name:"Tin Can Mailman",tier:"A",lat:21.2761,lng:-157.823,category:"shopping",subcategory:"vintage-books",tagline:"Kaimuki's treasure trove of vintage Hawaiiana — old maps, postcards, books, and ephemera that tell Hawaii's story.",area:"Kaimuki",price:"$-$$$",parking:"Street parking on Waialae Ave",hours:"Tue-Sat 10am-5pm; closed Sun-Mon",bestTime:"Weekday afternoons for unhurried browsing — the owner loves to talk story",kidFriendly:true,talkStory:"A Kaimuki shop specializing in vintage Hawaiiana — old books, maps, postcards, photographs, sheet music, and paper ephemera from Hawaii's past. If you want a meaningful, one-of-a-kind souvenir that isn't a plastic hula dancer, this is the place. Find a 1920s menu from the Royal Hawaiian Hotel, an original map of Pearl Harbor, or a first-edition Hawaiian history book. The owner is deeply knowledgeable and happy to help you find something special. A must-visit for history buffs and collectors.",kamaaina:null},
  {name:"Ala Moana Beach Park (Magic Island Reef)",tier:"B",lat:21.287,lng:-157.848,category:"snorkel",subcategory:"reef",tagline:"An urban reef snorkel that Honolulu locals hit on their lunch break.",area:"Honolulu",price:"Free",parking:"Large free lot at Ala Moana Beach Park; metered spots along the peninsula",hours:"Park open 4am–10pm; gates lock at night",bestTime:"Morning before trade winds chop up the surface; summer months for clearest water",kidFriendly:true,talkStory:"The reef off Magic Island's channel wall is home to endemic Hawaiian whitespotted toby and fourspot butterflyfish you won't see on the mainland. This area was dredged coral fill when the peninsula was built in 1964, and the reef has been slowly reclaiming it ever since — a quiet conservation success story. Experienced locals snorkel the outer channel edge at slack tide for the best visibility and biggest honu sightings; avoid afternoons when trade-wind chop turns it milky.",kamaaina:null},
  {name:"China Walls (Portlock)",tier:"C",lat:21.2616,lng:-157.7068,category:"snorkel",subcategory:"shore-dive",tagline:"A rugged cliff entry for experienced snorkelers rewarded with crystal-clear Portlock water.",area:"Hawaii Kai",price:"Free",parking:"Limited street parking on Hanapepe Loop in Portlock neighborhood; be respectful of residents",hours:"Open 24 hours (daylight recommended)",bestTime:"Summer mornings when south swell is minimal; flat days only — even moderate surf makes entry dangerous",kidFriendly:false,talkStory:"WARNING: People have died here — this is not an exaggeration. Rogue waves can sweep you off the rocks without warning. Never turn your back to the ocean and never go alone. This is NOT for beginners — entry is off a lava rock ledge and there is no beach. On calm days the water clarity is unreal, 60+ feet visibility with green sea turtles, reef sharks, and dense coral. You need to time your entry between sets and be comfortable climbing back up on wet rock. Locals come here to cliff jump too, so keep your head on a swivel. If there is any swell running, skip it.",kamaaina:null},
  {name:"Cockroach Cove (Halona Cove)",tier:"B",lat:21.272,lng:-157.693,category:"snorkel",subcategory:"cove",tagline:"The tiny hidden cove below the Halona Blowhole that most tourists photograph but never swim.",area:"Hawaii Kai",price:"Free",parking:"Free lot at Halona Blowhole Lookout; short steep scramble down to the cove",hours:"Open 24 hours; no lifeguard",bestTime:"Summer (May–Sep) when south shore is calm; ONLY on flat days — waves funnel into this cove dangerously",kidFriendly:false,talkStory:"Halona means 'peering place' in Hawaiian — ancient fishermen watched for fish schools from these cliffs long before Hollywood filmed From Here to Eternity here in 1953. The cove's lava shelters are packed with wana (sea urchins) and juvenile goatfish that use it as a nursery. If the Blowhole across the road is shooting spray, the cove has dangerous surge — only enter when it's dead silent and you can see the sandy bottom clearly.",kamaaina:null},
  {name:"Ko Olina Lagoon 3",tier:"A",lat:21.3355,lng:-158.1258,category:"snorkel",subcategory:"beginner",tagline:"Year-round protected snorkeling with turtles — the safest, most accessible snorkel on Oahu.",area:"Ko Olina",price:"Free",parking:"Free public lot for Lagoon 3 (fills by 9am weekends)",hours:"Open 24 hours (public beach access)",bestTime:"Arrive by 8am weekends for parking; weekdays are easy. Morning has best visibility",kidFriendly:true,talkStory:"Ko Olina means 'place of joy' and these lagoons were carved from the reef in the 1990s, with breakwaters designed to create perpetually calm water. Lagoon 3 draws the most honu because its deeper channel grows the limu (seaweed) turtles feed on. Stay 10+ feet from turtles — NOAA monitors this beach and violations carry federal fines up to $21,000. Weekday mornings you can have the lagoon to yourself before resort guests wake up.",kamaaina:null},
  {name:"Maili Point",tier:"C",lat:21.4185,lng:-158.172,category:"snorkel",subcategory:"reef",tagline:"A low-key Waianae reef that delivers when you want to avoid the tourist trail entirely.",area:"Waianae",price:"Free",parking:"Street parking along Farrington Hwy near Maili Beach Park",hours:"Open 24 hours",bestTime:"Summer mornings; only snorkel when the ocean is calm — exposed reef with no protection",kidFriendly:false,talkStory:"Maili takes its name from the maile vine sacred in Hawaiian lei-making, and this Waianae coastline was once prime fishing grounds for local ahupuaa families. The reef harbors big schools of manini (convict tang) and kole (goldring surgeonfish) because fishing pressure is lower than the tourist corridor. On calm summer days the outer edge drops to 25 feet where ulua (giant trevally) cruise past. Respect the community — this is not a tourist beach.",kamaaina:null},
  {name:"Pupukea Tide Pools",tier:"A",lat:21.654,lng:-158.0635,category:"snorkel",subcategory:"reef",tagline:"Sheltered tide pools perfect for a mellow snorkel right next to Shark's Cove.",area:"North Shore",price:"Free",parking:"Free lot across from Pupukea Beach Park (shared with Shark's Cove); fills by 9am in summer",hours:"Open 24 hours (Pupukea Beach Park)",bestTime:"Summer only (May–Sep); low tide reveals the best pools; mornings are calmest",kidFriendly:true,talkStory:"Pupukea means 'white shell hill' and this coastline is part of the Pupukea Marine Life Conservation District, established in 1983 to protect the reef from collection and fishing. The tide pools trap juvenile humuhumunukunukuapuaa, hermit crabs, and bright-red slate-pencil urchins in shallow bowls perfect for kids. Experienced snorkelers work the outer pools at low tide where octopus hide in crevices and endemic cleaner wrasse run cleaning stations.",kamaaina:null},
  {name:"Sans Souci Beach (Queen's Beach)",tier:"B",lat:21.2588,lng:-157.8225,category:"snorkel",subcategory:"reef",tagline:"Waikiki's secret reef — locals snorkel here while tourists stay on the sand a mile west.",area:"Waikiki",price:"Free",parking:"Free street parking on Kalakaua Ave or paid lot at Kapiolani Park; metered spots fill early",hours:"Open 24 hours",bestTime:"Early morning for calmest water and best visibility; year-round spot but summer is ideal",kidFriendly:true,talkStory:"Named after the resort where Robert Louis Stevenson stayed in 1893, calling these waters 'the most restful spot on earth.' The reef hosts resident schools of aholehole (Hawaiian flagtail), a culturally significant fish used in ceremonies at nearby heiau. The crumbling Natatorium war memorial creates a current break that funnels nutrients and attracts green sea turtles to its seawall. Locals enter the sandy channel and drift right where coral coverage is densest.",kamaaina:null},
  {name:"Three Tables",tier:"S",lat:21.6468,lng:-158.0621,category:"snorkel",subcategory:"beginner",tagline:"The easiest reef entry on the North Shore — walk right in from sand and float over a turtle-dotted reef.",area:"North Shore",price:"Free",parking:"Shares free lot with Shark's Cove across the street",hours:"Open 24 hours (no gates; Pupukea Beach Park)",bestTime:"Summer (May–Sep) for calm conditions; morning for best visibility",kidFriendly:true,talkStory:"Named for three flat reef platforms that emerge at low tide, this site sits within the Pupukea Marine Life Conservation District where fishing and collecting are prohibited — so reef life is noticeably denser than unprotected areas. The sandy channel between the tables is a cleaning station where honu line up to let cleaner wrasse pick parasites off their shells. Winter swells turn this same reef into a violent washing machine — the season shift catches visitors off guard.",kamaaina:null},
];
